import { TCM_DB } from '../constants';
import { Syndrome, PatientFormSchema, RxPoint, ScoredSyndrome } from '../types';

export interface AutoRxInput {
  syndrome: Syndrome;
  selectedSymptoms: string[];
  tongue?: string[];
  pulse?: string[];
  bodyRegion?: string[];
  isPregnant?: boolean;
}

export const normalize = (s: string) => 
  (s || "").toLowerCase().replace(/[^\p{L}\p{N}\s]/gu, " ").replace(/\s+/g, " ").trim();

const similarityRatio = (a: string, b: string): number => {
  const normA = normalize(a);
  const normB = normalize(b);
  if (normA === normB) return 1.0;
  if (normA.length === 0 || normB.length === 0) return 0.0;
  const setA = new Set(normA.split(/\s+/));
  const setB = new Set(normB.split(/\s+/));
  const intersection = new Set([...setA].filter(x => setB.has(x)));
  return intersection.size / Math.max(setA.size, setB.size);
};

export const fuzzyMatch = (a: string, b: string, threshold = 0.75): boolean => {
  const normA = normalize(a);
  const normB = normalize(b);
  if (normA.includes(normB) || normB.includes(normA)) return true;
  return similarityRatio(a, b) >= threshold;
};

const expandWithSynonyms = (base: string[]): Set<string> => {
  const out = new Set<string>();
  const synonymMap = TCM_DB.clinical_config.matching.synonym_map;
  base.forEach(s => {
    const key = normalize(s);
    if (!key) return;
    out.add(key);
    if (synonymMap[key]) {
      synonymMap[key].forEach(syn => out.add(normalize(syn)));
    }
  });
  return out;
};

const extractSymptoms = (text: string): string[] => {
    return text.split(/[\n,.]+/).map(normalize).filter(s => s.length > 2);
};

const detectPathologyFromSigns = (
  tongue: PatientFormSchema['tongue'],
  pulse: PatientFormSchema['pulse']
) => {
  const signs = {
    HEAT_FULL: false, HEAT_EMPTY: false,
    COLD_FULL: false, COLD_EMPTY: false,
    DAMP_PHLEGM: false, STASIS: false,
    BLOOD_DEF: false, QI_DEF: false,
    QI_STAG: false, ORGANS_IMPLICATED: new Set<string>()
  };

  const tBody = normalize(tongue.body_color);
  const tCoat = normalize(tongue.coating_color);
  const tQual = normalize(tongue.coating_quality);
  const pQuals = (pulse.qualities || []).map(normalize);

  if (tBody.includes('red') || tCoat.includes('yellow') || pQuals.some(q => q.includes('rapid'))) {
    if (tQual.includes('none') || tQual.includes('peeling') || tQual.includes('dry')) signs.HEAT_EMPTY = true;
    else signs.HEAT_FULL = true;
  }
  if (tBody.includes('pale') || tCoat.includes('white') || pQuals.some(q => q.includes('slow'))) {
    if (tQual.includes('wet') || pQuals.some(q => q.includes('weak'))) signs.COLD_EMPTY = true;
    else signs.COLD_FULL = true;
  }
  if (tQual.includes('greasy') || tQual.includes('sticky') || pQuals.some(q => q.includes('slippery'))) signs.DAMP_PHLEGM = true;
  if (tBody.includes('pale') && !tQual.includes('wet')) signs.BLOOD_DEF = true;
  if (pQuals.some(q => q.includes('wiry'))) signs.QI_STAG = true;

  return signs;
};

export const scoreSyndrome = (
  syn: Syndrome, 
  selExpanded: Set<string>, 
  pathology: any,
  modifiers: any
): number => {
  let score = 0;
  const weights = TCM_DB.clinical_config.scoring.weights;
  const pType = normalize(syn.pattern_type);

  (syn.key_symptoms || []).forEach(ks => {
    if (Array.from(selExpanded).some(sel => fuzzyMatch(sel, ks))) score += weights.key_symptom_match;
  });

  if (pathology.HEAT_FULL && pType.includes('full_heat')) score += 15;
  if (pathology.HEAT_EMPTY && pType.includes('deficiency_yin')) score += 15;
  if (pathology.COLD_FULL && pType.includes('excess_cold')) score += 15;
  if (pathology.COLD_EMPTY && pType.includes('yang_deficiency')) score += 15;

  return score;
};

export function buildAutoPrescription(DB: any, input: AutoRxInput): { points: RxPoint[], warnings: string[], rationale: string[] } {
  const syn = input.syndrome;
  const points: RxPoint[] = [];
  const basePts = Array.isArray(syn.acupuncture_points) ? syn.acupuncture_points : (syn.acupuncture_points?.kausal || []);
  basePts.forEach((code: string) => points.push({ code, role: "kausal", source: "syndrome" }));

  return { 
    points: points, 
    warnings: [], 
    rationale: ["Integrasi otomatis berdasarkan pola klinis Maciocia."] 
  };
}

export const getHerbalRecommendation = (syndrome: Syndrome) => {
  const guidelines = TCM_DB.herbal_guidelines;
  // Cari di overrides dulu
  if (guidelines.per_syndrome_overrides_for_current_DB_snippet[syndrome.id]) {
      return guidelines.per_syndrome_overrides_for_current_DB_snippet[syndrome.id];
  }
  // Cari di pattern type
  if (guidelines.herbal_rules_by_pattern_type[syndrome.pattern_type]) {
    const rule = guidelines.herbal_rules_by_pattern_type[syndrome.pattern_type];
    return {
      formula_name: rule.notes || "Formula Standar Maciocia",
      chief: rule.suggest_chief || rule.suggest_chief_herbs || [],
      assistants: rule.suggest_assistants || [],
      avoid: rule.avoid || []
    };
  }
  return undefined;
};

export const analyzePatient = (data: PatientFormSchema): ScoredSyndrome[] => {
    const allSyndromes = [...TCM_DB.syndromes.FILLED_FROM_PDF];
    const symptomsList = extractSymptoms((data as any).symptoms || "");
    const selExpanded = expandWithSynonyms(symptomsList);
    const pathology = detectPathologyFromSigns(data.tongue, data.pulse);

    return allSyndromes.map(syn => ({
        syndrome: syn,
        score: scoreSyndrome(syn, selExpanded, pathology, {})
    }))
    .filter(s => s.score > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, 3)
    .map(s => {
        return {
            ...s,
            points: buildAutoPrescription(TCM_DB, { syndrome: s.syndrome, selectedSymptoms: symptomsList }).points,
            warnings: [],
            rationale: ["Berdasarkan kecocokan gejala klinis Maciocia."],
            herbal_recommendation: getHerbalRecommendation(s.syndrome)
        };
    });
};

