export interface ClinicalConfig {
  version: string;
  scoring: {
    weights: {
      key_symptom_match: number;
      manifestation_match: number;
      tongue_match: number;
      pulse_match: number;
      organ_region_bonus: number;
      wuxing_branch_bonus: number;
    };
    exclusion_penalty: number;
    min_key_symptoms: number;
    top_k: number;
  };
  matching: {
    normalize: {
      lowercase: boolean;
      trim: boolean;
      remove_punctuation: boolean;
    };
