import React, { useState, useEffect } from 'react';
import { X, Save, Activity, Check, ThermometerSnowflake, User, Stethoscope, Pill, Calendar, Search, UserCheck, ChevronRight, Tag } from 'lucide-react';
import { db } from '../services/db';
import { SavedPatient } from '../types';

interface PatientData {
  patientName: string;
  age: string;
  sex: string;
  address: string;
  complaint: string;
  symptoms: string;
  selectedSymptoms: string[];
  isAcuteMode: boolean;

