const COMMON_SYMPTOMS = [
  'Pusing/Dizziness', 'Nyeri Kepala', 'Insomnia', 'Palpitasi', 'Napas Pendek', 
  'Mudah Marah', 'Kembung', 'Mual/Muntah', 'Diare', 'Sembelit', 
