];

const PatientFormModal: React.FC<Props> = ({ isOpen, onClose, onSubmit }) => {
  const [storedPatients, setStoredPatients] = useState<SavedPatient[]>([]);
  const [showLookup, setShowLookup] = useState(false);
  const [lookupSearch, setLookupSearch] = useState('');

  const [formData, setFormData] = useState<PatientData>({
    patientName: '',
    age: '',
    sex: 'male',
    address: '',
    complaint: '',
    symptoms: '',
    selectedSymptoms: [],
    isAcuteMode: false,
    biomedicalDiagnosis: '',
    icd10: '',
    medications: '',
    followUpDate: '',
    notes: '',
    tongue: {
      body_color: '',
      coating_color: '',
      coating_quality: '',
      special_features: []
    },
    pulse: {
      qualities: []
    }
  });

  // Load patients from db when modal opens
  useEffect(() => {
    if (isOpen) {
      setStoredPatients(db.patients.getAll());
    }
  }, [isOpen]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(formData);
    onClose();
  };

  const handleSelectExisting = (p: SavedPatient) => {
    setFormData({
      patientName: p.patientName,
      age: p.age,
      sex: p.sex as any,
      address: p.address || '',
      complaint: p.complaint,
      symptoms: p.symptoms,
      selectedSymptoms: p.selectedSymptoms || [],
      isAcuteMode: false,
      biomedicalDiagnosis: p.biomedicalDiagnosis || '',
      icd10: p.icd10 || '',
      medications: p.medications || '',
      followUpDate: p.followUpDate || '',
      notes: p.notes || '',
      tongue: {
        body_color: p.tongue.body_color || '',
        coating_color: p.tongue.coating_color || '',
        coating_quality: p.tongue.coating_quality || '',
        special_features: p.tongue.special_features || []
      },
      pulse: {
        qualities: p.pulse.qualities || []
      }
    });
    setShowLookup(false);
  };

  const toggleSymptom = (symptom: string) => {
    const current = formData.selectedSymptoms;
    const updated = current.includes(symptom)
      ? current.filter(s => s !== symptom)
      : [...current, symptom];
    setFormData({ ...formData, selectedSymptoms: updated });
  };

  const togglePulseQuality = (quality: string) => {
    const current = formData.pulse.qualities;
    const updated = current.includes(quality)
      ? current.filter(q => q !== quality)
      : [...current, quality];
    setFormData({ ...formData, pulse: { ...formData.pulse, qualities: updated } });
  };

  const filteredStored = storedPatients.filter(p => 
    p.patientName.toLowerCase().includes(lookupSearch.toLowerCase()) ||
    (p.biomedicalDiagnosis && p.biomedicalDiagnosis.toLowerCase().includes(lookupSearch.toLowerCase()))
  ).slice(0, 5);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-fade-in">
      <div className="bg-slate-800 border border-slate-700 w-full max-w-2xl rounded-2xl shadow-2xl max-h-[90vh] overflow-y-auto scrollbar-hide">
        <div className="flex items-center justify-between p-4 border-b border-slate-700 sticky top-0 bg-slate-800 z-20">
          <div className="flex items-center gap-2">
             <Activity className="w-5 h-5 text-tcm-primary" />
             <h2 className="text-xl font-bold text-tcm-primary">Patient Intake Form</h2>
          </div>
          <div className="flex items-center gap-2">
            <button 
                type="button"
                onClick={() => setShowLookup(!showLookup)}
                className="flex items-center gap-2 px-3 py-1.5 bg-slate-700 hover:bg-slate-600 text-slate-300 rounded-lg text-xs font-bold transition-all border border-slate-600"
            >
                <Search className="w-3.5 h-3.5" /> {showLookup ? 'Tutup Cari' : 'Cari Pasien'}
            </button>
            <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors">
                <X className="w-6 h-6" />
            </button>
          </div>
        </div>

        {showLookup && (
            <div className="p-4 bg-slate-900 border-b border-slate-700 animate-fade-in">
                <div className="relative mb-4">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                    <input 
                        type="text" 
                        placeholder="Ketik nama pasien yang sudah terdaftar..."
                        className="w-full bg-slate-800 border border-slate-700 rounded-xl py-2 pl-10 pr-4 text-sm text-white focus:border-tcm-primary outline-none"
                        value={lookupSearch}
                        onChange={(e) => setLookupSearch(e.target.value)}
                    />
                </div>
                <div className="space-y-2">
                    {filteredStored.map(p => (
                        <button 
                            key={p.id}
                            type="button"
                            onClick={() => handleSelectExisting(p)}
                            className="w-full text-left p-3 rounded-xl bg-slate-800 border border-slate-700 hover:border-tcm-primary flex items-center justify-between group transition-all"
                        >
                            <div className="flex items-center gap-3">
                                <div className="p-2 bg-slate-700 rounded-lg text-slate-400 group-hover:text-tcm-primary">
                                    <UserCheck className="w-4 h-4" />
                                </div>
                                <div>
                                    <span className="block text-sm font-bold text-slate-200">{p.patientName}</span>
                                    <span className="text-[10px] text-slate-500 uppercase">{p.age} th • {p.biomedicalDiagnosis || 'Umum'}</span>
                                </div>
                            </div>
                            <ChevronRight className="w-4 h-4 text-slate-600 group-hover:text-tcm-primary" />
                        </button>
                    ))}
                    {filteredStored.length === 0 && (
                        <div className="text-center py-4 text-xs text-slate-600 italic">Tidak ada pasien yang cocok di arsip.</div>
                    )}
                </div>
            </div>
        )}

        <form onSubmit={handleSubmit} className="p-6 space-y-6">
            {/* Identity Section */}
            <div className="space-y-4">
              <h3 className="text-xs font-bold text-indigo-400 uppercase tracking-widest border-b border-slate-700/50 pb-2">I. Identity</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                      <label className="block text-xs font-semibold text-slate-400 uppercase mb-1">Patient Name</label>
                      <div className="relative">
                        <User className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                        <input 
                            type="text" 
                            className="w-full bg-slate-900 border border-slate-700 rounded-lg pl-10 pr-3 py-2 text-slate-200 focus:border-tcm-primary outline-none transition-colors"
                            value={formData.patientName}
                            onChange={e => setFormData({...formData, patientName: e.target.value})}
                            placeholder="Full Name"
                        />
                      </div>
                  </div>
                  <div className="grid grid-cols-2 gap-2">
                    <div>
                        <label className="block text-xs font-semibold text-slate-400 uppercase mb-1">Age</label>
                        <input 
                            type="number" 
                            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-200 focus:border-tcm-primary outline-none"
                            value={formData.age}
                            onChange={e => setFormData({...formData, age: e.target.value})}
                            placeholder="Age"
                        />
                    </div>
                    <div>
                        <label className="block text-xs font-semibold text-slate-400 uppercase mb-1">Sex</label>
                        <select 
                            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-200 focus:border-tcm-primary outline-none"
                            value={formData.sex}
                            onChange={e => setFormData({...formData, sex: e.target.value})}
                        >
                            <option value="male">Male</option>
                            <option value="female">Female</option>
                        </select>
                    </div>
                  </div>
              </div>
              <div>
                  <label className="block text-xs font-semibold text-slate-400 uppercase mb-1">Address</label>
                  <input 
                      type="text" 
                      className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-200 focus:border-tcm-primary outline-none"
                      value={formData.address}
                      onChange={e => setFormData({...formData, address: e.target.value})}
                      placeholder="Home Address"
                  />
              </div>
            </div>

            {/* Clinical & Biomedical Section */}
            <div className="space-y-4">
              <h3 className="text-xs font-bold text-amber-400 uppercase tracking-widest border-b border-slate-700/50 pb-2">II. Clinical & Biomedical</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                      <label className="block text-xs font-semibold text-slate-400 uppercase mb-1">Biomedical Diagnosis (Penyakit)</label>
                      <div className="relative">
                        <Stethoscope className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                        <input 
                            type="text" 
                            className="w-full bg-slate-900 border border-slate-700 rounded-lg pl-10 pr-3 py-2 text-slate-200 focus:border-tcm-primary outline-none"
                            value={formData.biomedicalDiagnosis}
                            onChange={e => setFormData({...formData, biomedicalDiagnosis: e.target.value})}
                            placeholder="e.g. Hypertension, GERD"
                        />
                      </div>
                  </div>
                  <div>
                      <label className="block text-xs font-semibold text-slate-400 uppercase mb-1">ICD-10 Code</label>
                      <input 
                          type="text" 
                          className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-200 focus:border-tcm-primary outline-none"
                          value={formData.icd10}
                          onChange={e => setFormData({...formData, icd10: e.target.value})}
                          placeholder="e.g. I10, K21.9"
                      />
                  </div>
              </div>
              <div>
                  <label className="block text-xs font-semibold text-slate-400 uppercase mb-1">Current Medications (Obat Barat)</label>
                  <div className="relative">
                    <Pill className="absolute left-3 top-3 w-4 h-4 text-slate-500" />
                    <textarea 
                        className="w-full bg-slate-900 border border-slate-700 rounded-lg pl-10 pr-3 py-2 text-slate-200 focus:border-tcm-primary outline-none h-16 resize-none"
                        value={formData.medications}
                        onChange={e => setFormData({...formData, medications: e.target.value})}
                        placeholder="List current drugs..."
                    />
                  </div>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                    <label className="block text-xs font-semibold text-slate-400 uppercase mb-1">Chief Complaint (TCM)</label>
                    <input 
                        type="text" 
                        required
                        className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-200 focus:border-tcm-primary outline-none"
                        value={formData.complaint}
                        onChange={e => setFormData({...formData, complaint: e.target.value})}
                        placeholder="e.g. Headache for 3 days"
                    />
                </div>
                <div>
                    <label className="block text-xs font-semibold text-slate-400 uppercase mb-1 flex items-center gap-1"><Calendar className="w-3 h-3" /> Next Follow-up</label>
                    <input 
                        type="date" 
                        className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-200 focus:border-tcm-primary outline-none"
                        value={formData.followUpDate}
                        onChange={e => setFormData({...formData, followUpDate: e.target.value})}
                    />
                </div>
              </div>
            </div>

            {/* Symptoms Section */}
            <div className="space-y-4">
              <h3 className="text-xs font-bold text-tcm-primary uppercase tracking-widest border-b border-slate-700/50 pb-2">III. TCM Signs & Symptoms</h3>

              <div className="bg-slate-700/30 p-3 rounded-lg border border-slate-700 flex items-center justify-between">
                <div className="flex items-center gap-3">
                   <ThermometerSnowflake className={`w-5 h-5 ${formData.isAcuteMode ? 'text-tcm-accent' : 'text-slate-500'}`} />
                   <div>
                      <span className="block text-sm font-semibold text-slate-200">Acute Disease Mode</span>
                      <span className="text-xs text-slate-500">For Shang Han Lun / Wen Bing focus</span>
                   </div>
                </div>
                <label className="relative inline-flex items-center cursor-pointer">
                  <input type="checkbox" className="sr-only peer" checked={formData.isAcuteMode} onChange={e => setFormData({...formData, isAcuteMode: e.target.checked})} />
                  <div className="w-11 h-6 bg-slate-600 rounded-full peer peer-checked:after:translate-x-full after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-tcm-accent"></div>
                </label>
              </div>

              <div>
                  <label className="block text-xs font-semibold text-slate-400 uppercase mb-1 flex items-center gap-2"><Tag className="w-3 h-3"/> Common Symptom Tags (Historical Tracking)</label>
                  <div className="flex flex-wrap gap-2 mb-3 p-3 bg-slate-950/50 rounded-xl border border-slate-700">
                     {COMMON_SYMPTOMS.map(s => (
                       <button
                        key={s}
                        type="button"
                        onClick={() => toggleSymptom(s)}
                        className={`px-3 py-1 rounded-full text-[10px] font-bold border transition-all ${
                          formData.selectedSymptoms.includes(s)
                          ? 'bg-tcm-primary border-tcm-primary text-white'
                          : 'bg-slate-800 border-slate-700 text-slate-500 hover:border-slate-500'
                        }`}
                       >
                         {s}
                       </button>
                     ))}
                  </div>

                  <label className="block text-xs font-semibold text-slate-400 uppercase mb-1">Detailed Symptoms (Text)</label>
                  <textarea 
                      className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-200 focus:border-tcm-primary outline-none h-24 transition-colors resize-none"
                      value={formData.symptoms}
                      onChange={e => setFormData({...formData, symptoms: e.target.value})}
                      placeholder="List all signs and symptoms..."
                  />
              </div>

              {/* Tongue & Pulse Grids */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <h4 className="text-xs font-bold text-slate-300 mb-3 uppercase">Tongue</h4>
                  <div className="space-y-3">
                    <select className="w-full bg-slate-900 border border-slate-700 rounded-lg px-2 py-2 text-sm text-slate-200"
                            value={formData.tongue.body_color} onChange={e => setFormData({...formData, tongue: {...formData.tongue, body_color: e.target.value}})}>
                      <option value="">Body Color...</option>
                      {TONGUE_BODY_COLORS.map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                    <select className="w-full bg-slate-900 border border-slate-700 rounded-lg px-2 py-2 text-sm text-slate-200"
                            value={formData.tongue.coating_color} onChange={e => setFormData({...formData, tongue: {...formData.tongue, coating_color: e.target.value}})}>
                      <option value="">Coat Color...</option>
                      {TONGUE_COAT_COLORS.map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                    <select className="w-full bg-slate-900 border border-slate-700 rounded-lg px-2 py-2 text-sm text-slate-200"
                            value={formData.tongue.coating_quality} onChange={e => setFormData({...formData, tongue: {...formData.tongue, coating_quality: e.target.value}})}>
                      <option value="">Coat Quality...</option>
                      {TONGUE_COAT_QUALITIES.map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                  </div>
                </div>
                <div>
                  <h4 className="text-xs font-bold text-slate-300 mb-3 uppercase">Pulse</h4>
                  <div className="max-h-32 overflow-y-auto p-2 bg-slate-900 border border-slate-700 rounded-lg flex flex-wrap gap-1">
                    {PULSE_QUALITIES.map(q => (
                       <button key={q} type="button" onClick={() => togglePulseQuality(q)} 
                               className={`px-2 py-0.5 rounded text-[10px] border transition ${formData.pulse.qualities.includes(q) ? 'bg-emerald-600 border-emerald-400 text-white' : 'bg-slate-800 border-slate-700 text-slate-500'}`}>
                         {q}
                       </button>
                    ))}
                  </div>
                </div>
              </div>
            </div>

            <div className="pt-4 flex justify-end gap-3 sticky bottom-0 bg-slate-800 py-4 border-t border-slate-700 z-10">
                <button type="button" onClick={onClose} className="px-4 py-2 rounded-lg text-slate-400 hover:text-white text-sm">Cancel</button>
                <button type="submit" className="flex items-center gap-2 bg-tcm-primary hover:bg-tcm-secondary text-white px-6 py-2 rounded-lg font-bold shadow-lg text-sm">
                    <Save className="w-4 h-4" /> Save & Analyze
                </button>
            </div>
        </form>
      </div>
    </div>
  );
};

