const App: React.FC = () => {
  // --- AUTHENTICATION STATE ---
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);

  const [activePanel, setActivePanel] = useState<'chat' | 'diagnosis' | 'theory' | 'stroke' | 'atlas' | 'wuxing' | 'ukom' | 'archive'>('chat');
  const [linkedSyndromeId, setLinkedSyndromeId] = useState<string | null>(null);

  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: 'Selamat datang di TCM WuXing Pro. Silakan isi form pasien (tombol papan klip) atau ceritakan keluhan Anda untuk diagnosis.',
      timestamp: new Date()
    }
  ]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false); 
  const [selectedLanguage, setSelectedLanguage] = useState<Language>(Language.INDONESIAN);
  const [isPregnant, setIsPregnant] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isVisualizerOpen, setIsVisualizerOpen] = useState(false);
  const [isUserMgmtOpen, setIsUserMgmtOpen] = useState(false);
  const [visualizerHighlight, setVisualizerHighlight] = useState<string | null>(null);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [cdssResults, setCdssResults] = useState<ScoredSyndrome[]>([]);
  const [lastPatientForm, setLastPatientForm] = useState<any>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    if (activePanel === 'chat') {
        scrollToBottom();
    }
  }, [messages, activePanel]);

  const handleSendMessage = async (textOverride?: string, analysis?: ScoredSyndrome[]) => {
    const textToSend = textOverride || inputText;
    const imageToSend = textOverride ? undefined : (selectedImage || undefined);

    if ((!textToSend.trim() && !imageToSend) || isLoading) return;

    const userMessage: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: textToSend,
      image: imageToSend,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputText('');
    setSelectedImage(null);
    setIsLoading(true);

    try {
      const response = await sendMessageToGemini(textToSend, imageToSend, messages, selectedLanguage, isPregnant, analysis || cdssResults);

      const botMessage: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: response.conversationalResponse,
        timestamp: new Date(),
        tcmResult: response.diagnosis
      };

      setMessages(prev => [...prev, botMessage]);
    } catch (error) {
      const errorMessage: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Maaf, terjadi kesalahan koneksi atau analisis. Silakan coba lagi.",
        timestamp: new Date(),
        isError: true
      };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleFormSubmit = (data: any) => {
    setLastPatientForm(data);
    setIsAnalyzing(true);
    setActivePanel('diagnosis'); 

    setTimeout(() => {
        const results = analyzePatient({
            identity: {
                patient_name: data.patientName || "Anonymous",
                visit_date: new Date().toISOString(),
                address: data.address || "",
                age: data.age,
                sex: data.sex
            },
            chief_complaint: data.complaint,
            selected_symptoms: data.selectedSymptoms || [], 
            body_region_selector: data.body_region_selector || [], 
            tongue: data.tongue,
            pulse: data.pulse,
            isAcuteMode: data.isAcuteMode
        } as any);

        setCdssResults(results);
        setIsAnalyzing(false);

        // --- AUTOMATICALLY SAVE TO LOCAL ARCHIVE ---
        if (results && results.length > 0) {
            const topResult = results[0];
            const diagnosisToSave: TcmDiagnosisResult = {
                patternId: topResult.syndrome.id,
                confidence: topResult.score / 100,
                explanation: topResult.rationale.join('; '),
                recommendedPoints: topResult.points.map(p => p.code),
                lifestyleAdvice: "CDSS Analysis Result.",
                herbal_recommendation: topResult.herbal_recommendation,
                wuxingElement: topResult.syndrome.wuxing_element
            };

            const saved: SavedPatient = {
                id: crypto.randomUUID ? crypto.randomUUID() : Date.now().toString(),
                patientName: data.patientName || "Anonymous",
                age: data.age || "",
                sex: data.sex || "",
                address: data.address || "",
                complaint: data.complaint || "",
                symptoms: data.symptoms || "",
                selectedSymptoms: data.selectedSymptoms || [],
                tongue: data.tongue,
                pulse: data.pulse,
                diagnosis: diagnosisToSave,

                // Fields Integrasi Baru
                biomedicalDiagnosis: data.biomedicalDiagnosis || "",
                icd10: data.icd10 || "",
                medications: data.medications || "",
                followUpDate: data.followUpDate || "",
                notes: data.notes || "",
                treatmentPlan: topResult.syndrome.treatment_principle?.join(', ') || "",

                timestamp: Date.now(),
            };

            db.patients.add(saved);
        }

        const tongueDetails = [
          data.tongue.body_color ? `Body: ${data.tongue.body_color}` : '',
          data.tongue.coating_color ? `Coat Color: ${data.tongue.coating_color}` : '',
          data.tongue.coating_quality ? `Coat Quality: ${data.tongue.coating_quality}` : '',
          data.tongue.special_features.length ? `Features: ${data.tongue.special_features.join(', ')}` : ''
        ].filter(Boolean).join(' | ');

        const pulseDetails = data.pulse.qualities.length > 0 ? data.pulse.qualities.join(', ') : 'Not specified';

        const formattedMessage = `
**PATIENT INTAKE**
Name: ${data.patientName || 'Anonymous'}
Age/Sex: ${data.age} / ${data.sex}
Biomedical: ${data.biomedicalDiagnosis || 'N/A'} (ICD: ${data.icd10 || '-'})
Meds: ${data.medications || 'None'}

Complaint: ${data.complaint}
Selected Symptoms: ${(data.selectedSymptoms || []).join(', ') || 'None'}
Symptoms Detail: ${data.symptoms}
Tongue: ${tongueDetails || 'Not specified'}
Pulse: ${pulseDetails}

Please provide an integrated analysis.
        `.trim();

        handleSendMessage(formattedMessage, results);
    }, 800); 
  };

  const handleLoadPatient = (savedPatient: SavedPatient) => {
    const patientData = {
        patientName: savedPatient.patientName,
        age: savedPatient.age,
        sex: savedPatient.sex,
        address: savedPatient.address || "",
        complaint: savedPatient.complaint,
        symptoms: savedPatient.symptoms,
        selectedSymptoms: savedPatient.selectedSymptoms || [],
        tongue: savedPatient.tongue,
        pulse: savedPatient.pulse,
        biomedicalDiagnosis: savedPatient.biomedicalDiagnosis || "",
        icd10: savedPatient.icd10 || "",
        medications: savedPatient.medications || "",
        followUpDate: savedPatient.followUpDate || "",
        notes: savedPatient.notes || "",
        isAcuteMode: savedPatient.diagnosis.isMultiOrganInteraction || false 
    };

    setLastPatientForm(patientData);
    setIsAnalyzing(true);
    setActivePanel('diagnosis');

    setTimeout(() => {
        const results = analyzePatient({
            identity: {
                patient_name: savedPatient.patientName,
                visit_date: new Date(savedPatient.timestamp).toISOString(),
                address: savedPatient.address || "",
                age: savedPatient.age,
                sex: savedPatient.sex
            },
            chief_complaint: savedPatient.complaint,
            selected_symptoms: savedPatient.selectedSymptoms || [], 
            body_region_selector: [], 
            tongue: savedPatient.tongue,
            pulse: savedPatient.pulse,
            isAcuteMode: false
        } as any);

        setCdssResults(results);
        setIsAnalyzing(false);
    }, 500);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setMessages([{
      id: 'welcome',
      role: 'model',
      text: 'Selamat datang di TCM WuXing Pro. Silakan isi form pasien (tombol papan klip) atau ceritakan keluhan Anda untuk diagnosis.',
      timestamp: new Date()
    }]);
  };

  if (!currentUser) {
    return <LoginScreen onLoginSuccess={(user) => setCurrentUser(user)} />;
  }

  return (
    <div className="flex h-screen bg-slate-950 text-slate-100 font-sans overflow-hidden print:h-auto print:overflow-visible print:bg-white print:text-black print:block">
      <PatientFormModal isOpen={isFormOpen} onClose={() => setIsFormOpen(false)} onSubmit={handleFormSubmit} />
      <WuXingVisualizerModal 
        isOpen={isVisualizerOpen} 
        onClose={() => setIsVisualizerOpen(false)} 
        initialHighlight={visualizerHighlight}
      />
      {currentUser.role === 'admin' && (
        <UserManagementModal 
          isOpen={isUserMgmtOpen} 
          onClose={() => setIsUserMgmtOpen(false)} 
          currentUser={currentUser}
        />
      )}

      {/* SIDEBAR NAVIGATION */}
      <div className={`fixed inset-y-0 left-0 z-40 w-64 bg-slate-900 border-r border-slate-800 transform transition-transform duration-300 ease-in-out ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:relative md:translate-x-0 flex flex-col print:hidden`}>
        <div className="p-5">
           <h1 className="text-xl font-black bg-gradient-to-r from-tcm-primary to-tcm-accent bg-clip-text text-transparent flex items-center gap-2">
              <Activity className="w-6 h-6 text-tcm-primary" />
              TCM WuXing
           </h1>
           <p className="text-[10px] text-slate-500 mt-1 uppercase tracking-widest font-semibold flex items-center gap-1">
             <Shield className="w-3 h-3 text-emerald-500" /> {currentUser.role === 'admin' ? 'Admin Access' : 'Pro License'}
           </p>
        </div>

        <div className="flex-1 px-3 space-y-2 overflow-y-auto">
           <div className="space-y-1 mb-6">
              <button
                type="button"
                onClick={() => { setActivePanel('chat'); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all ${
                   activePanel === 'chat' 
                   ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/20' 
                   : 'text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                }`}
              >
                 <MessageSquare className="w-4 h-4" />
                 Chat / Input Cepat
              </button>

              <button
                type="button"
                onClick={() => { setActivePanel('diagnosis'); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all ${
                   activePanel === 'diagnosis' 
                   ? 'bg-tcm-primary text-white shadow-lg shadow-emerald-900/20' 
                   : 'text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                }`}
              >
                 <Stethoscope className="w-4 h-4" />
                 Diagnosis & Auto-Rx
              </button>

              <button
                type="button"
                onClick={() => { setActivePanel('archive'); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all ${
                   activePanel === 'archive' 
                   ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-900/20' 
                   : 'text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                }`}
              >
                 <Archive className="w-4 h-4" />
                 Arsip Pasien
              </button>

              <button
                type="button"
                onClick={() => { setActivePanel('wuxing'); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all ${
                   activePanel === 'wuxing' 
                   ? 'bg-pink-600 text-white shadow-lg shadow-pink-900/20' 
                   : 'text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                }`}
              >
                 <Compass className="w-4 h-4" />
                 Wu Xing Master
              </button>

              <button
                type="button"
                onClick={() => { setActivePanel('ukom'); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all ${
                   activePanel === 'ukom' 
                   ? 'bg-sky-600 text-white shadow-lg shadow-sky-900/20' 
                   : 'text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                }`}
              >
                 <GraduationCap className="w-4 h-4" />
                 Latihan UKOM
              </button>

              <button
                type="button"
                onClick={() => { setActivePanel('theory'); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all ${
                   activePanel === 'theory' 
                   ? 'bg-violet-600 text-white shadow-lg shadow-violet-900/20' 
                   : 'text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                }`}
              >
                 <BookOpen className="w-4 h-4" />
                 Theory & Syndromes
              </button>

              <button
                type="button"
                onClick={() => { setActivePanel('atlas'); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all ${
                   activePanel === 'atlas' 
                   ? 'bg-cyan-600 text-white shadow-lg shadow-cyan-900/20' 
                   : 'text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                }`}
              >
                 <Map className="w-4 h-4" />
                 Syndrome Atlas
              </button>

              <button
                type="button"
                onClick={() => { setActivePanel('stroke'); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all ${
                   activePanel === 'stroke' 
                   ? 'bg-amber-600 text-white shadow-lg shadow-amber-900/20' 
                   : 'text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                }`}
              >
                 <Zap className="w-4 h-4" />
                 Stroke Management
              </button>
           </div>

           <hr className="border-slate-800 mb-4 mx-2" />

           <div className="space-y-3">
              <div className="bg-slate-800/50 rounded-xl p-3 border border-slate-700/50">
                <label className="flex items-center cursor-pointer justify-between">
                  <div className="flex items-center gap-2">
                    <Baby className={`w-4 h-4 ${isPregnant ? 'text-pink-400' : 'text-slate-500'}`} />
                    <span className="text-sm font-medium text-slate-300">Pregnancy Mode</span>
                  </div>
                  <div className="relative">
                    <input type="checkbox" className="sr-only" checked={isPregnant} onChange={(e) => setIsPregnant(e.target.checked)} />
                    <div className={`block w-9 h-5 rounded-full transition-colors ${isPregnant ? 'bg-pink-500' : 'bg-slate-600'}`}></div>
                    <div className={`absolute left-1 top-1 bg-white w-3 h-3 rounded-full transition-transform ${isPregnant ? 'transform translate-x-4' : ''}`}></div>
                  </div>
                </label>
              </div>

              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-wider mb-2 px-1">Language</label>
                <LanguageSelector selected={selectedLanguage} onChange={setSelectedLanguage} />
              </div>
           </div>
        </div>

        <div className="p-3 pb-8 border-t border-slate-800 space-y-2 bg-slate-900">
           {currentUser.role === 'admin' && (
             <button 
               type="button"
               onClick={() => setIsUserMgmtOpen(true)}
               className="w-full flex items-center justify-start gap-3 px-3 py-2 text-indigo-400 hover:text-white hover:bg-indigo-900/30 rounded-lg text-sm transition-colors border border-transparent hover:border-indigo-500/30 cursor-pointer"
             >
                <Users className="w-4 h-4" /> Manage Users
             </button>
           )}

           <button 
             type="button"
             onClick={handleLogout}
             className="w-full flex items-center justify-start gap-3 px-3 py-2 text-slate-400 hover:text-rose-400 hover:bg-rose-900/10 rounded-lg text-sm transition-colors cursor-pointer"
           >
              <LogOut className="w-4 h-4" /> Logout ({currentUser.username})
           </button>

           <div className="pt-2">
             <button 
               type="button"
               onClick={() => setIsFormOpen(true)}
               className="w-full flex items-center justify-center gap-2 py-3 bg-slate-800 hover:bg-slate-700 text-tcm-primary rounded-xl font-bold text-sm transition-colors border border-slate-700 hover:border-tcm-primary cursor-pointer"
             >
                <ClipboardList className="w-4 h-4" /> New Patient
             </button>
           </div>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col h-full relative overflow-hidden bg-slate-950 print:h-auto print:overflow-visible print:bg-white print:text-black print:block">

        <div className="md:hidden flex items-center justify-between p-4 bg-slate-900 border-b border-slate-800 shrink-0 print:hidden">
          <button onClick={() => setIsSidebarOpen(true)} className="text-slate-300">
            <Menu className="w-6 h-6" />
          </button>
          <span className="font-bold text-tcm-primary">TCM WuXing Pro</span>
          <div className="w-6"></div> 
        </div>

        {activePanel === 'chat' && (
           <div className="flex-1 flex flex-col min-h-0 print:h-auto print:overflow-visible print:block">
              <div className="flex-1 overflow-y-auto p-4 space-y-4 scrollbar-hide print:h-auto print:overflow-visible print:block">
                {messages.map((msg) => (
                  <div key={msg.id} className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`flex max-w-[90%] md:max-w-[80%] gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                      <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 shadow-lg ${msg.role === 'user' ? 'bg-indigo-500' : 'bg-tcm-primary'} print:hidden`}>
                        {msg.role === 'user' ? <User className="w-5 h-5 text-white" /> : <Bot className="w-5 h-5 text-white" />}
                      </div>
                      <div className="flex flex-col gap-1 w-full min-w-0">
                        <div className={`p-4 rounded-2xl text-sm leading-relaxed whitespace-pre-wrap shadow-md ${
                          msg.role === 'user' 
                          ? 'bg-indigo-600 text-white rounded-tr-none print:bg-gray-100 print:text-black print:border print:border-gray-300' 
                          : 'bg-slate-800 text-slate-200 border border-slate-700 rounded-tl-none print:bg-white print:text-black print:border-gray-300'
                        }`}>
                          {msg.text}
                          {msg.image && (
                            <div className="mt-3 rounded-lg overflow-hidden border border-white/20 print:border-gray-300">
                              <img src={msg.image} alt="User upload" className="max-w-full h-auto max-h-64 object-cover" />
                            </div>
                          )}
                        </div>
                        {msg.tcmResult && (
                          <DiagnosisCard 
                            diagnosis={msg.tcmResult} 
                            isPregnant={isPregnant} 
                            onShowVisualizer={(element) => {
                                setVisualizerHighlight(element || null);
                                setIsVisualizerOpen(true);
                            }}
                            patientContext={lastPatientForm}
                          />
                        )}
                        <span className={`text-[10px] text-slate-500 ${msg.role === 'user' ? 'text-right' : 'text-left'} print:text-gray-400`}>
                          {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        </span>
                      </div>
                    </div>
                  </div>
                ))}
                {isLoading && (
                  <div className="flex justify-start w-full animate-fade-in print:hidden">
                    <div className="flex items-center gap-2 bg-slate-800 p-3 rounded-2xl rounded-tl-none border border-slate-700 ml-11 shadow-sm">
                      <div className="flex gap-1">
                        <div className="w-1.5 h-1.5 bg-tcm-primary rounded-full animate-bounce" style={{ animationDelay: '0s' }}></div>
                        <div className="w-1.5 h-1.5 bg-tcm-primary rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                        <div className="w-1.5 h-1.5 bg-tcm-primary rounded-full animate-bounce" style={{ animationDelay: '0.4s' }}></div>
                      </div>
                      <span className="text-xs text-slate-400 font-medium">Analyzing patterns...</span>
                    </div>
                  </div>
                )}
                <div ref={messagesEndRef} />
              </div>

              <div className="p-4 bg-slate-900 border-t border-slate-800 shrink-0 z-10 print:hidden">
                <div className="max-w-4xl mx-auto flex items-end gap-2 relative">
                  <div className="flex-1 bg-slate-950 rounded-2xl border border-slate-800 focus-within:border-tcm-primary focus-within:ring-1 focus-within:ring-tcm-primary transition-all flex items-end shadow-inner">
                    <textarea
                      value={inputText}
                      onChange={(e) => setInputText(e.target.value)}
                      placeholder={`Type symptoms (${selectedLanguage.split(' ')[0]})...`}
                      className="w-full bg-transparent border-none text-slate-200 placeholder-slate-600 text-sm p-3 max-h-32 focus:ring-0 resize-none scrollbar-hide leading-relaxed"
                      rows={1}
                      style={{ minHeight: '46px' }}
                    />
                  </div>
                  <button
                    onClick={() => handleSendMessage()}
                    disabled={isLoading || (!inputText.trim() && !selectedImage)}
                    className="p-3 bg-tcm-primary hover:bg-tcm-secondary text-white rounded-full transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-tcm-primary/20"
                  >
                    <Send className="w-5 h-5" />
                  </button>
                </div>
              </div>
           </div>
        )}

        {activePanel === 'diagnosis' && (
           <div className="flex-1 min-h-0 bg-slate-950 print:h-auto print:overflow-visible print:bg-white print:text-black print:block">
             <ScoringAndPointsHub 
                analysis={cdssResults} 
                onAnalyzeRequest={() => setIsFormOpen(true)}
                initialSyndromeId={linkedSyndromeId ?? undefined}
                isAnalyzing={isAnalyzing}
                onBack={() => setActivePanel('atlas')}
                patientContext={lastPatientForm}
             />
           </div>
        )}

        {activePanel === 'archive' && (
           <div className="flex-1 min-h-0 bg-slate-950">
             <PatientArchivePanel onLoadPatient={handleLoadPatient} />
           </div>
        )}

        {activePanel === 'ukom' && (
           <div className="flex-1 min-h-0 bg-slate-950">
             <UkomPracticePanel />
           </div>
        )}

        {activePanel === 'wuxing' && (
          <div className="flex-1 min-h-0 bg-slate-950 overflow-hidden">
             <WuXingMasterPanel 
                onSelectSyndrome={(id) => {
                  setLinkedSyndromeId(id);
                  setActivePanel('diagnosis');
                }}
                onShowMap={() => setIsVisualizerOpen(true)}
             />
          </div>
        )}

        {activePanel === 'theory' && (
          <div className="flex-1 min-h-0 bg-slate-950 overflow-hidden">
             <YinYangTheoryWindow />
          </div>
        )}

        {activePanel === 'atlas' && (
          <div className="flex-1 min-h-0 bg-slate-950 overflow-hidden">
             <SyndromeAtlasWindow 
                onSelectSyndrome={(id) => {
                  setLinkedSyndromeId(id);
                  setActivePanel('diagnosis');
                }}
             />
          </div>
        )}

        {activePanel === 'stroke' && (
          <div className="flex-1 min-h-0 bg-slate-950 overflow-hidden">
             <StrokeEducationPanel />
          </div>
        )}

      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { db } from '../services/db';
import { SavedPatient } from '../types';
import { Search, Trash2, User, Calendar, FileText, ChevronRight, Activity, X, RotateCcw, BrainCircuit, MapPin, Stethoscope, Pill, Clipboard, TrendingUp, CheckCircle2, PlusCircle, MinusCircle, AlertCircle } from 'lucide-react';

interface Props {
  onLoadPatient: (patient: SavedPatient) => void;
}

const PatientArchivePanel: React.FC<Props> = ({ onLoadPatient }) => {
  const [patients, setPatients] = useState<SavedPatient[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedPatient, setSelectedPatient] = useState<SavedPatient | null>(null);

  useEffect(() => {
    setPatients(db.patients.getAll());
  }, []);

  const handleDelete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm('Hapus data pasien ini secara permanen dari database lokal?')) {
      db.patients.delete(id);
      setPatients(db.patients.getAll());
      if (selectedPatient?.id === id) setSelectedPatient(null);
    }
  };

  const filteredPatients = patients.filter(p => 
    p.patientName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    p.complaint.toLowerCase().includes(searchTerm.toLowerCase()) ||
    (p.biomedicalDiagnosis && p.biomedicalDiagnosis.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  // --- HISTORICAL ANALYSIS LOGIC ---
  const patientHistory = selectedPatient 
    ? patients
        .filter(p => p.patientName.toLowerCase() === selectedPatient.patientName.toLowerCase() && p.id !== selectedPatient.id)
        .sort((a, b) => b.timestamp - a.timestamp)
    : [];

  const getSymptomEvolution = () => {
    if (!selectedPatient || patientHistory.length === 0) return null;

    const currentSymptoms = selectedPatient.selectedSymptoms || [];
    const previousVisit = patientHistory[0];
    const previousSymptoms = previousVisit.selectedSymptoms || [];

    const persistent = currentSymptoms.filter(s => previousSymptoms.includes(s));
    const newSymptoms = currentSymptoms.filter(s => !previousSymptoms.includes(s));
    const resolved = previousSymptoms.filter(s => !currentSymptoms.includes(s));

    return { persistent, newSymptoms, resolved, previousDate: new Date(previousVisit.timestamp).toLocaleDateString() };
  };

  const evolution = getSymptomEvolution();

  return (
    <div className="h-full flex flex-col md:flex-row bg-slate-950 text-slate-100 overflow-hidden animate-fade-in">
      {/* Sidebar Daftar Pasien */}
      <div className="w-full md:w-80 border-r border-slate-800 bg-slate-900 flex flex-col shrink-0">
        <div className="p-4 border-b border-slate-800">
           <h2 className="text-xl font-bold text-tcm-primary mb-3">Arsip Pasien</h2>
           <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
              <input 
                type="text" 
                placeholder="Cari nama / penyakit..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full bg-slate-950 border border-slate-700 rounded-xl py-2 pl-9 pr-3 text-sm focus:border-tcm-primary outline-none"
              />
           </div>
        </div>
        <div className="flex-1 overflow-y-auto p-2 space-y-1 scrollbar-hide">
           {filteredPatients.map(p => (
             <button 
               key={p.id}
               onClick={() => setSelectedPatient(p)}
               className={`w-full text-left p-3 rounded-xl transition-all border ${
                 selectedPatient?.id === p.id 
                 ? 'bg-tcm-primary/20 border-tcm-primary shadow-lg' 
                 : 'bg-slate-800/40 border-transparent hover:bg-slate-800'
               }`}
             >
                <div className="flex justify-between items-start">
                   <span className="font-bold text-slate-200">{p.patientName || 'Anonim'}</span>
                   <span className="text-[10px] text-slate-500">{new Date(p.timestamp).toLocaleDateString()}</span>
                </div>
                {p.biomedicalDiagnosis && (
                   <p className="text-[10px] text-indigo-400 font-bold uppercase truncate">{p.biomedicalDiagnosis}</p>
                )}
                <p className="text-xs text-slate-400 mt-1 line-clamp-1 italic">"{p.complaint}"</p>
                <div className="flex justify-between items-center mt-2">
                   <span className="text-[10px] px-2 py-0.5 rounded bg-slate-900 border border-slate-700 text-tcm-primary uppercase font-bold tracking-tighter">
                      {p.diagnosis.patternId.replace(/_/g, ' ')}
                   </span>
                   <Trash2 
                    className="w-3.5 h-3.5 text-slate-600 hover:text-rose-500 cursor-pointer transition-colors" 
                    onClick={(e) => handleDelete(e, p.id)}
                   />
                </div>
             </button>
           ))}
           {filteredPatients.length === 0 && (
             <div className="text-center py-10 text-slate-600 text-sm italic">Belum ada pasien tersimpan.</div>
           )}
        </div>
      </div>

      {/* Detail Pasien */}
      <div className="flex-1 overflow-y-auto bg-slate-950 p-6 md:p-10 relative scrollbar-hide">
         {!selectedPatient ? (
           <div className="h-full flex flex-col items-center justify-center text-slate-600">
              <User className="w-16 h-16 mb-4 opacity-10" />
              <p>Pilih pasien untuk melihat detail diagnosis</p>
           </div>
         ) : (
           <div className="max-w-4xl mx-auto space-y-8 animate-slide-in-right">
              <div className="flex flex-col md:flex-row justify-between items-start border-b border-slate-800 pb-6 gap-4">
                 <div>
                    <h1 className="text-3xl font-black text-white">{selectedPatient.patientName || 'Anonim'}</h1>
                    <div className="flex flex-wrap gap-4 mt-2 text-sm text-slate-400">
                       <span className="flex items-center gap-1"><Calendar className="w-4 h-4" /> {new Date(selectedPatient.timestamp).toLocaleString()}</span>
                       <span>Umur: {selectedPatient.age} th</span>
                       <span className="uppercase font-semibold text-tcm-primary">{selectedPatient.sex}</span>
                       {selectedPatient.address && (
                          <span className="flex items-center gap-1"><MapPin className="w-4 h-4" /> {selectedPatient.address}</span>
                       )}
                    </div>
                 </div>
                 <div className="flex items-center gap-3 w-full md:w-auto">
                    <button 
                        onClick={() => onLoadPatient(selectedPatient)}
                        className="flex-1 md:flex-none flex items-center justify-center gap-2 px-6 py-3 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl font-bold shadow-lg shadow-indigo-900/20 transition-all border border-indigo-400/30"
                    >
                        <BrainCircuit className="w-4 h-4" /> Muat ke CDSS
                    </button>
                    <button onClick={() => setSelectedPatient(null)} className="md:hidden p-2 bg-slate-800 rounded-full"><X className="w-6 h-6"/></button>
                 </div>
              </div>

              {/* Symptom Evolution (Historical Analysis) */}
              {evolution && (
                 <div className="bg-slate-900 border border-slate-800 p-6 rounded-2xl shadow-xl">
                    <div className="flex items-center justify-between mb-6">
                       <h3 className="text-sm font-bold text-amber-400 uppercase tracking-widest flex items-center gap-2">
                          <TrendingUp className="w-4 h-4" /> Symptom Evolution (vs {evolution.previousDate})
                       </h3>
                       <span className="text-[10px] text-slate-500 font-bold uppercase">Historical Tracker</span>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                       <div className="bg-slate-950 p-4 rounded-xl border border-slate-800">
                          <div className="flex items-center gap-2 text-emerald-400 font-bold text-[10px] uppercase mb-3">
                             <CheckCircle2 className="w-3 h-3" /> Persistent (Tetap)
                          </div>
                          <div className="flex flex-wrap gap-1.5">
                             {evolution.persistent.length > 0 ? evolution.persistent.map(s => (
                               <span key={s} className="px-2 py-0.5 rounded bg-emerald-900/20 text-emerald-400 text-[10px] font-bold border border-emerald-900/50">{s}</span>
                             )) : <span className="text-[10px] text-slate-600 italic">Tidak ada gejala menetap.</span>}
                          </div>
                       </div>

                       <div className="bg-slate-950 p-4 rounded-xl border border-slate-800">
                          <div className="flex items-center gap-2 text-rose-400 font-bold text-[10px] uppercase mb-3">
                             <PlusCircle className="w-3 h-3" /> New (Muncul Baru)
                          </div>
                          <div className="flex flex-wrap gap-1.5">
                             {evolution.newSymptoms.length > 0 ? evolution.newSymptoms.map(s => (
                               <span key={s} className="px-2 py-0.5 rounded bg-rose-900/20 text-rose-400 text-[10px] font-bold border border-rose-900/50">{s}</span>
                             )) : <span className="text-[10px] text-slate-600 italic">Tidak ada gejala baru.</span>}
                          </div>
                       </div>

                       <div className="bg-slate-950 p-4 rounded-xl border border-slate-800">
                          <div className="flex items-center gap-2 text-indigo-400 font-bold text-[10px] uppercase mb-3">
                             <MinusCircle className="w-3 h-3" /> Resolved (Sembuh)
                          </div>
                          <div className="flex flex-wrap gap-1.5">
                             {evolution.resolved.length > 0 ? evolution.resolved.map(s => (
                               <span key={s} className="px-2 py-0.5 rounded bg-indigo-900/20 text-indigo-400 text-[10px] font-bold border border-indigo-900/50">{s}</span>
                             )) : <span className="text-[10px] text-slate-600 italic">Tidak ada gejala terselesaikan.</span>}
                          </div>
                       </div>
                    </div>
                 </div>
              )}

              {/* Biomedical Summary Box */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                 <div className="bg-slate-900 border border-indigo-500/30 p-5 rounded-2xl shadow-xl">
                    <h3 className="text-sm font-bold text-indigo-400 uppercase tracking-widest mb-4 flex items-center gap-2">
                       <Stethoscope className="w-4 h-4" /> Biomedical Diagnosis
                    </h3>
                    <div className="space-y-3">
                       <div className="bg-slate-950 p-3 rounded-xl border border-slate-800">
                          <span className="text-[10px] text-slate-500 uppercase font-bold block mb-1">Diagnosis (Penyakit)</span>
                          <span className="text-lg font-bold text-white">{selectedPatient.biomedicalDiagnosis || 'Tidak ada data'}</span>
                          {selectedPatient.icd10 && (
                             <span className="ml-2 text-xs bg-indigo-900/50 text-indigo-300 px-2 py-0.5 rounded border border-indigo-800">ICD: {selectedPatient.icd10}</span>
                          )}
                       </div>
                       <div className="bg-slate-950 p-3 rounded-xl border border-slate-800">
                          <span className="text-[10px] text-slate-500 uppercase font-bold block mb-1">Medications (Obat Barat)</span>
                          <p className="text-xs text-slate-300 leading-relaxed">{selectedPatient.medications || 'Tidak ada catatan obat.'}</p>
                       </div>
                    </div>
                 </div>

                 <div className="bg-emerald-950/20 border border-emerald-500/30 p-5 rounded-2xl shadow-xl">
                    <h3 className="text-sm font-bold text-tcm-primary uppercase tracking-widest mb-4 flex items-center gap-2">
                       <Activity className="w-4 h-4" /> TCM Pattern Analysis
                    </h3>
                    <div className="space-y-3">
                       <h4 className="text-xl font-bold text-white border-b border-emerald-900/50 pb-2">{selectedPatient.diagnosis.patternId.replace(/_/g, ' ')}</h4>
                       <div className="flex items-center justify-between">
                          <span className="text-[10px] bg-emerald-900/40 text-emerald-300 px-2 py-0.5 rounded border border-emerald-800 font-bold uppercase">
                             Confidence: {Math.round(selectedPatient.diagnosis.confidence * 100)}%
                          </span>
                       </div>
                       <p className="text-sm text-slate-300 leading-relaxed pt-1 max-h-24 overflow-y-auto italic">
                          {selectedPatient.diagnosis.explanation}
                       </p>
                    </div>
                 </div>
              </div>

              {/* Examination Details */}
              <div className="bg-slate-900 border border-slate-800 p-5 rounded-2xl">
                 <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
                    <Clipboard className="w-4 h-4" /> Examination Details
                 </h3>
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-6 text-sm">
                    <div>
                        <span className="block text-slate-500 font-semibold mb-1">Subjective Complaint:</span>
                        <p className="text-slate-300 bg-slate-950 p-3 rounded-xl border border-slate-800 italic">"{selectedPatient.complaint}"</p>

                        {selectedPatient.selectedSymptoms && selectedPatient.selectedSymptoms.length > 0 && (
                          <div className="mt-4">
                             <span className="block text-slate-500 font-semibold mb-2 text-[10px] uppercase">Selected Symptoms:</span>
                             <div className="flex flex-wrap gap-1.5">
                                {selectedPatient.selectedSymptoms.map(s => (
                                  <span key={s} className="px-2 py-0.5 bg-slate-800 text-slate-400 text-[10px] rounded border border-slate-700">{s}</span>
                                ))}
                             </div>
                          </div>
                        )}
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                       <div className="bg-slate-950/50 p-3 rounded-xl border border-slate-800">
                          <span className="block text-slate-500 font-semibold mb-1 text-[10px] uppercase">Lidah:</span>
                          <p className="text-slate-300 font-medium">{selectedPatient.tongue.body_color} Body</p>
                          <p className="text-[11px] text-slate-400">{selectedPatient.tongue.coating_quality} {selectedPatient.tongue.coating_color} coat</p>
                       </div>
                       <div className="bg-slate-950/50 p-3 rounded-xl border border-slate-800">
                          <span className="block text-slate-500 font-semibold mb-1 text-[10px] uppercase">Nadi:</span>
                          <p className="text-slate-300 font-medium truncate">{selectedPatient.pulse.qualities?.join(', ') || 'N/A'}</p>
                       </div>
                    </div>
                 </div>
              </div>

              {/* Prescription Plan */}
              <div className="bg-slate-900 border border-slate-800 p-5 rounded-2xl shadow-xl">
                 <h3 className="text-sm font-bold text-amber-400 uppercase tracking-widest mb-4">Prescription Plan (Points & Control)</h3>
                 <div className="flex flex-wrap gap-2 mb-6">
                    {selectedPatient.diagnosis.recommendedPoints.map(p => (
                       <span key={p} className="px-3 py-1.5 bg-slate-950 border border-slate-700 rounded-lg text-tcm-primary font-bold text-sm shadow-inner">
                          {p}
                       </span>
                    ))}
                 </div>
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="bg-slate-950 p-4 rounded-xl border border-slate-800">
                        <span className="text-[10px] text-amber-500 font-bold uppercase block mb-1">Prinsip Terapi</span>
                        <p className="text-sm text-slate-300 font-medium">{selectedPatient.treatmentPlan || 'Tidak ditentukan.'}</p>
                    </div>
                    <div className="bg-indigo-900/10 p-4 rounded-xl border border-indigo-500/30">
                        <span className="text-[10px] text-indigo-400 font-bold uppercase block mb-1">Rencana Kontrol (Follow-up)</span>
                        <div className="flex items-center gap-2 text-white font-bold">
                           <Calendar className="w-4 h-4 text-indigo-400" />
                           {selectedPatient.followUpDate ? new Date(selectedPatient.followUpDate).toLocaleDateString('id-ID', { dateStyle: 'full' }) : 'Belum dijadwalkan'}
                        </div>
                    </div>
                 </div>
              </div>

              <div className="flex justify-center pt-10">
                 <button 
                    onClick={() => {
                        if (window.confirm("Muat data ini ke sistem aktif? Diagnosis yang ada saat ini di panel utama akan tertimpa.")) {
                            onLoadPatient(selectedPatient);
                        }
                    }}
                    className="flex items-center gap-2 text-slate-500 hover:text-white transition-colors text-xs font-bold uppercase tracking-widest"
                 >
                    <RotateCcw className="w-4 h-4" /> Pulihkan Sesi Diagnosis Ini
                 </button>
              </div>
           </div>
         )}
      </div>
    </div>
  );
};

export default PatientArchivePanel;

import React, { useState, useRef } from 'react';
import { TcmDiagnosisResult } from '../types';
import { TCM_DB } from '../constants';
import { db } from '../services/db';
import { 
  AlertTriangle, Activity, Stethoscope, GitMerge, MapPin, 
  BrainCircuit, Zap, Target, Layers, Save, FileText, 
  FileDown, Leaf, Map, ChevronRight, Info, Download, Clipboard
} from 'lucide-react';
import DoctorNoteModal from './DoctorNoteModal';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface Props {
  diagnosis: TcmDiagnosisResult;
  isPregnant: boolean;
  onShowVisualizer: (element?: string) => void;
  patientContext?: any;
}

const DiagnosisCard: React.FC<Props> = ({ diagnosis, isPregnant, onShowVisualizer, patientContext }) => {
  const [showNoteModal, setShowNoteModal] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const cardRef = useRef<HTMLDivElement>(null);

  const allSyndromes = [
    ...TCM_DB.syndromes.FILLED_FROM_PDF,
    ...TCM_DB.syndromes.TODO_FROM_PDF
  ];

  const pattern = allSyndromes.find(p => p.id === diagnosis.patternId);
  const patternName = pattern ? pattern.name_id : diagnosis.patternId.replace(/_/g, ' ');

  const handleSaveToArchive = () => {
    let patientName = patientContext?.patientName;
    if (!patientName) {
        patientName = prompt("Masukkan Nama Pasien (Opsional):") || "Anonim";
    }

    // Add missing selectedSymptoms property to the object passed to db.patients.add to satisfy SavedPatient interface.
    db.patients.add({
      id: Date.now().toString(),
      patientName: patientName,
      age: patientContext?.age || "?",
      sex: patientContext?.sex || "?",
      address: patientContext?.address || "",
      complaint: patientContext?.complaint || "Chat Diagnosis",
      symptoms: patientContext?.symptoms || "",
      selectedSymptoms: patientContext?.selectedSymptoms || [],
      tongue: patientContext?.tongue || {},
      pulse: patientContext?.pulse || { qualities: [] },
      diagnosis: diagnosis,
      biomedicalDiagnosis: patientContext?.biomedicalDiagnosis || "",
      icd10: patientContext?.icd10 || "",
      medications: patientContext?.medications || "",
      herbs: patientContext?.herbs || "",
      treatmentPlan: patientContext?.treatmentPlan || pattern?.treatment_principle?.join(', ') || "",
      notes: patientContext?.notes || "",
      followUpDate: patientContext?.followUpDate || "",
      timestamp: Date.now()
    });

    setIsSaved(true);
  };

  const handleVisualizerClick = () => {
    let elementToHighlight = diagnosis.wuxingElement?.toLowerCase();
    if (!elementToHighlight) {
        const text = (diagnosis.wuxingAnalysis || pattern?.wuxing_element || "").toLowerCase();
        if (text.includes('wood') || text.includes('liver') || text.includes('gall')) elementToHighlight = 'wood';
        else if (text.includes('fire') || text.includes('heart') || text.includes('small intestine')) elementToHighlight = 'fire';
        else if (text.includes('earth') || text.includes('spleen') || text.includes('stomach')) elementToHighlight = 'earth';
        else if (text.includes('metal') || text.includes('lung') || text.includes('large intestine')) elementToHighlight = 'metal';
        else if (text.includes('water') || text.includes('kidney') || text.includes('bladder')) elementToHighlight = 'water';
    }
    onShowVisualizer(elementToHighlight);
  };

  const handleExportPDF = async () => {
    if (!cardRef.current) return;
    try {
      const canvas = await html2canvas(cardRef.current, {
        scale: 3,
        useCORS: true,
        backgroundColor: '#020617',
        logging: false
      });
      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');
      const pageWidth = pdf.internal.pageSize.getWidth();
      const imgProps = pdf.getImageProperties(imgData);
      const imgHeight = (imgProps.height * pageWidth) / imgProps.width;
      pdf.addImage(imgData, 'PNG', 0, 0, pageWidth, imgHeight);
      pdf.save(`TCM_Report_${patternName.replace(/\s+/g, '_')}.pdf`);
    } catch (error) {
      console.error("PDF Export Error:", error);
    }
  };

  const handleExportText = () => {
    const textContent = `
=== TCM DIAGNOSIS REPORT ===
Pattern: ${patternName}
Element: ${diagnosis.wuxingElement || 'N/A'}
Confidence: ${Math.round(diagnosis.confidence * 100)}%

ANALYSIS:
- Root (Ben): ${diagnosis.analysisDetail?.root || 'N/A'}
- Branch (Biao): ${diagnosis.analysisDetail?.branch || 'N/A'}
- Explanation: ${diagnosis.explanation}

TREATMENT:
- Recommended Points: ${diagnosis.recommendedPoints.join(', ')}
- Herbal Formula: ${diagnosis.herbal_recommendation?.formula_name || 'N/A'}
- Chief Herbs: ${diagnosis.herbal_recommendation?.chief?.join(', ') || 'N/A'}

LIFESTYLE ADVICE:
${diagnosis.lifestyleAdvice}

Generated by TCM WuXing Pro v${TCM_DB.metadata.version}
    `.trim();

    const blob = new Blob([textContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Diagnosis_${patternName.replace(/\s+/g, '_')}.txt`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const cycleBadge = (() => {
    const dynamic = (diagnosis.wuxingDynamic || "").toLowerCase();
    if (dynamic.includes('overact') || dynamic.includes('cheng')) return { label: 'Overacting (Cheng)', color: 'text-rose-400 bg-rose-500/10 border-rose-500/30', icon: <AlertTriangle className="w-3 h-3"/> };
    if (dynamic.includes('insult') || dynamic.includes('wu')) return { label: 'Insulting (Wu)', color: 'text-orange-400 bg-orange-500/10 border-orange-500/30', icon: <Zap className="w-3 h-3"/> };
    if (dynamic.includes('generat') || dynamic.includes('sheng')) return { label: 'Generating (Sheng)', color: 'text-emerald-400 bg-emerald-500/10 border-emerald-500/30', icon: <Activity className="w-3 h-3"/> };
    if (dynamic.includes('control') || dynamic.includes('ke')) return { label: 'Controlling (Ke)', color: 'text-indigo-400 bg-indigo-500/10 border-indigo-500/30', icon: <GitMerge className="w-3 h-3"/> };
    return { label: 'Balanced', color: 'text-slate-400 bg-slate-500/10 border-slate-500/30', icon: <Info className="w-3 h-3"/> };
  })();

  const elementStyle = (() => {
    const el = (diagnosis.wuxingElement || "").toLowerCase();
    if (el.includes('wood')) return 'border-emerald-500 shadow-emerald-900/20';
    if (el.includes('fire')) return 'border-rose-500 shadow-rose-900/20';
    if (el.includes('earth')) return 'border-amber-500 shadow-amber-900/20';
    if (el.includes('metal')) return 'border-slate-300 shadow-slate-500/20';
    if (el.includes('water')) return 'border-blue-500 shadow-blue-900/20';
    return 'border-slate-800';
  })();

  return (
    <>
      <DoctorNoteModal 
        isOpen={showNoteModal} 
        onClose={() => setShowNoteModal(false)} 
        diagnosis={diagnosis} 
        initialPatientData={{
          name: patientContext?.patientName,
          age: patientContext?.age,
          address: patientContext?.address
        }}
      />

      <div ref={cardRef} className={`group bg-slate-950 border-t-4 ${elementStyle} rounded-3xl p-6 my-6 shadow-2xl animate-fade-in relative overflow-hidden transition-all hover:border-slate-600 print:bg-white print:text-black print:border-gray-300`}>
        {/* Background Accents */}
        <div className="absolute top-0 right-0 w-48 h-48 bg-tcm-primary/5 blur-[100px] rounded-full pointer-events-none"></div>

        {/* Header Section */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8 relative z-10">
          <div className="flex items-center gap-5">
            <div className="w-16 h-16 rounded-2xl bg-slate-900 flex items-center justify-center border border-slate-800 shadow-inner shrink-0 group-hover:scale-105 transition-transform">
               <BrainCircuit className="w-10 h-10 text-tcm-primary" />
            </div>
            <div>
              <div className="flex items-center gap-2 mb-1">
                 <h3 className="text-3xl font-black text-white tracking-tighter uppercase">{patternName}</h3>
                 <span className="text-[10px] bg-emerald-500/20 text-emerald-400 px-2 py-0.5 rounded-full font-black border border-emerald-500/30">
                    {Math.round(diagnosis.confidence * 100)}% CONFIDENCE
                 </span>
              </div>
              <div className="flex items-center gap-2">
                <span className="text-xs text-slate-500 font-bold uppercase tracking-widest">{diagnosis.patternId.replace(/_/g, ' ')}</span>
                {pattern?.name_en && <span className="text-xs text-slate-400 italic font-medium opacity-60">• {pattern.name_en}</span>}
              </div>
            </div>
          </div>

          <div className="flex flex-wrap items-center gap-2 print:hidden">
              <button 
                  onClick={handleSaveToArchive} 
                  disabled={isSaved}
