           ) : (
             <div className="bg-slate-900/40 border border-dashed border-slate-800 p-6 rounded-3xl flex items-center justify-center text-slate-600 text-xs italic">
                <Leaf className="w-5 h-5 mr-3 opacity-20" /> No herbal protocol generated for this pattern.
             </div>
           )}
        </div>

        {/* Lifestyle / Safety Section */}
        <div className="mt-8 flex flex-col md:flex-row gap-4 relative z-10">
           <div className="flex-1 bg-slate-900 border border-slate-800 p-5 rounded-3xl">
              <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3 flex items-center gap-2">
                 <Activity className="w-4 h-4" /> Lifestyle Advice
              </h4>
              <p className="text-xs text-slate-400 leading-relaxed italic">{diagnosis.lifestyleAdvice}</p>
