const getBaseWuxingRelationships = (element: string, patternType: string) => {
  const relationships: any[] = [];
  const el = (element || "").toLowerCase();
  const pt = (patternType || "").toLowerCase();

  if (el.includes('wood') && pt.includes('excess')) {
    relationships.push({
      type: 'Overacting',
      targetElement: 'Earth',
      description: 'Energi Kayu (Hati) yang berlebih menekan sistem Tanah (Limpa/Lambung), mengganggu transportasi dan transformasi nutrisi.'
    });
  } else if (el.includes('fire') && pt.includes('excess')) {
    relationships.push({
      type: 'Overacting',
      targetElement: 'Metal',
      description: 'Panas Api (Jantung) yang berlebih dapat melukai Logam (Paru), menyebabkan gangguan cairan atau panas di saluran napas.'
    });
  } else if (el.includes('water') && pt.includes('deficiency')) {
    relationships.push({
