export const normalize = (s: string) => 
  (s || "").toLowerCase().replace(/[^\p{L}\p{N}\s]/gu, " ").replace(/\s+/g, " ").trim();

const fuzzyMatch = (a: string, b: string, threshold = 0.75): boolean => {
  const normA = normalize(a);
  const normB = normalize(b);
  if (normA.includes(normB) || normB.includes(normA)) return true;
  return false;
};

const extractSymptoms = (text: string): string[] => {
    return text.split(/[\n,.]+/).map(normalize).filter(s => s.length > 2);
};

/**
 * Menghasilkan hubungan Wu Xing patologis mendalam sesuai Maciocia.
 */
const getBaseWuxingRelationships = (element: string, patternType: string) => {
  const relationships: any[] = [];
  const el = (element || "").toLowerCase();
  const pt = (patternType || "").toLowerCase();

  // WOOD (Liver/Gallbladder)
  if (el.includes('wood')) {
    if (pt.includes('excess') || pt.includes('fire')) {
      relationships.push({
        type: 'Overacting',
        targetElement: 'Earth',
        description: 'Kayu (Hati) yang berlebih menyerang Tanah (Limpa), menyebabkan gangguan pencernaan akibat emosi.'
      });
      relationships.push({
        type: 'Insulting',
        targetElement: 'Metal',
        description: 'Kayu yang terlalu kuat menghina Logam (Paru), sering memicu asma atau sesak napas (Liver Fire insulting Lung).'
      });
    } else if (pt.includes('deficiency')) {
      relationships.push({
        type: 'Generating',
        targetElement: 'Fire',
        description: 'Kayu yang lemah gagal menghidupi Api, mengakibatkan Jantung kekurangan suplai darah dan muncul kecemasan.'
      });
    }
  } 

  // FIRE (Heart/Small Intestine)
  else if (el.includes('fire')) {
    if (pt.includes('excess') || pt.includes('heat')) {
      relationships.push({
        type: 'Overacting',
        targetElement: 'Metal',
        description: 'Api (Jantung) yang berlebih melukai Logam (Paru), mengeringkan cairan tubuh di saluran napas.'
      });
    } else if (pt.includes('deficiency')) {
      relationships.push({
        type: 'Generating',
        targetElement: 'Earth',
        description: 'Api yang redup (Yang Def) gagal menghangatkan Tanah (Limpa), menyebabkan diare fajar atau tinja lembek.'
      });
    }
  }

  // EARTH (Spleen/Stomach)
  else if (el.includes('earth')) {
    if (pt.includes('damp') || pt.includes('excess')) {
        relationships.push({
          type: 'Insulting',
          targetElement: 'Wood',
          description: 'Tanah yang lembap membebani Kayu, menghambat aliran bebas Qi Hati.'
        });
    } else if (pt.includes('deficiency')) {
        relationships.push({
          type: 'Generating',
          targetElement: 'Metal',
          description: 'Tanah yang lemah gagal menghasilkan Logam (Spleen Qi Def leads to Lung Qi Def), imunitas menurun.'
        });
    }
  }

  // METAL (Lung/Large Intestine)
  else if (el.includes('metal')) {
    if (pt.includes('deficiency')) {
      relationships.push({
        type: 'Generating',
        targetElement: 'Water',
        description: 'Logam gagal menghasilkan Air, cairan tidak turun ke Ginjal, menyebabkan kekeringan atau panas kosong.'
      });
    }
  }

  // WATER (Kidney/Bladder)
  else if (el.includes('water')) {
    if (pt.includes('deficiency')) {
      relationships.push({
        type: 'Generating',
        targetElement: 'Wood',
        description: 'Air yang kurang gagal menghidupi Kayu (Hati), memicu naiknya Yang Hati (pusing/tinnitus).'
      });
      relationships.push({
        type: 'Insulting',
        targetElement: 'Earth',
        description: 'Air yang lemah dihina oleh Tanah, menyebabkan penumpukan cairan atau edema.'
      });
    }
  }

  return relationships;
};

export const getHerbalRecommendation = (syndrome: Syndrome) => {
  const guidelines = TCM_DB.herbal_guidelines;
  const override = guidelines.per_syndrome_overrides_for_current_DB_snippet[syndrome.id];
  if (override) return { formula_name: override.notes, chief: override.suggest_chief || [] };
  const patternRule = guidelines.herbal_rules_by_pattern_type[syndrome.pattern_type];
  if (patternRule) return { formula_name: patternRule.notes || "Standard Protocol", chief: patternRule.suggest_chief || [] };
  return undefined;
};

export const analyzePatient = (data: any): ScoredSyndrome[] => {
    const allSyndromes = [...TCM_DB.syndromes.FILLED_FROM_PDF];
    const symptomsList = extractSymptoms(data.symptoms || "");

    return allSyndromes.map(syn => {
        let score = 0;
        (syn.key_symptoms || []).forEach(ks => {
            if (symptomsList.some(sel => fuzzyMatch(sel, ks))) score += 20;
        });
        return {
            syndrome: syn,
            score: score
        };
    })
    .filter(s => s.score > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, 3)
    .map(s => ({
        ...s,
        points: Array.isArray(s.syndrome.acupuncture_points) ? s.syndrome.acupuncture_points.map((p:string) => ({code:p, role:'kausal', source:'db'})) : [],
        warnings: [],
        rationale: ["Kecocokan pola klinis Maciocia."],
        herbal_recommendation: getHerbalRecommendation(s.syndrome),
        wuxingRelationships: getBaseWuxingRelationships(s.syndrome.wuxing_element, s.syndrome.pattern_type)
    }));
};

