  const handleNodeClick = (label: string) => {
    const newVal = selectedElement?.toLowerCase() === label.toLowerCase() ? null : label.toLowerCase();
    setSelectedElement(newVal);
    if (onElementSelect) {
      onElementSelect(newVal);
    }
  };

  const positions = {
    fire: { x: 50, y: 18, color: '#f43f5e', label: 'FIRE', icon: <Flame /> },
    earth: { x: 82, y: 42, color: '#f59e0b', label: 'EARTH', icon: <Mountain /> },
    metal: { x: 70, y: 82, color: '#cbd5e1', label: 'METAL', icon: <Wind /> },
    water: { x: 30, y: 82, color: '#3b82f6', label: 'WATER', icon: <Droplets /> },
    wood: { x: 18, y: 42, color: '#10b981', label: 'WOOD', icon: <Leaf /> },
  };

  const elements: WuXingElement[] = [
