      diseaseCorrelations: ["Insomnia", "Palpitasi", "Gangguan Bicara/Afasia", "Sariawan", "Kecemasan Berlebih"]
    },
    { 
      id: 'earth', zang: 'Spleen', fu: 'Stomach', 
      mother: 'fire', child: 'metal', controls: 'water', controlledBy: 'wood', ...positions.earth,
      description: "Element Tanah adalah pusat transformasi dan transportasi nutrisi. Limpa menguasai otot dan anggota gerak.",
      meridians: ["Foot Taiyin (Spleen)", "Foot Yangming (Stomach)"],
      diseaseCorrelations: ["Gastritis/Maag", "Diare/Tinja Lembek", "Kelelahan Kronis (Qi Def)", "Edema", "Obesitas"]
    },
    { 
      id: 'metal', zang: 'Lung', fu: 'Large Intestine', 
      mother: 'earth', child: 'water', controls: 'wood', controlledBy: 'fire', ...positions.metal,
      description: "Element Logam menguasai Qi pernapasan dan pertahanan tubuh (Wei Qi). Paru mengatur pori-pori dan kulit.",
      meridians: ["Hand Taiyin (Lung)", "Hand Yangming (LI)"],
      diseaseCorrelations: ["Asma/Sesak Napas", "Batuk Kronis", "Masalah Kulit/Eksim", "Sembelit", "Imunitas Rendah"]
    },
    { 
      id: 'water', zang: 'Kidney', fu: 'Bladder', 
      mother: 'metal', child: 'wood', controls: 'fire', controlledBy: 'earth', ...positions.water,
      description: "Element Air adalah akar dari kehidupan, menyimpan Jing (esensi) dan menguasai tulang serta sumsum.",
      meridians: ["Foot Shaoyin (Kidney)", "Foot Taiyang (Bladder)"],
      diseaseCorrelations: ["Nyeri Pinggang", "Tinnitus/Pendengaran Menurun", "Infertilitas", "Osteoporosis", "Gangguan Kemih"]
    },
    { 
      id: 'wood', zang: 'Liver', fu: 'Gall Bladder', 
      mother: 'water', child: 'fire', controls: 'earth', controlledBy: 'metal', ...positions.wood,
      description: "Element Kayu mengatur aliran Qi yang lancar dan menguasai tendon. Hati menyimpan darah dan terbuka di mata.",
      meridians: ["Foot Jueyin (Liver)", "Foot Shaoyang (GB)"],
      diseaseCorrelations: ["Stroke/Lumpuh", "Migrain", "Gangguan Menstruasi", "Mata Merah/Kabur", "Hipertensi"]
    },
  ];

  const getOrganData = (name: string): OrganDetail | undefined => {
    return TCM_DB.organ_details[name];
  };

  const isPathActive = (startId: string, endId: string, type: 'generating' | 'controlling') => {
    if (!selectedElement) return false;
    const el = elements.find(e => e.id === selectedElement);
    if (!el) return false;

    if (type === 'generating') {
        // Highlight generating: mother -> self OR self -> child
        return (startId === el.mother && endId === el.id) || (startId === el.id && endId === el.child);
    } else {
        // Highlight controlling: controlledBy -> self OR self -> controls
        return (startId === el.controlledBy && endId === el.id) || (startId === el.id && endId === el.controls);
    }
  };

  const renderArrow = (start: any, end: any, type: 'generating' | 'controlling', key: string) => {
    const startEl = elements.find(e => e.id === Object.keys(positions).find(k => (positions as any)[k].label === start.label));
    const endEl = elements.find(e => e.id === Object.keys(positions).find(k => (positions as any)[k].label === end.label));
    if (!startEl || !endEl) return null;

    const active = isPathActive(startEl.id, endEl.id, type);
    const opacity = selectedElement ? (active ? 1 : 0.05) : 0.4;

    const angle = Math.atan2(end.y - start.y, end.x - start.x);
    const r = 12;
    const x1 = start.x + r * Math.cos(angle);
    const y1 = start.y + r * Math.sin(angle);
    const x2 = end.x - (r + 2) * Math.cos(angle);
    const y2 = end.y - (r + 2) * Math.sin(angle);

    const color = type === 'generating' ? '#10b981' : '#f43f5e';
    const width = active ? 2.5 : 1;
    const dash = type === 'generating' ? '' : '3 2';

    return (
      <g key={key} className="transition-all duration-500">
        <path
          d={`M ${x1} ${y1} L ${x2} ${y2}`}
          stroke={color}
          strokeWidth={width}
          strokeDasharray={dash}
          strokeLinecap="round"
          fill="none"
          opacity={opacity}
          markerEnd={`url(#arrow-${type}${active ? '-active' : ''})`}
          className={active ? "animate-flow" : ""}
          style={active ? { strokeDasharray: type === 'generating' ? '10 5' : '3 2', strokeDashoffset: 0 } : {}}
        />
        {active && (
            <circle cx={x1} cy={y1} r="1" fill={color} className="animate-ping" />
        )}
      </g>
    );
  };

  const activeElementData = elements.find(e => e.id === selectedElement);

  const OrganDetailCard = ({ name, isFu, color }: { name: string, isFu?: boolean, color: string }) => {
    const data = getOrganData(name);
    if (!data) return null;

    return (
      <div className={`mb-3 p-3 rounded-xl border border-slate-800/50 bg-slate-900/50 hover:bg-slate-800/80 transition-colors shadow-sm`}>
        <div className="flex justify-between items-start mb-2">
          <div className="flex flex-col">
            <h4 className="text-sm font-bold text-white flex items-center gap-2">
              <span className="w-1.5 h-3 rounded-full" style={{ backgroundColor: color }}></span>
              {data.name} 
              <span className={`text-[9px] px-1.5 py-0.5 rounded font-black ${isFu ? 'bg-slate-800 text-slate-500' : 'bg-tcm-primary/20 text-tcm-primary'}`}>
                {isFu ? 'FU' : 'ZANG'}
              </span>
            </h4>
          </div>
          <span className="text-[9px] text-slate-500 font-mono">{data.time_of_day}</span>
        </div>
        <div className="text-[10px] text-slate-400 leading-relaxed mb-1">
           {data.main_functions.slice(0, 2).join(' • ')}
        </div>
        <div className="text-[9px] text-slate-500 flex gap-2">
            <span>Sense: {data.sense_organ}</span>
            <span>Flavor: {data.flavor}</span>
        </div>
      </div>
    );
  };

  return (
    <div className={`bg-slate-950 flex flex-col h-full overflow-hidden ${className || ''}`}>
        {!embedded && (
            <div className="flex items-center justify-between p-4 border-b border-slate-800 bg-slate-900 shrink-0">
                <div className="flex flex-col">
                    <h2 className="text-xl font-bold text-emerald-400 flex items-center gap-2">Wu Xing Interactive Master</h2>
                    <p className="text-[10px] text-slate-500 uppercase tracking-widest font-bold">Generating & Controlling Dynamics</p>
                </div>
                {onClose && (
                    <button onClick={onClose} className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-full transition-colors">
                        <X className="w-6 h-6" />
                    </button>
                )}
            </div>
        )}

        <div className="flex-1 overflow-hidden flex flex-col md:flex-row min-h-0">

          {/* DIAGRAM SECTION */}
          <div className={`relative bg-black flex items-center justify-center p-4 md:p-8 transition-all duration-500 ${selectedElement ? 'h-[40%] md:h-full md:flex-1' : 'h-full md:flex-1'}`}>
            <svg 
              viewBox="0 0 100 100" 
              className="w-full h-full max-h-[90%] select-none"
              preserveAspectRatio="xMidYMid meet"
            >
              <defs>
                <marker id="arrow-generating" markerWidth="4" markerHeight="4" refX="4" refY="2" orient="auto">
                  <path d="M0,0 L0,4 L4,2 z" fill="#10b981" opacity="0.4" />
                </marker>
                <marker id="arrow-generating-active" markerWidth="6" markerHeight="6" refX="6" refY="3" orient="auto">
                  <path d="M0,0 L0,6 L6,3 z" fill="#10b981" />
                </marker>
                <marker id="arrow-controlling" markerWidth="4" markerHeight="4" refX="4" refY="2" orient="auto">
                  <path d="M0,0 L0,4 L4,2 z" fill="#f43f5e" opacity="0.4" />
                </marker>
                <marker id="arrow-controlling-active" markerWidth="6" markerHeight="6" refX="6" refY="3" orient="auto">
                  <path d="M0,0 L0,6 L6,3 z" fill="#f43f5e" />
                </marker>
              </defs>

              {/* Generating Cycles (Sheng) */}
              {renderArrow(positions.wood, positions.fire, 'generating', 'wood-fire')}
              {renderArrow(positions.fire, positions.earth, 'generating', 'fire-earth')}
              {renderArrow(positions.earth, positions.metal, 'generating', 'earth-metal')}
              {renderArrow(positions.metal, positions.water, 'generating', 'metal-water')}
              {renderArrow(positions.water, positions.wood, 'generating', 'water-wood')}

              {/* Controlling Cycles (Ke) */}
              {renderArrow(positions.wood, positions.earth, 'controlling', 'wood-earth')}
              {renderArrow(positions.earth, positions.water, 'controlling', 'earth-water')}
              {renderArrow(positions.water, positions.fire, 'controlling', 'water-fire')}
              {renderArrow(positions.fire, positions.metal, 'controlling', 'fire-metal')}
              {renderArrow(positions.metal, positions.wood, 'controlling', 'metal-wood')}

              {/* Nodes */}
              {elements.map((el) => {
                const isSelected = selectedElement === el.id;
                const isDimmed = selectedElement && !isSelected;

                return (
                  <g 
                    key={el.id} 
                    className="cursor-pointer transition-all duration-500" 
                    onClick={() => handleNodeClick(el.id)}
                    style={{ opacity: isDimmed ? 0.3 : 1 }}
                  >
                    {isSelected && (
                       <circle cx={el.x} cy={el.y} r="14" fill="none" stroke={el.color} strokeWidth="0.5" strokeDasharray="2,2" className="animate-spin-slow" />
                    )}
                    <circle 
                      cx={el.x} cy={el.y} 
                      r={isSelected ? "11" : "9"} 
                      fill={isSelected ? el.color : "#0f172a"} 
                      stroke={el.color} 
                      strokeWidth={isSelected ? "2" : "1"} 
                      className="transition-all duration-500 shadow-xl"
                    />
                    <text x={el.x} y={el.y - 1} textAnchor="middle" fontSize="3" fill={isSelected ? 'black' : el.color} fontWeight="900" pointerEvents="none">{el.label}</text>
                    <text x={el.x} y={el.y + 3} textAnchor="middle" fontSize="2.5" fill={isSelected ? 'white' : '#94a3b8'} fontWeight="bold" pointerEvents="none">{el.zang}</text>
                  </g>
                );
              })}
            </svg>

            {/* Legend */}
            <div className={`absolute bottom-6 left-6 flex flex-col gap-2 bg-black/60 p-3 rounded-xl border border-white/5 backdrop-blur-sm transition-opacity duration-500 ${selectedElement ? 'opacity-20 hover:opacity-100' : 'opacity-100'}`}>
               <div className="flex items-center gap-3">
                 <div className="w-8 h-0.5 bg-emerald-500 rounded-full"></div>
                 <span className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Generating (Sheng)</span>
               </div>
               <div className="flex items-center gap-3">
                 <div className="w-8 h-0.5 border-t border-rose-500 border-dashed"></div>
                 <span className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Controlling (Ke)</span>
               </div>
            </div>
          </div>

          {/* DETAIL PANEL */}
          <div className={`bg-slate-950 flex flex-col h-full overflow-hidden transition-all duration-500 border-t md:border-t-0 md:border-l border-slate-800 shrink-0 ${selectedElement ? 'flex-1 md:w-[450px]' : 'h-0 md:w-0 opacity-0'}`}>
            {activeElementData && (
               <div className="flex-1 overflow-y-auto p-5 md:p-8 animate-slide-in-right scrollbar-hide">
                 <div className="mb-8">
                   <button onClick={() => setSelectedElement(null)} className="text-[10px] text-slate-500 hover:text-white font-bold uppercase tracking-widest mb-6 flex items-center gap-2">
                     &larr; View Full Map
                   </button>

                   <div className="flex items-center gap-5">
                      <div className="w-16 h-16 rounded-3xl flex items-center justify-center bg-slate-900 border border-slate-800 shadow-2xl" style={{ color: activeElementData.color }}>
                         {React.cloneElement(activeElementData.icon as React.ReactElement, { className: 'w-8 h-8' })}
                      </div>
                      <div>
                         <h3 className="text-4xl font-black text-white uppercase tracking-tighter">{activeElementData.label}</h3>
                         <div className="flex items-center gap-2 mt-1">
                            <span className="text-[10px] bg-slate-800 px-2 py-0.5 rounded text-slate-400 font-bold uppercase">Elemental Theory</span>
                         </div>
                      </div>
                   </div>
                 </div>

                 <p className="text-sm text-slate-300 leading-relaxed italic mb-8 border-l-2 border-slate-700 pl-4">
                    "{activeElementData.description}"
                 </p>

                 {/* Dynamic Relationships */}
                 <div className="grid grid-cols-2 gap-3 mb-8">
                    <div className="bg-emerald-900/10 border border-emerald-500/30 p-4 rounded-2xl">
                       <div className="text-[10px] text-emerald-400 font-black uppercase mb-1 tracking-widest">Generating</div>
                       <div className="text-xs text-white font-bold uppercase">Mother: <span className="text-emerald-400">{activeElementData.mother}</span></div>
                       <div className="text-xs text-white font-bold uppercase">Child: <span className="text-emerald-400">{activeElementData.child}</span></div>
                    </div>
                    <div className="bg-rose-900/10 border border-rose-500/30 p-4 rounded-2xl">
                       <div className="text-[10px] text-rose-400 font-black uppercase mb-1 tracking-widest">Controlling</div>
                       <div className="text-xs text-white font-bold uppercase">Controls: <span className="text-rose-400">{activeElementData.controls}</span></div>
                       <div className="text-xs text-white font-bold uppercase">Controlled By: <span className="text-rose-400">{activeElementData.controlledBy}</span></div>
                    </div>
                 </div>

                 {/* Meridians & Diseases */}
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
                    <div className="bg-slate-900 p-4 rounded-2xl border border-slate-800">
                        <h4 className="text-[10px] text-indigo-400 font-black uppercase tracking-widest mb-3 flex items-center gap-2">
                            <Activity className="w-3 h-3" /> Meridians
                        </h4>
                        <ul className="space-y-2">
                            {activeElementData.meridians.map(m => (
                                <li key={m} className="text-[11px] text-slate-300 font-medium">• {m}</li>
                            ))}
                        </ul>
                    </div>
                    <div className="bg-slate-900 p-4 rounded-2xl border border-slate-800">
                        <h4 className="text-[10px] text-rose-400 font-black uppercase tracking-widest mb-3 flex items-center gap-2">
                            <Thermometer className="w-3 h-3" /> Potential Pathology
                        </h4>
                        <ul className="space-y-2">
                            {activeElementData.diseaseCorrelations.map(d => (
                                <li key={d} className="text-[11px] text-slate-300 font-medium">• {d}</li>
                            ))}
                        </ul>
                    </div>
                 </div>

                 {/* Associated Organs */}
                 <div className="space-y-4 pb-20">
                    <h4 className="text-[11px] text-slate-500 font-black uppercase tracking-[0.2em] mb-2 flex items-center gap-2">
                       <Heart className="w-4 h-4" /> Zang-Fu Mapping
                    </h4>
                    <OrganDetailCard name={activeElementData.zang} color={activeElementData.color} />
                    {activeElementData.zang2 && <OrganDetailCard name={activeElementData.zang2} color={activeElementData.color} />}
                    <OrganDetailCard name={activeElementData.fu} color={activeElementData.color} isFu />
                    {activeElementData.fu2 && <OrganDetailCard name={activeElementData.fu2} color={activeElementData.color} isFu /> }
                 </div>
               </div>
            )}
          </div>
        </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { X, Flame, Mountain, Wind, Droplets, Leaf, Activity, Heart, Thermometer, ChevronRight } from 'lucide-react';
import { TCM_DB } from '../constants';
import { OrganDetail } from '../types';

interface HighlightedRelationship {
  type: string;
  targetElement: string;
  description?: string;
}

interface Props {
  initialHighlight?: string | null;
  highlightedRelationships?: HighlightedRelationship[];
  onClose?: () => void;
  className?: string;
  embedded?: boolean;
  onElementSelect?: (element: string | null) => void;
  compact?: boolean;
}

interface WuXingElement {
  id: string;
  label: string;
  zang: string;
  fu: string;
  zang2?: string;
  fu2?: string;
  x: number;
  y: number;
  color: string;
  icon: React.ReactNode;
  mother: string;
  child: string;
  controls: string;
  controlledBy: string;
  description: string;
  meridians: string[];
  diseaseCorrelations: string[];
}

export const WuXingInteractiveDiagram: React.FC<Props> = ({ 
  initialHighlight, 
  highlightedRelationships = [], 
  onClose, 
  className, 
  embedded = false, 
  onElementSelect,
  compact = false
}) => {
  const [selectedElement, setSelectedElement] = useState<string | null>(initialHighlight || null);

  useEffect(() => {
    if (initialHighlight) {
      setSelectedElement(initialHighlight);
    }
  }, [initialHighlight]);

  const handleNodeClick = (label: string) => {
    const newVal = selectedElement?.toLowerCase() === label.toLowerCase() ? null : label.toLowerCase();
    setSelectedElement(newVal);
    if (onElementSelect) {
      onElementSelect(newVal);
    }
  };

  const positions = {
    fire: { x: 50, y: 18, color: '#f43f5e', label: 'FIRE', icon: <Flame /> },
    earth: { x: 82, y: 42, color: '#f59e0b', label: 'EARTH', icon: <Mountain /> },
    metal: { x: 70, y: 82, color: '#cbd5e1', label: 'METAL', icon: <Wind /> },
    water: { x: 30, y: 82, color: '#3b82f6', label: 'WATER', icon: <Droplets /> },
    wood: { x: 18, y: 42, color: '#10b981', label: 'WOOD', icon: <Leaf /> },
  };

  const elements: WuXingElement[] = [
    { 
      id: 'fire', zang: 'Heart', fu: 'Small Intestine', zang2: 'Pericardium', fu2: 'San Jiao', 
      mother: 'wood', child: 'earth', controls: 'metal', controlledBy: 'water', ...positions.fire,
      description: "Fire represents vitality and consciousness (Shen). Heart is the Emperor.",
      meridians: ["HT", "SI", "PC", "SJ"],
      diseaseCorrelations: ["Insomnia", "Palpitations", "Anxiety"]
    },
    { 
      id: 'earth', zang: 'Spleen', fu: 'Stomach', 
      mother: 'fire', child: 'metal', controls: 'water', controlledBy: 'wood', ...positions.earth,
      description: "Earth is the center of transformation and transportation.",
      meridians: ["SP", "ST"],
      diseaseCorrelations: ["Fatigue", "Gastritis", "Edema"]
    },
    { 
      id: 'metal', zang: 'Lung', fu: 'Large Intestine', 
      mother: 'earth', child: 'water', controls: 'wood', controlledBy: 'fire', ...positions.metal,
      description: "Metal governs respiration and the Defensive Qi (Wei Qi).",
      meridians: ["LU", "LI"],
      diseaseCorrelations: ["Asthma", "Cough", "Skin issues"]
    },
    { 
      id: 'water', zang: 'Kidney', fu: 'Bladder', 
      mother: 'metal', child: 'wood', controls: 'fire', controlledBy: 'earth', ...positions.water,
      description: "Water is the root of life, storing Jing (Essence).",
      meridians: ["KI", "BL"],
      diseaseCorrelations: ["Back pain", "Tinnitus", "Infertility"]
    },
    { 
      id: 'wood', zang: 'Liver', fu: 'Gall Bladder', 
      mother: 'water', child: 'fire', controls: 'earth', controlledBy: 'metal', ...positions.wood,
      description: "Wood regulates the smooth flow of Qi and governs tendons.",
      meridians: ["LR", "GB"],
      diseaseCorrelations: ["Migraine", "Stroke", "Anger"]
    },
  ];

  const getOrganData = (name: string): OrganDetail | undefined => {
    return TCM_DB.organ_details[name];
  };

  const isPathActive = (startId: string, endId: string, type: 'generating' | 'controlling') => {
    const current = selectedElement || initialHighlight?.toLowerCase();
    if (!current) return false;

    // Check diagnosis-based highlights
    if (highlightedRelationships.length > 0) {
      return highlightedRelationships.some(rel => {
        const target = rel.targetElement.toLowerCase();
        if (type === 'controlling' && (rel.type === 'Overacting' || rel.type === 'Insulting' || rel.type === 'Controlling')) {
          if (rel.type === 'Insulting') return startId === target && endId === current;
          return startId === current && endId === target;
        }
        if (type === 'generating' && rel.type === 'Generating') {
          return startId === current && endId === target;
        }
        return false;
      });
    }

    // Default interactive highlights
    const el = elements.find(e => e.id === current);
    if (!el) return false;
    if (type === 'generating') return (startId === el.mother && endId === el.id) || (startId === el.id && endId === el.child);
    return (startId === el.controlledBy && endId === el.id) || (startId === el.id && endId === el.controls);
  };

  const renderArrow = (start: any, end: any, type: 'generating' | 'controlling', key: string) => {
    const startId = Object.keys(positions).find(k => (positions as any)[k].label === start.label)!;
    const endId = Object.keys(positions).find(k => (positions as any)[k].label === end.label)!;
    const active = isPathActive(startId, endId, type);
    const opacity = (selectedElement || highlightedRelationships.length > 0) ? (active ? 1 : 0.05) : 0.3;

    const angle = Math.atan2(end.y - start.y, end.x - start.x);
    const r = compact ? 8 : 11;
    const x1 = start.x + r * Math.cos(angle);
    const y1 = start.y + r * Math.sin(angle);
    const x2 = end.x - (r + 2) * Math.cos(angle);
    const y2 = end.y - (r + 2) * Math.sin(angle);

    const color = type === 'generating' ? '#10b981' : '#f43f5e';
    return (
      <g key={key} className="transition-all duration-500">
        <path
          d={`M ${x1} ${y1} L ${x2} ${y2}`}
          stroke={color}
          strokeWidth={active ? 2 : 0.8}
          strokeDasharray={type === 'generating' ? '' : '3 2'}
          fill="none"
          opacity={opacity}
          markerEnd={`url(#arrow-${type}${active ? '-active' : ''})`}
          className={active ? "animate-flow" : ""}
        />
      </g>
    );
  };

  const OrganDetailCard = ({ name, isFu, color }: { name: string, isFu?: boolean, color: string }) => {
    const data = getOrganData(name);
    if (!data) return null;
    return (
      <div className="mb-2 p-2 rounded-xl border border-slate-800/50 bg-slate-900/50">
        <div className="flex justify-between items-center mb-1">
          <h4 className="text-[10px] font-bold text-white flex items-center gap-1">
            <span className="w-1 h-2 rounded-full" style={{ backgroundColor: color }}></span>
            {data.name}
            <span className={`text-[7px] px-1 py-0.5 rounded font-black ${isFu ? 'bg-slate-800 text-slate-500' : 'bg-emerald-500/20 text-emerald-400'}`}>
              {isFu ? 'FU' : 'ZANG'}
            </span>
          </h4>
          <span className="text-[7px] text-slate-600 font-mono">{data.time_of_day}</span>
        </div>
        <p className="text-[9px] text-slate-400 line-clamp-1">{data.main_functions[0]}</p>
      </div>
    );
  };

  const activeElementData = elements.find(e => e.id === (selectedElement || initialHighlight?.toLowerCase()));

  return (
    <div className={`bg-slate-950 flex flex-col h-full overflow-hidden ${className || ''}`}>
      {!embedded && !compact && (
        <div className="flex items-center justify-between p-4 border-b border-slate-800 bg-slate-900 shrink-0">
          <h2 className="text-sm font-bold text-emerald-400 uppercase tracking-widest">Wu Xing Dynamics</h2>
          {onClose && <button onClick={onClose} className="p-1 text-slate-400 hover:text-white"><X className="w-5 h-5"/></button>}
        </div>
      )}

      <div className={`flex-1 overflow-hidden flex ${compact ? 'flex-col' : 'flex-col md:flex-row'} min-h-0`}>
        <div className="relative bg-black flex items-center justify-center p-4 flex-1">
          <svg viewBox="0 0 100 100" className="w-full h-full max-h-[90%]">
            <defs>
              <marker id="arrow-generating" markerWidth="3" markerHeight="3" refX="3" refY="1.5" orient="auto"><path d="M0,0 L0,3 L3,1.5 z" fill="#10b981" opacity="0.3"/></marker>
              <marker id="arrow-generating-active" markerWidth="4" markerHeight="4" refX="4" refY="2" orient="auto"><path d="M0,0 L0,4 L4,2 z" fill="#10b981"/></marker>
              <marker id="arrow-controlling" markerWidth="3" markerHeight="3" refX="3" refY="1.5" orient="auto"><path d="M0,0 L0,3 L3,1.5 z" fill="#f43f5e" opacity="0.3"/></marker>
              <marker id="arrow-controlling-active" markerWidth="4" markerHeight="4" refX="4" refY="2" orient="auto"><path d="M0,0 L0,4 L4,2 z" fill="#f43f5e"/></marker>
            </defs>

            {renderArrow(positions.wood, positions.fire, 'generating', 'wf')}
            {renderArrow(positions.fire, positions.earth, 'generating', 'fe')}
            {renderArrow(positions.earth, positions.metal, 'generating', 'em')}
            {renderArrow(positions.metal, positions.water, 'generating', 'mw')}
            {renderArrow(positions.water, positions.wood, 'generating', 'ww')}
            {renderArrow(positions.wood, positions.earth, 'controlling', 'we')}
            {renderArrow(positions.earth, positions.water, 'controlling', 'ew')}
            {renderArrow(positions.water, positions.fire, 'controlling', 'waf')}
            {renderArrow(positions.fire, positions.metal, 'controlling', 'fm')}
            {renderArrow(positions.metal, positions.wood, 'controlling', 'mw-c')}

            {elements.map((el) => (
              <g key={el.id} className="cursor-pointer" onClick={() => handleNodeClick(el.id)}>
                <circle cx={el.x} cy={el.y} r={compact ? 8 : 10} fill={selectedElement === el.id ? el.color : "#0f172a"} stroke={el.color} strokeWidth="1" />
                <text x={el.x} y={el.y + 1} textAnchor="middle" fontSize="2.5" fill={selectedElement === el.id ? 'black' : 'white'} fontWeight="bold">{el.label}</text>
              </g>
            ))}
          </svg>
        </div>

        {!compact && activeElementData && (
          <div className="bg-slate-900 border-l border-slate-800 w-full md:w-64 p-4 overflow-y-auto shrink-0">
            <h3 className="text-xs font-bold text-white uppercase mb-3 flex items-center gap-2">
              <Activity className="w-3 h-3 text-emerald-400"/> {activeElementData.label} Details
            </h3>
            <OrganDetailCard name={activeElementData.zang} color={activeElementData.color} />
            <OrganDetailCard name={activeElementData.fu} color={activeElementData.color} isFu />
            <div className="mt-4 pt-4 border-t border-slate-800">
               <h4 className="text-[9px] font-black text-slate-500 uppercase mb-2">Diseases</h4>
               <div className="flex flex-wrap gap-1">
                  {activeElementData.diseaseCorrelations.map(d => <span key={d} className="text-[8px] bg-slate-950 px-1.5 py-0.5 rounded text-slate-400">{d}</span>)}
               </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useRef, useMemo } from 'react';
import { TcmDiagnosisResult, Syndrome } from '../types';
import { TCM_DB } from '../constants';
import { db } from '../services/db';
import { 
  AlertTriangle, Activity, Stethoscope, GitMerge, MapPin, 
  BrainCircuit, Zap, Target, Layers, Save, FileText, 
  FileDown, Leaf, Map, ChevronRight, Info, Clipboard, Search
} from 'lucide-react';
import DoctorNoteModal from './DoctorNoteModal';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';
import { WuXingInteractiveDiagram } from './WuXingInteractiveDiagram';

interface Props {
  diagnosis: TcmDiagnosisResult;
  isPregnant: boolean;
  onShowVisualizer: (element?: string) => void;
  patientContext?: any;
}

const DiagnosisCard: React.FC<Props> = ({ diagnosis, isPregnant, onShowVisualizer, patientContext }) => {
  const [showNoteModal, setShowNoteModal] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const [syndromeSearch, setSyndromeSearch] = useState('');
  const cardRef = useRef<HTMLDivElement>(null);

  const allSyndromes = useMemo(() => [
    ...TCM_DB.syndromes.FILLED_FROM_PDF,
    ...TCM_DB.syndromes.TODO_FROM_PDF
  ], []);

  const pattern = allSyndromes.find(p => p.id === diagnosis.patternId);
  const patternName = pattern ? pattern.name_id : diagnosis.patternId.replace(/_/g, ' ');
  const displayOrgans = diagnosis.affectedOrgans || pattern?.primary_organs || [];

  const filteredSyndromes = useMemo(() => {
    if (!syndromeSearch.trim()) return [];
    return allSyndromes.filter(s => 
      s.name_id.toLowerCase().includes(syndromeSearch.toLowerCase()) || 
      s.name_en.toLowerCase().includes(syndromeSearch.toLowerCase())
    ).slice(0, 5);
  }, [syndromeSearch, allSyndromes]);

  const handleSaveToArchive = () => {
    let patientName = patientContext?.patientName;
    if (!patientName) {
        patientName = prompt("Masukkan Nama Pasien (Opsional):") || "Anonim";
    }

    db.patients.add({
      id: Date.now().toString(),
      patientName: patientName,
      age: patientContext?.age || "?",
      sex: patientContext?.sex || "?",
      address: patientContext?.address || "",
      complaint: patientContext?.complaint || "Chat Diagnosis",
      symptoms: patientContext?.symptoms || "",
      selectedSymptoms: patientContext?.selectedSymptoms || [],
      tongue: patientContext?.tongue || {},
      pulse: patientContext?.pulse || { qualities: [] },
      diagnosis: diagnosis,
      biomedicalDiagnosis: patientContext?.biomedicalDiagnosis || "",
      icd10: patientContext?.icd10 || "",
      medications: patientContext?.medications || "",
      herbs: patientContext?.herbs || "",
      treatmentPlan: patientContext?.treatmentPlan || pattern?.treatment_principle?.join(', ') || "",
      notes: patientContext?.notes || "",
      followUpDate: patientContext?.followUpDate || "",
      timestamp: Date.now()
    });
    setIsSaved(true);
  };

  const handleExportPDF = async () => {
    if (!cardRef.current) return;
    try {
      const canvas = await html2canvas(cardRef.current, { scale: 2, useCORS: true, backgroundColor: '#020617' });
      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');
      const pageWidth = pdf.internal.pageSize.getWidth();
      const imgProps = pdf.getImageProperties(imgData);
      const imgHeight = (imgProps.height * pageWidth) / imgProps.width;
      pdf.addImage(imgData, 'PNG', 0, 0, pageWidth, imgHeight);
      pdf.save(`TCM_Report_${patternName.replace(/\s+/g, '_')}.pdf`);
    } catch (error) {
      console.error("PDF Export Error:", error);
    }
  };

  const cycleBadge = (() => {
    const dynamic = (diagnosis.wuxingDynamic || "").toLowerCase();
    if (dynamic.includes('overact') || dynamic.includes('cheng')) return { label: 'Overacting (Cheng)', color: 'text-rose-400 bg-rose-500/10 border-rose-500/30', icon: <AlertTriangle className="w-3 h-3"/> };
    if (dynamic.includes('insult') || dynamic.includes('wu')) return { label: 'Insulting (Wu)', color: 'text-orange-400 bg-orange-500/10 border-orange-500/30', icon: <Zap className="w-3 h-3"/> };
    if (dynamic.includes('generat') || dynamic.includes('sheng')) return { label: 'Generating (Sheng)', color: 'text-emerald-400 bg-emerald-500/10 border-emerald-500/30', icon: <Activity className="w-3 h-3"/> };
    return { label: 'Controlling (Ke)', color: 'text-indigo-400 bg-indigo-500/10 border-indigo-500/30', icon: <GitMerge className="w-3 h-3"/> };
  })();

  const elementColorClass = (() => {
    const el = (diagnosis.wuxingElement || "").toLowerCase();
    if (el.includes('wood')) return 'border-emerald-500 shadow-emerald-900/20';
    if (el.includes('fire')) return 'border-rose-500 shadow-rose-900/20';
    if (el.includes('earth')) return 'border-amber-500 shadow-amber-900/20';
    if (el.includes('metal')) return 'border-slate-300 shadow-slate-500/20';
    if (el.includes('water')) return 'border-blue-500 shadow-blue-900/20';
    return 'border-slate-800';
  })();

  return (
    <>
      <DoctorNoteModal isOpen={showNoteModal} onClose={() => setShowNoteModal(false)} diagnosis={diagnosis} initialPatientData={{ name: patientContext?.patientName, age: patientContext?.age, address: patientContext?.address }} />

      <div ref={cardRef} className={`bg-slate-950 border-t-4 ${elementColorClass} rounded-3xl p-6 my-6 shadow-2xl animate-fade-in relative overflow-hidden transition-all print:bg-white print:text-black`}>
        {/* Header Section */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8 relative z-10">
          <div className="flex items-center gap-5">
            <div className="w-16 h-16 rounded-2xl bg-slate-900 flex items-center justify-center border border-slate-800 shadow-inner">
               <BrainCircuit className="w-10 h-10 text-tcm-primary" />
            </div>
            <div>
              <div className="flex items-center gap-2 mb-1">
                 <h3 className="text-3xl font-black text-white tracking-tighter uppercase">{patternName}</h3>
                 <span className="text-[10px] bg-emerald-500/20 text-emerald-400 px-2 py-0.5 rounded-full font-black border border-emerald-500/30">
                    {Math.round(diagnosis.confidence * 100)}% CONFIDENCE
                 </span>
              </div>
              <div className="text-xs text-slate-500 font-bold uppercase tracking-widest">{diagnosis.patternId.replace(/_/g, ' ')}</div>
            </div>
          </div>

          <div className="flex flex-wrap items-center gap-2 print:hidden">
              <button onClick={handleSaveToArchive} disabled={isSaved} className={`px-4 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 border ${isSaved ? 'bg-emerald-950 text-emerald-400 border-emerald-800' : 'bg-slate-900 text-slate-300 border-slate-700'}`}>
                  <Save className="w-4 h-4" /> {isSaved ? 'Archived' : 'Archive'}
              </button>
              <button onClick={() => setShowNoteModal(true)} className="px-4 py-2 bg-tcm-primary hover:bg-emerald-400 text-white rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 shadow-lg">
                  <FileText className="w-4 h-4" /> Rx Note
              </button>
              <button onClick={handleExportPDF} title="Export PDF" className="p-2.5 bg-slate-900 text-slate-400 hover:text-white rounded-xl border border-slate-800"><FileDown className="w-5 h-5" /></button>
          </div>
        </div>

        {/* Pathological Process with Diagram */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8 relative z-10">
           <div className="bg-slate-900/40 border border-indigo-500/20 p-6 rounded-3xl flex flex-col">
              <div className="flex items-center gap-2 mb-4 text-indigo-400 text-[10px] font-black uppercase tracking-[0.3em]">
                 <GitMerge className="w-4 h-4" /> Pathological Process
              </div>
              <div className="flex-1 min-h-[250px] mb-4">
                 <WuXingInteractiveDiagram 
                    initialHighlight={diagnosis.wuxingElement} 
                    highlightedRelationships={diagnosis.wuxingRelationships}
                    compact={true}
                    embedded={true}
                 />
              </div>
              <div className="space-y-3">
                 {diagnosis.wuxingRelationships?.map((rel, i) => (
                    <div key={i} className="flex items-start gap-3 p-3 rounded-xl bg-slate-950/60 border border-slate-800/50">
                       <div className={`mt-1 p-1.5 rounded-lg bg-slate-900 border ${rel.type === 'Overacting' || rel.type === 'Insulting' ? 'border-rose-500/40 text-rose-400' : 'border-indigo-500/40 text-indigo-400'}`}>
                          <ChevronRight className="w-3 h-3" />
                       </div>
                       <div>
                          <span className="font-black text-white text-[10px] uppercase tracking-wider">{rel.type} ⇢ {rel.targetElement}</span>
                          <p className="text-slate-400 text-[11px] leading-relaxed mt-0.5">{rel.description}</p>
                       </div>
                    </div>
                 ))}
              </div>
           </div>

           <div className="flex flex-col gap-6">
              {/* Organs & Element */}
              <div className="grid grid-cols-2 gap-4">
                 <div className="bg-slate-900 border border-slate-800 p-5 rounded-3xl">
                    <div className="flex items-center gap-2 text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3">
                       <Target className="w-4 h-4 text-emerald-500" /> Organs
                    </div>
                    <div className="flex flex-wrap gap-1.5">
                       {displayOrgans.map(org => <span key={org} className="bg-slate-950 px-3 py-1 rounded-xl border border-slate-800 text-xs font-bold text-slate-200">{org}</span>)}
                    </div>
                 </div>
                 <div className="bg-slate-900 border border-slate-800 p-5 rounded-3xl">
                    <div className="flex items-center gap-2 text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3">
                       <Layers className="w-4 h-4 text-tcm-primary" /> Element
                    </div>
                    <div className="flex items-center justify-between">
                       <span className="text-lg font-black text-tcm-primary uppercase tracking-tighter">{diagnosis.wuxingElement || 'General'}</span>
                       <div className={`text-[8px] font-black px-2 py-1 rounded-lg border flex items-center gap-1 uppercase tracking-widest ${cycleBadge.color}`}>
                          {cycleBadge.icon} {cycleBadge.label}
                       </div>
                    </div>
                 </div>
              </div>

              {/* Syndrome Comparison / Search */}
              <div className="bg-slate-900/60 border border-slate-800 p-5 rounded-3xl flex-1">
                 <div className="flex items-center gap-2 mb-4 text-[10px] font-black text-slate-500 uppercase tracking-widest">
                    <Search className="w-4 h-4" /> Syndrome Explorer
                 </div>
                 <div className="relative mb-4">
                    <input 
                      type="text" 
                      placeholder="Compare with other syndromes..."
                      value={syndromeSearch}
                      onChange={e => setSyndromeSearch(e.target.value)}
                      className="w-full bg-slate-950 border border-slate-800 rounded-xl py-2 px-3 text-xs text-white focus:border-tcm-primary outline-none transition-all"
                    />
                 </div>
                 <div className="space-y-2">
                    {filteredSyndromes.map(s => (
                       <div key={s.id} className="p-3 bg-slate-950 border border-slate-800 rounded-xl flex items-center justify-between group hover:border-tcm-primary transition-all">
                          <div>
                             <span className="text-xs font-bold text-slate-200 group-hover:text-tcm-primary">{s.name_id}</span>
                             <span className="block text-[9px] text-slate-600 uppercase">{s.wuxing_element} • {s.pattern_type}</span>
                          </div>
                          <button onClick={() => onShowVisualizer(s.wuxing_element)} className="p-1.5 bg-slate-900 rounded-lg text-slate-500 hover:text-white"><Map className="w-4 h-4"/></button>
                       </div>
                    ))}
                    {!syndromeSearch && <p className="text-[10px] text-slate-600 italic text-center py-4">Search for related syndromes to compare pathology.</p>}
                 </div>
              </div>
           </div>
        </div>

        {/* Synthesis & Points */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 relative z-10">
           <div className="bg-slate-900 border border-slate-800 p-6 rounded-3xl shadow-inner">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4 block">Clinical Explanation</span>
              <p className="text-slate-300 leading-relaxed text-sm font-medium whitespace-pre-line border-l-2 border-tcm-primary pl-6">"{diagnosis.explanation}"</p>
           </div>
           <div className="bg-slate-900 border border-slate-800 p-6 rounded-3xl">
              <h4 className="text-[10px] font-black text-tcm-primary uppercase tracking-[0.3em] mb-4 flex items-center gap-2">
                  <MapPin className="w-4 h-4"/> Acu-Prescription
              </h4>
              <div className="flex flex-wrap gap-2">
                {diagnosis.recommendedPoints.map((point) => (
                    <div key={point} className="px-3 py-1.5 rounded-xl text-xs font-black bg-slate-950 text-tcm-primary border border-tcm-primary/40 shadow-xl transition-all hover:bg-tcm-primary hover:text-white cursor-default">
                      {point}
                    </div>
                ))}
              </div>
           </div>
        </div>
      </div>
    </>
  );
};

