                className={`p-2 rounded-xl border transition-all ${showEncyclopedia ? 'bg-indigo-600 border-indigo-400 text-white' : 'bg-slate-800 border-slate-700 text-slate-400 hover:text-white'}`}
                title="Toggle Encyclopedia"
