                              <p className="text-sm font-bold uppercase tracking-widest">No matching patterns found</p>
                              <p className="text-[10px] mt-1 text-slate-800">Try clearing filters or search query.</p>
                          </div>
                          )}
                      </div>
                      </div>
                  );
                  })}
              </div>
            )}

            <div className="mt-32 py-20 border-t border-slate-900 text-center">
                <p className="text-[10px] text-slate-800 uppercase tracking-[0.5em] font-black font-mono">
                    TCM Wu Xing Master Pro v{TCM_DB.metadata.version}
                </p>
                <p className="text-[9px] text-slate-900 mt-2 uppercase font-bold">Comprehensive Elemental Theory & Syndrome Mapping</p>
            </div>
         </div>
      </div>
    </div>
  );
};

export default WuXingMasterPanel;

import React, { useState, useRef, useMemo } from 'react';
import { TcmDiagnosisResult, Syndrome } from '../types';
import { TCM_DB } from '../constants';
import { db } from '../services/db';
import { 
  AlertTriangle, Activity, Stethoscope, GitMerge, MapPin, 
  BrainCircuit, Zap, Target, Layers, Save, FileText, 
  FileDown, Leaf, Map, ChevronRight, Info, Clipboard, Search, AlertCircle, ShieldAlert
} from 'lucide-react';
import DoctorNoteModal from './DoctorNoteModal';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';
import { WuXingInteractiveDiagram } from './WuXingInteractiveDiagram';

interface Props {
  diagnosis: TcmDiagnosisResult;
  isPregnant: boolean;
  onShowVisualizer: (element?: string) => void;
  patientContext?: any;
}

const DiagnosisCard: React.FC<Props> = ({ diagnosis, isPregnant, onShowVisualizer, patientContext }) => {
  const [showNoteModal, setShowNoteModal] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const [syndromeSearch, setSyndromeSearch] = useState('');
  const cardRef = useRef<HTMLDivElement>(null);

  const allSyndromes = useMemo(() => [
    ...TCM_DB.syndromes.FILLED_FROM_PDF,
    ...TCM_DB.syndromes.TODO_FROM_PDF
  ], []);

  const pattern = allSyndromes.find(p => p.id === diagnosis.patternId);
  const patternName = pattern ? pattern.name_id : diagnosis.patternId.replace(/_/g, ' ');
  const displayOrgans = diagnosis.affectedOrgans || pattern?.primary_organs || [];

  const filteredSyndromes = useMemo(() => {
    if (!syndromeSearch.trim()) return [];
    return allSyndromes.filter(s => 
      s.name_id.toLowerCase().includes(syndromeSearch.toLowerCase()) || 
      s.name_en.toLowerCase().includes(syndromeSearch.toLowerCase())
    ).slice(0, 5);
  }, [syndromeSearch, allSyndromes]);

  const handleSaveToArchive = () => {
    let patientName = patientContext?.patientName;
    if (!patientName) {
        patientName = prompt("Masukkan Nama Pasien (Opsional):") || "Anonim";
    }

    db.patients.add({
      id: Date.now().toString(),
      patientName: patientName,
      age: patientContext?.age || "?",
      sex: patientContext?.sex || "?",
      address: patientContext?.address || "",
      complaint: patientContext?.complaint || "Chat Diagnosis",
      symptoms: patientContext?.symptoms || "",
      selectedSymptoms: patientContext?.selectedSymptoms || [],
      tongue: patientContext?.tongue || {},
      pulse: patientContext?.pulse || { qualities: [] },
      diagnosis: diagnosis,
      biomedicalDiagnosis: patientContext?.biomedicalDiagnosis || "",
      icd10: patientContext?.icd10 || "",
      medications: patientContext?.medications || "",
      herbs: patientContext?.herbs || "",
      treatmentPlan: patientContext?.treatmentPlan || pattern?.treatment_principle?.join(', ') || "",
      notes: patientContext?.notes || "",
      followUpDate: patientContext?.followUpDate || "",
      timestamp: Date.now()
    });
    setIsSaved(true);
  };

  const handleExportPDF = async () => {
    if (!cardRef.current) return;
    try {
      const canvas = await html2canvas(cardRef.current, { scale: 2, useCORS: true, backgroundColor: '#020617' });
      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');
      const pageWidth = pdf.internal.pageSize.getWidth();
      const imgProps = pdf.getImageProperties(imgData);
      const imgHeight = (imgProps.height * pageWidth) / imgProps.width;
      pdf.addImage(imgData, 'PNG', 0, 0, pageWidth, imgHeight);
      pdf.save(`TCM_Report_${patternName.replace(/\s+/g, '_')}.pdf`);
    } catch (error) {
      console.error("PDF Export Error:", error);
    }
  };

  const cycleBadge = (() => {
    const dynamic = (diagnosis.wuxingDynamic || "").toLowerCase();
    if (dynamic.includes('overact') || dynamic.includes('cheng')) return { label: 'Overacting (Cheng)', color: 'text-rose-400 bg-rose-500/10 border-rose-500/30', icon: <AlertTriangle className="w-3 h-3"/> };
    if (dynamic.includes('insult') || dynamic.includes('wu')) return { label: 'Insulting (Wu)', color: 'text-orange-400 bg-orange-500/10 border-orange-500/30', icon: <Zap className="w-3 h-3"/> };
    if (dynamic.includes('generat') || diagnosis.wuxingDynamic?.toLowerCase().includes('sheng')) return { label: 'Generating (Sheng)', color: 'text-emerald-400 bg-emerald-500/10 border-emerald-500/30', icon: <Activity className="w-3 h-3"/> };
    return { label: 'Controlling (Ke)', color: 'text-indigo-400 bg-indigo-500/10 border-indigo-500/30', icon: <GitMerge className="w-3 h-3"/> };
  })();

  const elementColorClass = (() => {
    const el = (diagnosis.wuxingElement || "").toLowerCase();
    if (el.includes('wood')) return 'border-emerald-500 shadow-emerald-900/20';
    if (el.includes('fire')) return 'border-rose-500 shadow-rose-900/20';
    if (el.includes('earth')) return 'border-amber-500 shadow-amber-900/20';
    if (el.includes('metal')) return 'border-slate-300 shadow-slate-500/20';
    if (el.includes('water')) return 'border-blue-500 shadow-blue-900/20';
    return 'border-slate-800';
  })();

  const allContraindications = [
    ...(diagnosis.herbal_recommendation?.avoid || []),
    ...(diagnosis.safetyWarnings || [])
  ];

  return (
    <>
      <DoctorNoteModal isOpen={showNoteModal} onClose={() => setShowNoteModal(false)} diagnosis={diagnosis} initialPatientData={{ name: patientContext?.patientName, age: patientContext?.age, address: patientContext?.address }} />

      <div ref={cardRef} className={`bg-slate-950 border-t-4 ${elementColorClass} rounded-3xl p-6 my-6 shadow-2xl animate-fade-in relative overflow-hidden transition-all print:bg-white print:text-black`}>
        {/* Header Section */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8 relative z-10">
          <div className="flex items-center gap-5">
            <div className="w-16 h-16 rounded-2xl bg-slate-900 flex items-center justify-center border border-slate-800 shadow-inner">
               <BrainCircuit className="w-10 h-10 text-tcm-primary" />
            </div>
            <div>
              <div className="flex items-center gap-2 mb-1">
                 <h3 className="text-3xl font-black text-white tracking-tighter uppercase">{patternName}</h3>
                 <span className="text-[10px] bg-emerald-500/20 text-emerald-400 px-2 py-0.5 rounded-full font-black border border-emerald-500/30">
                    {Math.round(diagnosis.confidence * 100)}% CONFIDENCE
                 </span>
              </div>
              <div className="text-xs text-slate-500 font-bold uppercase tracking-widest">{diagnosis.patternId.replace(/_/g, ' ')}</div>
            </div>
          </div>

          <div className="flex flex-wrap items-center gap-2 print:hidden">
              <button onClick={handleSaveToArchive} disabled={isSaved} className={`px-4 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 border ${isSaved ? 'bg-emerald-950 text-emerald-400 border-emerald-800' : 'bg-slate-900 text-slate-300 border-slate-700'}`}>
                  <Save className="w-4 h-4" /> {isSaved ? 'Archived' : 'Archive'}
              </button>
              <button onClick={() => setShowNoteModal(true)} className="px-4 py-2 bg-tcm-primary hover:bg-emerald-400 text-white rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 shadow-lg">
                  <FileText className="w-4 h-4" /> Rx Note
              </button>
              <button onClick={handleExportPDF} title="Export PDF" className="p-2.5 bg-slate-900 text-slate-400 hover:text-white rounded-xl border border-slate-800"><FileDown className="w-5 h-5" /></button>
          </div>
        </div>

        {/* Pathological Process with Diagram */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8 relative z-10">
