                    <button onClick={() => setSelectedPatient(null)} className="md:hidden p-2 bg-slate-800 rounded-full"><X className="w-6 h-6"/></button>
                 </div>
              </div>

              {/* Visit Timeline Navigator */}
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-2xl overflow-x-auto scrollbar-hide">
                <div className="flex gap-4 min-w-max">
                  {allVisits.map((visit, idx) => (
                    <button 
                      key={visit.id}
                      onClick={() => setSelectedPatient(visit)}
                      className={`flex flex-col items-center gap-1 p-3 rounded-xl border transition-all ${
                        selectedPatient.id === visit.id 
                        ? 'bg-tcm-primary border-tcm-primary shadow-lg shadow-emerald-900/40' 
                        : 'bg-slate-950 border-slate-800 hover:border-slate-700'
                      }`}
                    >
                      <span className={`text-[9px] font-black uppercase ${selectedPatient.id === visit.id ? 'text-white' : 'text-slate-500'}`}>
                        {idx === 0 ? 'Current' : idx === 1 ? 'Last' : `Visit ${allVisits.length - idx}`}
                      </span>
                      <span className={`text-xs font-bold ${selectedPatient.id === visit.id ? 'text-white' : 'text-slate-200'}`}>
                        {new Date(visit.timestamp).toLocaleDateString('id-ID', { day: '2-digit', month: 'short' })}
                      </span>
                    </button>
                  ))}
                </div>
              </div>

              {/* Symptom Frequency & Persistence Analysis */}
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-2 bg-slate-900 border border-slate-800 p-6 rounded-2xl shadow-xl">
                   <h3 className="text-sm font-black text-amber-400 uppercase tracking-[0.2em] flex items-center gap-2 mb-6">
                      <BarChart3 className="w-4 h-4" /> Chronic Symptom Profile
                   </h3>
                   <div className="space-y-4">
                      {symptomFrequency.slice(0, 5).map(([symptom, count]) => (
                        <div key={symptom}>
                           <div className="flex justify-between items-center mb-1.5">
                              <span className="text-xs font-bold text-slate-200">{symptom}</span>
                              <span className="text-[10px] text-slate-500 font-black uppercase tracking-widest">
                                 {Math.round((count / allVisits.length) * 100)}% Persistence
                              </span>
                           </div>
                           <div className="h-1.5 bg-slate-950 rounded-full overflow-hidden border border-slate-800">
                              <div 
                                className="h-full bg-amber-500 transition-all duration-1000" 
                                style={{ width: `${(count / allVisits.length) * 100}%` }}
                              />
                           </div>
                        </div>
                      ))}
                      {symptomFrequency.length === 0 && <p className="text-xs text-slate-600 italic">No persistent symptoms recorded.</p>}
                   </div>
                </div>

                <div className="bg-slate-900 border border-slate-800 p-6 rounded-2xl flex flex-col justify-center items-center text-center">
                   <div className="p-4 bg-indigo-500/10 rounded-full border border-indigo-500/20 mb-4">
                      <Clock className="w-8 h-8 text-indigo-400" />
                   </div>
                   <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Observation Period</h4>
                   <p className="text-xl font-black text-white">
                      {allVisits.length > 1 ? (
                        Math.round((allVisits[0].timestamp - allVisits[allVisits.length-1].timestamp) / (1000 * 60 * 60 * 24))
                      ) : 0} Days
                   </p>
                   <p className="text-[10px] text-slate-600 mt-1 uppercase font-bold">Total care history duration</p>
                </div>
              </div>

              {/* Detailed Symptom Evolution (vs Previous) */}
              {evolution && (
                 <div className="bg-slate-900 border border-slate-800 p-6 rounded-2xl shadow-xl relative overflow-hidden group">
                    <div className="absolute top-0 right-0 p-4 opacity-5">
                       <History className="w-20 h-20" />
                    </div>
                    <div className="flex items-center justify-between mb-8">
                       <h3 className="text-sm font-black text-tcm-primary uppercase tracking-widest flex items-center gap-2">
                          <TrendingUp className="w-4 h-4" /> Comparison: Current vs {evolution.previousDate}
                       </h3>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                       <div className="bg-slate-950 p-5 rounded-2xl border border-slate-800 transition-all hover:border-emerald-500/30">
                          <div className="flex items-center gap-2 text-emerald-400 font-black text-[10px] uppercase mb-4">
                             <CheckCircle2 className="w-4 h-4" /> Stable (Persistent)
                          </div>
                          <div className="flex flex-wrap gap-2">
                             {evolution.persistent.length > 0 ? evolution.persistent.map(s => (
                               <span key={s} className="px-3 py-1 rounded-xl bg-emerald-950/30 text-emerald-400 text-[10px] font-black border border-emerald-900/40">{s}</span>
                             )) : <span className="text-[10px] text-slate-600 italic">No stable symptoms.</span>}
                          </div>
                       </div>

                       <div className="bg-slate-950 p-5 rounded-2xl border border-slate-800 transition-all hover:border-rose-500/30">
                          <div className="flex items-center gap-2 text-rose-400 font-black text-[10px] uppercase mb-4">
                             <PlusCircle className="w-4 h-4" /> New Manifestations
                          </div>
                          <div className="flex flex-wrap gap-2">
                             {evolution.newSymptoms.length > 0 ? evolution.newSymptoms.map(s => (
                               <span key={s} className="px-3 py-1 rounded-xl bg-rose-950/30 text-rose-400 text-[10px] font-black border border-rose-900/40">{s}</span>
                             )) : <span className="text-[10px] text-slate-600 italic">No new symptoms.</span>}
                          </div>
                       </div>

                       <div className="bg-slate-950 p-5 rounded-2xl border border-slate-800 transition-all hover:border-indigo-500/30">
                          <div className="flex items-center gap-2 text-indigo-400 font-black text-[10px] uppercase mb-4">
                             <MinusCircle className="w-4 h-4" /> Resolved (Success)
                          </div>
                          <div className="flex flex-wrap gap-2">
                             {evolution.resolved.length > 0 ? evolution.resolved.map(s => (
                               <span key={s} className="px-3 py-1 rounded-xl bg-indigo-950/30 text-indigo-400 text-[10px] font-black border border-indigo-900/40">{s}</span>
                             )) : <span className="text-[10px] text-slate-600 italic">No resolution observed.</span>}
                          </div>
                       </div>
                    </div>
                 </div>
              )}

              {/* Diagnostic Snapshot */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                 <div className="bg-slate-900 border border-indigo-500/30 p-6 rounded-2xl shadow-xl">
                    <h3 className="text-sm font-black text-indigo-400 uppercase tracking-widest mb-4 flex items-center gap-2">
                       <Stethoscope className="w-4 h-4" /> Diagnosis Snapshot
                    </h3>
                    <div className="space-y-3">
                       <div className="bg-slate-950 p-4 rounded-xl border border-slate-800">
                          <span className="text-[9px] text-slate-500 uppercase font-black block mb-1">Western Biomedical</span>
                          <span className="text-lg font-black text-white">{selectedPatient.biomedicalDiagnosis || 'General Wellness'}</span>
                          {selectedPatient.icd10 && (
                             <span className="ml-2 text-[10px] bg-indigo-900/50 text-indigo-300 px-2 py-0.5 rounded border border-indigo-800 font-black">ICD: {selectedPatient.icd10}</span>
                          )}
                       </div>
                       <div className="bg-slate-950 p-4 rounded-xl border border-slate-800">
                          <span className="text-[9px] text-slate-500 uppercase font-black block mb-1">Primary Complaint</span>
                          <p className="text-xs text-slate-300 italic leading-relaxed">"{selectedPatient.complaint}"</p>
                       </div>
                    </div>
                 </div>

                 <div className="bg-emerald-950/20 border border-emerald-500/30 p-6 rounded-2xl shadow-xl">
                    <h3 className="text-sm font-black text-tcm-primary uppercase tracking-widest mb-4 flex items-center gap-2">
                       <Activity className="w-4 h-4" /> TCM Pattern Analysis
                    </h3>
                    <div className="space-y-3">
                       <h4 className="text-xl font-black text-white border-b border-emerald-900/30 pb-3 uppercase tracking-tighter">
                         {selectedPatient.diagnosis.patternId.replace(/_/g, ' ')}
                       </h4>
                       <div className="flex items-center justify-between mb-4">
                          <div className="bg-emerald-900/40 text-emerald-300 px-3 py-1 rounded-lg border border-emerald-800 font-black text-[10px] uppercase tracking-widest">
                             Confidence: {Math.round(selectedPatient.diagnosis.confidence * 100)}%
                          </div>
                       </div>
                       <p className="text-sm text-slate-300 leading-relaxed font-medium">
                          {selectedPatient.diagnosis.explanation}
                       </p>
                    </div>
                 </div>
              </div>

              {/* Physical Markers Section */}
              <div className="bg-slate-900 border border-slate-800 p-6 rounded-2xl">
                 <h3 className="text-sm font-black text-slate-500 uppercase tracking-widest mb-6 flex items-center gap-2">
                    <Clipboard className="w-4 h-4" /> Physical Exam Markers
                 </h3>
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-8 text-sm">
                    <div className="space-y-4">
                       <div className="bg-slate-950 p-4 rounded-xl border border-slate-800">
                          <span className="block text-[9px] text-slate-500 font-black uppercase mb-2">Subjective Sensation</span>
                          <p className="text-slate-200 font-medium">Lidah: {selectedPatient.tongue.body_color} Body, {selectedPatient.tongue.coating_quality} {selectedPatient.tongue.coating_color} coat</p>
                          <div className="mt-3 flex flex-wrap gap-1.5">
                             {selectedPatient.tongue.special_features?.map(f => (
                               <span key={f} className="px-2 py-0.5 bg-slate-800 text-slate-400 text-[9px] font-bold rounded border border-slate-700">{f}</span>
                             ))}
                          </div>
                       </div>
                    </div>
                    <div>
                       <div className="bg-slate-950 p-4 rounded-xl border border-slate-800 h-full flex flex-col justify-center">
                          <span className="block text-[9px] text-slate-500 font-black uppercase mb-2">Pulse Palpation</span>
                          <div className="flex flex-wrap gap-2">
                            {selectedPatient.pulse.qualities?.map(q => (
                              <span key={q} className="px-3 py-1 bg-slate-800 text-slate-200 text-[10px] font-black rounded-lg border border-slate-700 uppercase tracking-tighter">
                                {q}
                              </span>
                            )) || <span className="text-slate-600">N/A</span>}
                          </div>
                       </div>
                    </div>
                 </div>
              </div>

              {/* Interactive Footer */}
              <div className="flex justify-center py-10 border-t border-slate-900">
                 <button 
                    onClick={() => {
                        if (window.confirm("Restore this diagnostic session to the active CDSS interface?")) {
                            onLoadPatient(selectedPatient);
                        }
                    }}
                    className="flex items-center gap-3 text-slate-500 hover:text-white transition-all text-[10px] font-black uppercase tracking-[0.3em] group"
                 >
                    <RotateCcw className="w-5 h-5 group-hover:rotate-[-90deg] transition-transform" /> Restore Session Data
                 </button>
              </div>
           </div>
         )}
      </div>
    </div>
  );
};

export default PatientArchivePanel;

import React, { useState, useEffect } from 'react';
import { X, Save, Activity, ThermometerSnowflake, User, Stethoscope, Pill, Calendar, Search, UserCheck, ChevronRight, Tag, Info, AlertCircle } from 'lucide-react';
import { db } from '../services/db';
import { SavedPatient } from '../types';

interface PatientData {
  patientName: string;
  age: string;
  sex: string;
  address: string;
  complaint: string;
  symptoms: string;
  selectedSymptoms: string[];
  isAcuteMode: boolean;

  biomedicalDiagnosis: string;
  icd10: string;
  medications: string;
  followUpDate: string;
  notes: string;

  tongue: {
    body_color: string;
    coating_color: string;
    coating_quality: string;
    special_features: string[];
  };
  pulse: {
    qualities: string[];
  };
}

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (data: PatientData) => void;
}

const TONGUE_BODY_COLORS = ['Pale', 'Pink (Normal)', 'Red', 'Deep Red', 'Purple', 'Blue'];
const TONGUE_COAT_COLORS = ['White', 'Yellow', 'Grey', 'Black', 'None'];
const TONGUE_COAT_QUALITIES = ['Thin', 'Thick', 'Dry', 'Wet', 'Greasy/Sticky', 'Peeling/Map', 'None'];
const TONGUE_FEATURES = ['Teeth Marks', 'Cracks', 'Prickles/Spots', 'Swollen', 'Deviated', 'Short/Contracted', 'Quivering'];

const PULSE_QUALITIES = [
  'Floating', 'Deep', 'Slow', 'Rapid', 'Empty/Deficient', 'Full/Excess', 
  'Slippery', 'Wiry', 'Tight', 'Thready/Fine', 'Knotted', 'Intermittent', 'Choppy', 'Hasty'
];

const SYMPTOM_GROUPS = [
  {
    category: "General/Qi",
    items: ['Mudah Lelah', 'Kedinginan', 'Haus Berlebih', 'Berkeringat Malam', 'Keringat Spontan', 'Lemas']
  },
  {
    category: "Head/Mind",
    items: ['Pusing/Dizziness', 'Nyeri Kepala', 'Insomnia', 'Mimpi Banyak', 'Mudah Marah', 'Pelupa']
  },
  {
    category: "Chest/Heart",
    items: ['Palpitasi', 'Napas Pendek', 'Nyeri Dada', 'Sesak Napas', 'Batuk Kering']
  },
  {
    category: "Digestive/Earth",
    items: ['Kembung', 'Mual/Muntah', 'Diare', 'Sembelit', 'Nafsu Makan Turun']
  },
  {
    category: "Lower/Water",
    items: ['Nyeri Punggung', 'Nyeri Lutut', 'Urinitas Sering', 'Urinitas Sedikit']
  }
];

const PatientFormModal: React.FC<Props> = ({ isOpen, onClose, onSubmit }) => {
  const [storedPatients, setStoredPatients] = useState<SavedPatient[]>([]);
  const [showLookup, setShowLookup] = useState(false);
  const [lookupSearch, setLookupSearch] = useState('');

  const [formData, setFormData] = useState<PatientData>({
    patientName: '',
    age: '',
    sex: 'male',
    address: '',
    complaint: '',
    symptoms: '',
    selectedSymptoms: [],
    isAcuteMode: false,
    biomedicalDiagnosis: '',
    icd10: '',
    medications: '',
    followUpDate: '',
    notes: '',
    tongue: {
      body_color: '',
      coating_color: '',
      coating_quality: '',
      special_features: []
    },
    pulse: {
      qualities: []
    }
  });

  useEffect(() => {
    if (isOpen) {
      setStoredPatients(db.patients.getAll());
    }
  }, [isOpen]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(formData);
    onClose();
  };

  const handleSelectExisting = (p: SavedPatient) => {
    setFormData({
      patientName: p.patientName,
      age: p.age,
      sex: p.sex as any,
      address: p.address || '',
      complaint: p.complaint,
      symptoms: p.symptoms,
      selectedSymptoms: p.selectedSymptoms || [],
      isAcuteMode: false,
      biomedicalDiagnosis: p.biomedicalDiagnosis || '',
      icd10: p.icd10 || '',
      medications: p.medications || '',
      followUpDate: p.followUpDate || '',
      notes: p.notes || '',
      tongue: {
        body_color: p.tongue.body_color || '',
        coating_color: p.tongue.coating_color || '',
        coating_quality: p.tongue.coating_quality || '',
        special_features: p.tongue.special_features || []
      },
      pulse: {
        qualities: p.pulse.qualities || []
      }
    });
    setShowLookup(false);
  };

  const toggleSymptom = (symptom: string) => {
    const current = formData.selectedSymptoms;
    const updated = current.includes(symptom)
      ? current.filter(s => s !== symptom)
      : [...current, symptom];
    setFormData({ ...formData, selectedSymptoms: updated });
  };

  const toggleTongueFeature = (feature: string) => {
    const current = formData.tongue.special_features;
    const updated = current.includes(feature)
      ? current.filter(f => f !== feature)
      : [...current, feature];
    setFormData({ ...formData, tongue: { ...formData.tongue, special_features: updated } });
  };

  const togglePulseQuality = (quality: string) => {
    const current = formData.pulse.qualities;
    const updated = current.includes(quality)
      ? current.filter(q => q !== quality)
      : [...current, quality];
    setFormData({ ...formData, pulse: { ...formData.pulse, qualities: updated } });
  };

  const filteredStored = storedPatients.filter(p => 
    p.patientName.toLowerCase().includes(lookupSearch.toLowerCase()) ||
    (p.biomedicalDiagnosis && p.biomedicalDiagnosis.toLowerCase().includes(lookupSearch.toLowerCase()))
  ).slice(0, 5);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-fade-in">
      <div className="bg-slate-800 border border-slate-700 w-full max-w-2xl rounded-2xl shadow-2xl max-h-[90vh] overflow-y-auto scrollbar-hide">
        <div className="flex items-center justify-between p-4 border-b border-slate-700 sticky top-0 bg-slate-800 z-20">
          <div className="flex items-center gap-2">
             <Activity className="w-5 h-5 text-tcm-primary" />
             <h2 className="text-xl font-bold text-tcm-primary">Patient Intake Form</h2>
          </div>
          <div className="flex items-center gap-2">
            <button 
                type="button"
                onClick={() => setShowLookup(!showLookup)}
                className="flex items-center gap-2 px-3 py-1.5 bg-slate-700 hover:bg-slate-600 text-slate-300 rounded-lg text-xs font-bold transition-all border border-slate-600"
            >
                <Search className="w-3.5 h-3.5" /> {showLookup ? 'Tutup Cari' : 'Cari Pasien'}
            </button>
            <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors">
                <X className="w-6 h-6" />
            </button>
          </div>
        </div>

        {showLookup && (
            <div className="p-4 bg-slate-900 border-b border-slate-700 animate-fade-in">
                <div className="relative mb-4">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                    <input 
                        type="text" 
                        placeholder="Ketik nama pasien yang sudah terdaftar..."
                        className="w-full bg-slate-800 border border-slate-700 rounded-xl py-2 pl-10 pr-4 text-sm text-white focus:border-tcm-primary outline-none"
                        value={lookupSearch}
                        onChange={(e) => setLookupSearch(e.target.value)}
                    />
                </div>
                <div className="space-y-2">
                    {filteredStored.map(p => (
                        <button 
                            key={p.id}
                            type="button"
                            onClick={() => handleSelectExisting(p)}
                            className="w-full text-left p-3 rounded-xl bg-slate-800 border border-slate-700 hover:border-tcm-primary flex items-center justify-between group transition-all"
                        >
                            <div className="flex items-center gap-3">
                                <div className="p-2 bg-slate-700 rounded-lg text-slate-400 group-hover:text-tcm-primary">
                                    <UserCheck className="w-4 h-4" />
                                </div>
                                <div>
                                    <span className="block text-sm font-bold text-slate-200">{p.patientName}</span>
                                    <span className="text-[10px] text-slate-500 uppercase">{p.age} th • {p.biomedicalDiagnosis || 'Umum'}</span>
                                </div>
                            </div>
                            <ChevronRight className="w-4 h-4 text-slate-600 group-hover:text-tcm-primary" />
                        </button>
                    ))}
                </div>
            </div>
        )}

        <form onSubmit={handleSubmit} className="p-6 space-y-8">
            {/* Identity Section */}
            <div className="space-y-4">
              <h3 className="text-xs font-bold text-indigo-400 uppercase tracking-widest border-b border-slate-700/50 pb-2">I. Identity</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                      <label className="block text-xs font-semibold text-slate-400 uppercase mb-1">Patient Name</label>
                      <div className="relative">
                        <User className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                        <input 
                            type="text" 
                            className="w-full bg-slate-900 border border-slate-700 rounded-lg pl-10 pr-3 py-2 text-slate-200 focus:border-tcm-primary outline-none transition-all"
                            value={formData.patientName}
                            onChange={e => setFormData({...formData, patientName: e.target.value})}
                            placeholder="Full Name"
                        />
                      </div>
                  </div>
                  <div className="grid grid-cols-2 gap-2">
                    <div>
                        <label className="block text-xs font-semibold text-slate-400 uppercase mb-1">Age</label>
                        <input 
                            type="number" 
                            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-200 focus:border-tcm-primary outline-none"
                            value={formData.age}
                            onChange={e => setFormData({...formData, age: e.target.value})}
                        />
                    </div>
                    <div>
                        <label className="block text-xs font-semibold text-slate-400 uppercase mb-1">Sex</label>
                        <select 
                            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-200 focus:border-tcm-primary outline-none"
                            value={formData.sex}
                            onChange={e => setFormData({...formData, sex: e.target.value})}
                        >
                            <option value="male">Male</option>
                            <option value="female">Female</option>
                        </select>
                    </div>
                  </div>
              </div>
            </div>

            {/* Symptoms Tracking Section */}
            <div className="space-y-4">
              <h3 className="text-xs font-bold text-tcm-primary uppercase tracking-widest border-b border-slate-700/50 pb-2">II. Clinical Manifestations (Symptom Tracking)</h3>

              <div className="space-y-4">
                {SYMPTOM_GROUPS.map((group) => (
                  <div key={group.category}>
                    <label className="block text-[10px] font-black text-slate-500 uppercase mb-2 tracking-widest flex items-center gap-2">
                       <Tag className="w-3 h-3 text-tcm-primary"/> {group.category}
                    </label>
                    <div className="flex flex-wrap gap-2 mb-3">
                       {group.items.map(s => (
                         <button
                          key={s}
                          type="button"
                          onClick={() => toggleSymptom(s)}
                          className={`px-3 py-1.5 rounded-xl text-[10px] font-bold border transition-all ${
                            formData.selectedSymptoms.includes(s)
                            ? 'bg-tcm-primary border-tcm-primary text-white shadow-lg shadow-emerald-900/40'
                            : 'bg-slate-900 border-slate-700 text-slate-500 hover:border-slate-500'
                          }`}
                         >
                           {s}
                         </button>
                       ))}
                    </div>
                  </div>
                ))}
              </div>

              <div className="pt-4">
                  <label className="block text-xs font-semibold text-slate-400 uppercase mb-1 flex items-center gap-2">
                    <Clipboard className="w-3 h-3"/> Detailed Observation / Chief Complaint
                  </label>
                  <textarea 
                      className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-3 text-sm text-slate-200 focus:border-tcm-primary outline-none h-24 transition-colors resize-none font-medium"
                      value={formData.symptoms}
                      onChange={e => setFormData({...formData, symptoms: e.target.value})}
                      placeholder="Add detailed specific symptoms or history here..."
                  />
                  <p className="text-[10px] text-slate-500 mt-2 italic flex items-center gap-1">
                    <Info className="w-3 h-3" /> Detailed symptoms help the AI build a more accurate Wu Xing pathological timeline.
                  </p>
              </div>
            </div>

