import { GoogleGenAI, Type } from "@google/genai";
import { Language, ScoredSyndrome } from '../types';

const getSystemInstruction = (language: Language, isPregnant: boolean, cdssAnalysis?: ScoredSyndrome[]) => {
  let cdssText = "";
  if (cdssAnalysis && cdssAnalysis.length > 0) {
    const primary = cdssAnalysis[0];
    const pointsFormatted = primary.points.map(p => `${p.code} (${p.role})`).join(', ');
    const principle = primary.syndrome.treatment_principle?.join(', ') || "";
    const organs = primary.syndrome.primary_organs?.join(', ') || "";

    cdssText = `
**REFERENSI CDSS (UTAMA):**
- Pola: ${primary.syndrome.name_id} (${primary.syndrome.name_en})
- Elemen: ${primary.syndrome.wuxing_element}
- Organ Terkena: ${organs}
- Titik Dasar: ${pointsFormatted}
    `;
  }

  return `
Anda adalah Sistem Pakar TCM Senior yang mengadopsi 100% literatur Giovanni Maciocia ("The Foundations of Chinese Medicine" & "The Practice of Chinese Medicine").

**ATURAN WAJIB:**
1. **Nomenklatur:** Gunakan Nama Pinyin di awal (Contoh: "Xiao Chang Xu Han" atau "Gan Qi Zhi"). Jangan mengarang istilah sendiri.
2. **Analisis Wu Xing:** Jelaskan patologi berdasarkan siklus Sheng (Generating), Ke (Controlling), Cheng (Overacting), dan Wu (Insulting).
3. **Bahasa:** Gunakan ${language}.
4. **Keamanan:** Jika 'isPregnant' adalah true, berikan peringatan keras untuk titik kontraindikasi (LI4, SP6, BL60, LR3).

**FORMAT OUTPUT:**
Isi field 'patternId' dengan nama Pinyin yang akurat sesuai Maciocia.
Isi 'wuxingRelationships' dengan detail interaksi elemen yang terjadi pada pasien ini.

${cdssText}
`;
};

const diagnosisSchema = {
  type: Type.OBJECT,
  properties: {
    conversationalResponse: { type: Type.STRING },
    diagnosis: {
      type: Type.OBJECT,
      properties: {
        patternId: { type: Type.STRING, description: "Maciocia Pinyin Pattern Name" },
        confidence: { type: Type.NUMBER },
        explanation: { type: Type.STRING },
        recommendedPoints: { type: Type.ARRAY, items: { type: Type.STRING } },
        affectedOrgans: { type: Type.ARRAY, items: { type: Type.STRING } },
        lifestyleAdvice: { type: Type.STRING },
        wuxingElement: { type: Type.STRING },
        wuxingRelationships: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING, description: "Generating, Controlling, Overacting, or Insulting" },
              targetElement: { type: Type.STRING },
              description: { type: Type.STRING }
            },
            required: ["type", "targetElement", "description"]
          }
        },
        herbal_recommendation: {
          type: Type.OBJECT,
          properties: {
            formula_name: { type: Type.STRING },
            chief: { type: Type.ARRAY, items: { type: Type.STRING } },
            assistants: { type: Type.ARRAY, items: { type: Type.STRING } },
            avoid: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["chief"]
        },
        safetyWarnings: { type: Type.ARRAY, items: { type: Type.STRING } }
      },
      required: ["patternId", "explanation", "wuxingRelationships"]
    }
  },
  required: ["conversationalResponse", "diagnosis"]
};

export const sendMessageToGemini = async (
  message: string,
  image: string | undefined,
  history: any[],
  language: Language,
  isPregnant: boolean,
  cdssAnalysis?: ScoredSyndrome[]
) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const parts: any[] = [{ text: message }];
    if (image) {
      const [mimeTypePrefix, base64Data] = image.split(';base64,');
      parts.push({ inlineData: { mimeType: mimeTypePrefix.split(':')[1], data: base64Data } });
    }

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: [
        ...history.slice(-6).map(h => ({ role: h.role === 'user' ? 'user' : 'model', parts: [{ text: h.text }] })),
        { role: 'user', parts }
      ],
      config: {
        systemInstruction: getSystemInstruction(language, isPregnant, cdssAnalysis),
        responseMimeType: "application/json",
        responseSchema: diagnosisSchema
      }
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { X, Flame, Mountain, Wind, Droplets, Leaf, Activity, ChevronRight, AlertTriangle, Zap } from 'lucide-react';
import { TCM_DB } from '../constants';

interface HighlightedRelationship {
  type: string;
  targetElement: string;
  description?: string;
}

interface Props {
  initialHighlight?: string | null;
  highlightedRelationships?: HighlightedRelationship[];
  onClose?: () => void;
  className?: string;
  embedded?: boolean;
  onElementSelect?: (element: string | null) => void;
  compact?: boolean;
}

export const WuXingInteractiveDiagram: React.FC<Props> = ({ 
  initialHighlight, 
  highlightedRelationships = [], 
  onClose, 
  className, 
  embedded = false, 
  onElementSelect,
  compact = false
}) => {
  const [selectedElement, setSelectedElement] = useState<string | null>(initialHighlight || null);

  useEffect(() => {
    if (initialHighlight) setSelectedElement(initialHighlight.toLowerCase());
  }, [initialHighlight]);

  const handleNodeClick = (id: string) => {
    const newVal = selectedElement === id ? null : id;
    setSelectedElement(newVal);
    if (onElementSelect) onElementSelect(newVal);
  };

  // Coordinates for the Pentagram/Circle
  const nodes = {
    fire:  { x: 50, y: 15,  color: '#f43f5e', label: 'FIRE' },
    earth: { x: 85, y: 40,  color: '#f59e0b', label: 'EARTH' },
    metal: { x: 72, y: 80,  color: '#cbd5e1', label: 'METAL' },
    water: { x: 28, y: 80,  color: '#3b82f6', label: 'WATER' },
    wood:  { x: 15, y: 40,  color: '#10b981', label: 'WOOD' }
  };

  const getPathStatus = (start: string, end: string) => {
    const activeRel = highlightedRelationships.find(r => 
      r.targetElement.toLowerCase() === end && (selectedElement === start || initialHighlight?.toLowerCase() === start)
    );

    if (activeRel) return { active: true, type: activeRel.type };

    // Default interactive logic if no specific relationship data is passed
    if (selectedElement === start) {
        // Generating
        const shengMap: any = { wood:'fire', fire:'earth', earth:'metal', metal:'water', water:'wood' };
        if (shengMap[start] === end) return { active: true, type: 'Generating' };
        // Controlling
        const keMap: any = { wood:'earth', earth:'water', water:'fire', fire:'metal', metal:'wood' };
        if (keMap[start] === end) return { active: true, type: 'Controlling' };
    }
    return { active: false, type: null };
  };

  const renderConnection = (startId: string, endId: string, isKeCycle: boolean) => {
    const start = (nodes as any)[startId];
    const end = (nodes as any)[endId];
    const status = getPathStatus(startId, endId);

    const isOveracting = status.type === 'Overacting';
    const isInsulting = status.type === 'Insulting';

    let strokeColor = isKeCycle ? '#f43f5e' : '#10b981';
    let opacity = status.active ? 1 : 0.1;
    let strokeWidth = status.active ? 2.5 : 0.8;
    let dashArray = isKeCycle ? '3,2' : '';

    if (isOveracting) {
        strokeColor = '#ff0000';
        strokeWidth = 4;
        dashArray = '';
    } else if (isInsulting) {
        strokeColor = '#fbbf24';
        strokeWidth = 3;
        dashArray = '2,1';
    }

    const dx = end.x - start.x;
    const dy = end.y - start.y;
    const angle = Math.atan2(dy, dx);
    const r = compact ? 8 : 10;

    const x1 = start.x + r * Math.cos(angle);
    const y1 = start.y + r * Math.sin(angle);
    const x2 = end.x - (r + 2) * Math.cos(angle);
    const y2 = end.y - (r + 2) * Math.sin(angle);

    return (
      <g key={`${startId}-${endId}`}>
        <path
          d={`M ${x1} ${y1} L ${x2} ${y2}`}
          stroke={strokeColor}
          strokeWidth={strokeWidth}
          strokeDasharray={dashArray}
          fill="none"
          opacity={opacity}
          markerEnd={`url(#arrow-${startId}-${endId})`}
          className={status.active ? "animate-flow" : ""}
        />
        <defs>
          <marker id={`arrow-${startId}-${endId}`} markerWidth="3" markerHeight="3" refX="2" refY="1.5" orient="auto">
            <path d="M0,0 L0,3 L3,1.5 z" fill={strokeColor} opacity={opacity} />
          </marker>
        </defs>
      </g>
    );
  };

  return (
    <div className={`bg-slate-950 flex flex-col h-full overflow-hidden ${className || ''}`}>
      <div className="relative bg-black flex items-center justify-center p-6 flex-1">
        <svg viewBox="0 0 100 100" className="w-full h-full max-h-[85vh] drop-shadow-[0_0_20px_rgba(0,0,0,0.5)]">
          {/* Generating Cycle (Outer) */}
          {renderConnection('wood', 'fire', false)}
          {renderConnection('fire', 'earth', false)}
          {renderConnection('earth', 'metal', false)}
          {renderConnection('metal', 'water', false)}
          {renderConnection('water', 'wood', false)}

          {/* Controlling Cycle (Inner Pentagram) */}
          {renderConnection('wood', 'earth', true)}
          {renderConnection('earth', 'water', true)}
          {renderConnection('water', 'fire', true)}
          {renderConnection('fire', 'metal', true)}
          {renderConnection('metal', 'wood', true)}

          {/* Nodes */}
          {Object.entries(nodes).map(([id, node]) => (
            <g key={id} className="cursor-pointer group" onClick={() => handleNodeClick(id)}>
              <circle 
                cx={node.x} cy={node.y} r={compact ? 8 : 10} 
                fill={selectedElement === id ? node.color : "#0f172a"} 
                stroke={node.color} 
                strokeWidth={selectedElement === id ? 3 : 1}
                className="transition-all duration-300"
              />
              <text 
                x={node.x} y={node.y + 1} textAnchor="middle" 
                fontSize="3" fill={selectedElement === id ? 'black' : 'white'} 
                fontWeight="900" className="pointer-events-none uppercase tracking-tighter"
              >
                {node.label}
              </text>
            </g>
          ))}
        </svg>

        {/* Legend Overlay */}
        <div className="absolute bottom-4 left-4 bg-slate-900/80 backdrop-blur-md border border-slate-800 p-3 rounded-xl text-[8px] font-black uppercase tracking-widest space-y-2">
           <div className="flex items-center gap-2"><div className="w-4 h-0.5 bg-emerald-500"></div> Generating (Sheng)</div>
           <div className="flex items-center gap-2"><div className="w-4 h-0.5 border-t border-dashed border-rose-500"></div> Controlling (Ke)</div>
           <div className="flex items-center gap-2"><div className="w-4 h-1 bg-red-600"></div> Overacting (Cheng)</div>
           <div className="flex items-center gap-2"><div className="w-4 h-1 border-t border-dotted border-amber-400"></div> Insulting (Wu)</div>
        </div>
      </div>
    </div>
  );
};

