import React, { useState, useEffect } from 'react';
import { TCM_DB } from '../constants';

interface HighlightedRelationship {
  type: string;
  targetElement: string;
  description?: string;
}

interface Props {
  initialHighlight?: string | null;
  highlightedRelationships?: HighlightedRelationship[];
  onClose?: () => void;
  className?: string;
  embedded?: boolean;
  onElementSelect?: (element: string | null) => void;
  compact?: boolean;
}

export const WuXingInteractiveDiagram: React.FC<Props> = ({ 
  initialHighlight, 
  highlightedRelationships = [], 
  className, 
  onElementSelect,
  compact = false
}) => {
  const [selectedElement, setSelectedElement] = useState<string | null>(initialHighlight || null);

  useEffect(() => {
    if (initialHighlight) setSelectedElement(initialHighlight.toLowerCase());
  }, [initialHighlight]);

  const nodes = {
    fire:  { x: 50, y: 15,  color: '#f43f5e', label: 'FIRE' },
    earth: { x: 85, y: 40,  color: '#f59e0b', label: 'EARTH' },
    metal: { x: 72, y: 80,  color: '#cbd5e1', label: 'METAL' },
    water: { x: 28, y: 80,  color: '#3b82f6', label: 'WATER' },
    wood:  { x: 15, y: 40,  color: '#10b981', label: 'WOOD' }
  };

  const renderConnection = (startId: string, endId: string, isKeCycle: boolean) => {
    const start = (nodes as any)[startId];
    const end = (nodes as any)[endId];

    // Pathological logic
    const rel = highlightedRelationships.find(r => 
       r.targetElement.toLowerCase() === endId && 
       (selectedElement === startId || initialHighlight?.toLowerCase() === startId)
    );

    const isOveracting = rel?.type === 'Overacting';
    const isInsulting = rel?.type === 'Insulting';
    const isActive = !!rel || (selectedElement === startId);

    let strokeColor = isKeCycle ? '#f43f5e' : '#10b981';
    let opacity = isActive ? 1 : 0.1;
    let classNameStr = "";

    if (isOveracting) {
        strokeColor = '#ef4444';
        classNameStr = "path-overacting animate-vibrate";
    } else if (isInsulting) {
        strokeColor = '#f59e0b';
        classNameStr = "path-insulting";
    } else if (isActive && !isKeCycle) {
        classNameStr = "animate-flow";
    }

    const dx = end.x - start.x;
    const dy = end.y - start.y;
    const angle = Math.atan2(dy, dx);
    const r = compact ? 8 : 10;

    const x1 = start.x + r * Math.cos(angle);
    const y1 = start.y + r * Math.sin(angle);
    const x2 = end.x - (r + 2) * Math.cos(angle);
    const y2 = end.y - (r + 2) * Math.sin(angle);

    return (
      <g key={`${startId}-${endId}`}>
        <path
          d={`M ${x1} ${y1} L ${x2} ${y2}`}
          stroke={strokeColor}
          strokeWidth={isActive ? (isOveracting ? 5 : 3) : 1}
          strokeDasharray={isKeCycle && !isOveracting ? "3,2" : ""}
          fill="none"
          opacity={opacity}
          markerEnd={`url(#arrow-${startId}-${endId})`}
          className={classNameStr}
        />
        <defs>
          <marker id={`arrow-${startId}-${endId}`} markerWidth="3" markerHeight="3" refX="2" refY="1.5" orient="auto">
            <path d="M0,0 L0,3 L3,1.5 z" fill={strokeColor} opacity={opacity} />
          </marker>
        </defs>
      </g>
    );
  };

  return (
    <div className={`bg-slate-950 flex flex-col h-full overflow-hidden ${className || ''}`}>
      <div className="relative bg-black flex items-center justify-center p-6 flex-1">
        <svg viewBox="0 0 100 100" className="w-full h-full max-h-[85vh]">
          {/* Sheng Cycle */}
          {renderConnection('wood', 'fire', false)}
          {renderConnection('fire', 'earth', false)}
          {renderConnection('earth', 'metal', false)}
          {renderConnection('metal', 'water', false)}
          {renderConnection('water', 'wood', false)}

          {/* Ke Cycle */}
          {renderConnection('wood', 'earth', true)}
          {renderConnection('earth', 'water', true)}
          {renderConnection('water', 'fire', true)}
          {renderConnection('fire', 'metal', true)}
          {renderConnection('metal', 'wood', true)}

          {Object.entries(nodes).map(([id, node]) => (
            <g key={id} className="cursor-pointer" onClick={() => { setSelectedElement(id); onElementSelect?.(id); }}>
              <circle 
                cx={node.x} cy={node.y} r={compact ? 8 : 10} 
                fill={selectedElement === id ? node.color : "#0f172a"} 
                stroke={node.color} strokeWidth="2"
              />
              <text x={node.x} y={node.y + 1} textAnchor="middle" fontSize="3" fill={selectedElement === id ? 'black' : 'white'} fontWeight="900" className="uppercase">{node.label}</text>
            </g>
          ))}
        </svg>

        <div className="absolute bottom-4 left-4 bg-slate-900/90 border border-slate-800 p-2 rounded-lg text-[7px] font-black uppercase tracking-widest space-y-1">
           <div className="flex items-center gap-2"><div className="w-3 h-0.5 bg-emerald-500"></div> Generating (Sheng)</div>
           <div className="flex items-center gap-2"><div className="w-3 h-1 bg-red-600"></div> Overacting (Penindasan)</div>
           <div className="flex items-center gap-2"><div className="w-3 h-0.5 border-t border-dotted border-amber-400"></div> Insulting (Penghinaan)</div>
        </div>
      </div>
    </div>
  );
};

