  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  useEffect(() => { if (activePanel === 'chat') scrollToBottom(); }, [messages, activePanel]);

  const handleSendMessage = async (textOverride?: string, analysis?: ScoredSyndrome[]) => {
    const textToSend = textOverride || inputText;
    const imageToSend = textOverride ? undefined : (selectedImage || undefined);
    if ((!textToSend.trim() && !imageToSend) || isLoading) return;

    const userMessage: ChatMessage = { id: Date.now().toString(), role: 'user', text: textToSend, image: imageToSend, timestamp: new Date() };
    setMessages(prev => [...prev, userMessage]);
    setInputText('');
    setSelectedImage(null);
    setIsLoading(true);

    try {
      const response = await sendMessageToGemini(textToSend, imageToSend, messages, selectedLanguage, isPregnant, analysis || cdssResults);
      const botMessage: ChatMessage = { id: (Date.now() + 1).toString(), role: 'model', text: response.conversationalResponse, timestamp: new Date(), tcmResult: response.diagnosis };
      setMessages(prev => [...prev, botMessage]);
    } catch (error) {
      setMessages(prev => [...prev, { id: (Date.now() + 1).toString(), role: 'model', text: "Maaf, terjadi kesalahan koneksi. Silakan coba lagi.", timestamp: new Date(), isError: true }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleFormSubmit = (data: any) => {
    setLastPatientForm(data);
