        {activePanel === 'ukom' && <div className="flex-1 min-h-0 bg-slate-950"><UkomPracticePanel /></div>}
        {activePanel === 'wuxing' && <div className="flex-1 min-h-0 bg-slate-950"><WuXingMasterPanel onSelectSyndrome={(id) => { setActivePanel('diagnosis'); }} /></div>}
      </div>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { Language, ScoredSyndrome } from '../types';

const getSystemInstruction = (language: Language, isPregnant: boolean, cdssAnalysis?: ScoredSyndrome[]) => {
  let cdssText = "";
  if (cdssAnalysis && cdssAnalysis.length > 0) {
    const primary = cdssAnalysis[0];
    cdssText = `
**REFERENSI CDSS (Maciocia DB):**
- Pola: ${primary.syndrome.name_id} (${primary.syndrome.name_en})
- Elemen: ${primary.syndrome.wuxing_element}
- Poin Utama: ${primary.syndrome.acupuncture_points?.join(', ')}
    `;
  }

  return `
Anda adalah Pakar Senior TCM yang mengadopsi 100% teori Giovanni Maciocia ("The Foundations of Chinese Medicine").

**KEWAJIBAN KERAS:**
1. **Nama Pinyin:** Gunakan nama Pinyin asli Maciocia untuk field 'patternId'. JANGAN hanya menggunakan bahasa Inggris. (Contoh: "Gan Qi Zhi" untuk Liver Qi Stagnation, "Pi Qi Xu" untuk Spleen Qi Deficiency).
2. **Acu-Points:** Berikan resep titik akupunktur lengkap dengan DESKRIPSI fungsinya sesuai literatur Maciocia (Contoh: "LR3: Menenangkan Hati dan melancarkan Qi").
3. **Analisis Wu Xing:** Jelaskan dinamika elemen secara detail menggunakan siklus Sheng (Generating), Ke (Controlling), Cheng (Overacting), dan Wu (Insulting).
4. **Bahasa:** Gunakan ${language}.

${cdssText}
`;
};

const diagnosisSchema = {
  type: Type.OBJECT,
  properties: {
    conversationalResponse: { type: Type.STRING },
    diagnosis: {
      type: Type.OBJECT,
      properties: {
        patternId: { type: Type.STRING, description: "Nama Pinyin Sindrom Maciocia (WAJIB PINYIN)" },
        confidence: { type: Type.NUMBER },
        explanation: { type: Type.STRING },
        recommendedPoints: { 
          type: Type.ARRAY, 
          items: { 
            type: Type.OBJECT,
            properties: {
              code: { type: Type.STRING },
              description: { type: Type.STRING, description: "Fungsi/Rasional titik ini menurut Maciocia" }
            },
            required: ["code", "description"]
          } 
        },
        affectedOrgans: { type: Type.ARRAY, items: { type: Type.STRING } },
        lifestyleAdvice: { type: Type.STRING },
        wuxingElement: { type: Type.STRING },
        wuxingRelationships: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING, description: "Generating, Controlling, Overacting, or Insulting" },
              targetElement: { type: Type.STRING },
              description: { type: Type.STRING }
            },
            required: ["type", "targetElement", "description"]
          }
        },
        herbal_recommendation: {
          type: Type.OBJECT,
          properties: {
            formula_name: { type: Type.STRING },
            chief: { type: Type.ARRAY, items: { type: Type.STRING } },
            assistants: { type: Type.ARRAY, items: { type: Type.STRING } },
            avoid: { type: Type.ARRAY, items: { type: Type.STRING } }
          }
        }
      },
      required: ["patternId", "explanation", "recommendedPoints", "wuxingRelationships", "wuxingElement"]
    }
  },
  required: ["conversationalResponse", "diagnosis"]
};

export const sendMessageToGemini = async (
  message: string,
  image: string | undefined,
  history: any[],
  language: Language,
  isPregnant: boolean,
  cdssAnalysis?: ScoredSyndrome[]
) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const parts: any[] = [{ text: message }];
    if (image) {
      const [mimeTypePrefix, base64Data] = image.split(';base64,');
      parts.push({ inlineData: { mimeType: mimeTypePrefix.split(':')[1], data: base64Data } });
    }

    // Menggunakan gemini-3-flash-preview untuk kecepatan maksimal
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history.slice(-10).map(h => ({ role: h.role === 'user' ? 'user' : 'model', parts: [{ text: h.text }] })),
        { role: 'user', parts }
      ],
      config: {
        systemInstruction: getSystemInstruction(language, isPregnant, cdssAnalysis),
        responseMimeType: "application/json",
        responseSchema: diagnosisSchema
      }
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

