      >
        {/* Konten Diagnosis Lengkap */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8 relative z-10">
          <div className="flex items-center gap-5">
            <div className="w-16 h-16 rounded-2xl bg-slate-900 flex items-center justify-center border border-slate-800 shadow-inner">
               <BrainCircuit className="w-10 h-10 text-tcm-primary" />
            </div>
            <div>
              <div className="flex items-center gap-2 mb-1">
                 <h3 className="text-2xl font-black text-white tracking-tighter uppercase">{patternName}</h3>
                 <span className="text-[10px] bg-emerald-500/20 text-emerald-400 px-2 py-0.5 rounded-full font-black border border-emerald-500/30">
                    {Math.round(diagnosis.confidence * 100)}% CONFIDENCE
                 </span>
              </div>
              <div className="text-xs text-slate-500 font-bold uppercase tracking-widest">Maciocia Syndrome Classification</div>
            </div>
          </div>

          <div className="flex flex-wrap items-center gap-2 print:hidden">
              <button onClick={handleSaveToArchive} disabled={isSaved} className={`p-2.5 rounded-xl border transition-all ${isSaved ? 'bg-emerald-950 text-emerald-400 border-emerald-800' : 'bg-slate-900 text-slate-400 border-slate-800 hover:text-white'}`}>
                  <Save className="w-5 h-5" />
              </button>
              <button onClick={() => setShowNoteModal(true)} className="px-4 py-2 bg-tcm-primary hover:bg-emerald-400 text-white rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 shadow-lg">
                  <FileText className="w-4 h-4" /> Rx Note
              </button>
              <button 
                onClick={handleExportPDF} 
                disabled={isExporting}
                title="Export PDF" 
                className="p-2.5 bg-slate-900 text-slate-400 hover:text-white rounded-xl border border-slate-800 disabled:opacity-50"
              >
                {isExporting ? <Loader2 className="w-5 h-5 animate-spin" /> : <FileDown className="w-5 h-5" />}
              </button>
          </div>
        </div>

        {/* Pathological Diagram Area */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8 relative z-10">
           <div className="bg-slate-900/40 border border-slate-800/50 p-6 rounded-3xl flex flex-col h-[450px]">
              <div className="flex items-center gap-2 mb-4 text-indigo-400 text-[10px] font-black uppercase tracking-[0.3em]">
                 <GitMerge className="w-4 h-4" /> Pathological Visualizer
              </div>
              <div className="flex-1 min-h-0">
                 <WuXingInteractiveDiagram 
                    initialHighlight={diagnosis.wuxingElement} 
                    highlightedRelationships={diagnosis.wuxingRelationships}
                    compact={true}
                    embedded={true}
                 />
              </div>
           </div>

           <div className="flex flex-col gap-6">
              <div className="grid grid-cols-2 gap-4">
                 <div className="bg-slate-900 border border-slate-800 p-5 rounded-3xl">
                    <div className="flex items-center gap-2 text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3">
                       <Target className="w-4 h-4 text-emerald-500" /> Organs
                    </div>
                    <div className="flex flex-wrap gap-1.5">
                       {displayOrgans.map(org => <span key={org} className="bg-slate-950 px-3 py-1 rounded-xl border border-slate-800 text-xs font-bold text-slate-200">{org}</span>)}
                    </div>
                 </div>
                 <div className="bg-slate-900 border border-slate-800 p-5 rounded-3xl">
                    <div className="flex items-center gap-2 text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3">
                       <Layers className="w-4 h-4 text-tcm-primary" /> Element
                    </div>
                    <span className="text-lg font-black text-tcm-primary uppercase tracking-tighter">{diagnosis.wuxingElement || 'General'}</span>
                 </div>
              </div>

              {/* Related Syndrome Search (Hidden in PDF via CSS if needed, but here we include it) */}
              <div className="bg-slate-900/60 border border-slate-800 p-5 rounded-3xl flex-1 print:hidden">
                 <div className="flex items-center gap-2 mb-4 text-[10px] font-black text-slate-500 uppercase tracking-widest">
                    <Search className="w-4 h-4" /> Related Patterns
                 </div>
                 <div className="space-y-2 max-h-[200px] overflow-y-auto scrollbar-hide">
                    {filteredSyndromes.map(s => (
