              </div>
           </div>
        </div>

        {/* Diagnosis & Acu-Prescription Details */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8 relative z-10">
           <div className="bg-slate-900 border border-slate-800 p-6 rounded-3xl shadow-inner">
