import React, { useState, useEffect } from 'react';

interface HighlightedRelationship {
  type: string;
  targetElement: string;
  description?: string;
}

interface Props {
  initialHighlight?: string | null;
  highlightedRelationships?: HighlightedRelationship[];
  onClose?: () => void;
  className?: string;
  embedded?: boolean;
  onElementSelect?: (element: string | null) => void;
  compact?: boolean;
}

export const WuXingInteractiveDiagram: React.FC<Props> = ({ 
  initialHighlight, 
  highlightedRelationships = [], 
  className, 
  onElementSelect,
  compact = false
}) => {
  const [selectedElement, setSelectedElement] = useState<string | null>(initialHighlight || null);

  useEffect(() => {
    if (initialHighlight) setSelectedElement(initialHighlight.toLowerCase());
  }, [initialHighlight]);

  // Coordinates (Percentage on 100x100)
  const nodes = {
    fire:  { x: 50, y: 15,  color: '#f43f5e', label: 'FIRE' },
    earth: { x: 85, y: 40,  color: '#f59e0b', label: 'EARTH' },
    metal: { x: 72, y: 80,  color: '#cbd5e1', label: 'METAL' },
    water: { x: 28, y: 80,  color: '#3b82f6', label: 'WATER' },
    wood:  { x: 15, y: 40,  color: '#10b981', label: 'WOOD' }
  };

  const isPathologyActive = highlightedRelationships.length > 0;

  const renderConnection = (startId: string, endId: string, baseType: 'Sheng' | 'Ke') => {
    const start = (nodes as any)[startId];
    const end = (nodes as any)[endId];

    // Cek hubungan patologis spesifik
    const rel = highlightedRelationships.find(r => 
       r.targetElement.toLowerCase() === endId && 
       (selectedElement === startId || initialHighlight?.toLowerCase() === startId)
    );

    const insultingRel = highlightedRelationships.find(r => 
        r.type === 'Insulting' && 
        r.targetElement.toLowerCase() === startId &&
        (selectedElement === endId || initialHighlight?.toLowerCase() === endId)
    );

    const isOveracting = rel?.type === 'Overacting';
    const isInsulting = !!insultingRel;
    const isGenerating = rel?.type === 'Generating' || (!isPathologyActive && selectedElement === startId && baseType === 'Sheng');
    const isControlling = rel?.type === 'Controlling' || (!isPathologyActive && selectedElement === startId && baseType === 'Ke');

    const isActivePathology = isOveracting || isInsulting;

    // Jika ada patologi, jalur normal (Sheng/Ke) dibuat hampir tidak terlihat (opacity 0.05)
    // Kecuali jalur tersebut adalah bagian dari patologi yang sedang di-highlight
    let opacity = 0.1;
    if (isPathologyActive) {
        opacity = isActivePathology ? 1 : 0.03;
    } else {
        opacity = (isGenerating || isControlling) ? 0.8 : 0.15;
    }

    let strokeColor = baseType === 'Ke' ? '#f43f5e' : '#10b981';
    let classNameStr = "";
    let dashArray = (baseType === 'Ke' && !isOveracting) ? "3,2" : "";
    let strokeWidth = isActivePathology ? 4 : 1.5;

    if (isOveracting) {
        strokeColor = '#ef4444'; // Merah menyala untuk Menindas
        strokeWidth = 6;
        dashArray = "";
        classNameStr = "path-overacting animate-vibrate";
    } else if (isInsulting) {
        strokeColor = '#f59e0b'; // Amber untuk Menghina
        strokeWidth = 5;
        dashArray = "1,2";
        classNameStr = "path-insulting animate-flow";
    } else if (isGenerating) {
        classNameStr = "animate-flow";
        strokeWidth = 3;
    }

    // Arah panah: Insulting (Wu) adalah kebalikan dari Ke normal
    const x1_raw = isInsulting ? end.x : start.x;
    const y1_raw = isInsulting ? end.y : start.y;
    const x2_raw = isInsulting ? start.x : end.x;
    const y2_raw = isInsulting ? start.y : end.y;

    const dx = x2_raw - x1_raw;
    const dy = y2_raw - y1_raw;
    const angle = Math.atan2(dy, dx);
    const r = compact ? 8 : 10;

    const x1 = x1_raw + r * Math.cos(angle);
    const y1 = y1_raw + r * Math.sin(angle);
    const x2 = x2_raw - (r + 3) * Math.cos(angle);
    const y2 = y2_raw - (r + 3) * Math.sin(angle);

    return (
      <g key={`${startId}-${endId}-${baseType}`}>
        <path
          d={`M ${x1} ${y1} L ${x2} ${y2}`}
          stroke={strokeColor}
          strokeWidth={strokeWidth}
          strokeDasharray={dashArray}
          fill="none"
          opacity={opacity}
          markerEnd={`url(#arrow-${startId}-${endId}-${baseType})`}
          className={classNameStr}
          style={{ transition: 'all 0.5s ease' }}
        />
        <defs>
          <marker id={`arrow-${startId}-${endId}-${baseType}`} markerWidth="4" markerHeight="4" refX="3" refY="2" orient="auto">
            <path d="M0,0 L0,4 L4,2 z" fill={strokeColor} opacity={opacity} />
          </marker>
        </defs>
      </g>
    );
  };

  return (
    <div className={`bg-slate-950 flex flex-col h-full overflow-hidden ${className || ''}`}>
      <div className="relative bg-black flex items-center justify-center p-6 flex-1">
        <svg viewBox="0 0 100 100" className="w-full h-full max-h-[85vh]">
          {/* Efek Glow untuk Patologi */}
          <defs>
            <filter id="pathology-glow">
              <feGaussianBlur stdDeviation="1.5" result="blur" />
              <feComposite in="SourceGraphic" in2="blur" operator="over" />
            </filter>
          </defs>

          {/* Sheng Cycle */}
          {renderConnection('wood', 'fire', 'Sheng')}
          {renderConnection('fire', 'earth', 'Sheng')}
          {renderConnection('earth', 'metal', 'Sheng')}
          {renderConnection('metal', 'water', 'Sheng')}
          {renderConnection('water', 'wood', 'Sheng')}

          {/* Ke Cycle */}
          {renderConnection('wood', 'earth', 'Ke')}
          {renderConnection('earth', 'water', 'Ke')}
          {renderConnection('water', 'fire', 'Ke')}
          {renderConnection('fire', 'metal', 'Ke')}
          {renderConnection('metal', 'wood', 'Ke')}

          {/* Nodes (Elemen) */}
          {Object.entries(nodes).map(([id, node]) => {
            const isTargetOfPathology = highlightedRelationships.some(r => r.targetElement.toLowerCase() === id);
            const isSourceOfPathology = selectedElement === id || initialHighlight?.toLowerCase() === id;
            const isInvolved = isTargetOfPathology || isSourceOfPathology;

            // Redupkan elemen yang tidak terlibat jika mode patologi aktif
            const nodeOpacity = isPathologyActive ? (isInvolved ? 1 : 0.2) : 1;

            return (
              <g 
                key={id} 
                className="cursor-pointer group" 
                onClick={() => { setSelectedElement(id); onElementSelect?.(id); }}
                style={{ opacity: nodeOpacity, transition: 'opacity 0.5s ease' }}
              >
                <circle 
                  cx={node.x} cy={node.y} r={compact ? 8 : 10} 
                  fill={selectedElement === id ? node.color : "#0f172a"} 
                  stroke={node.color} 
                  strokeWidth={selectedElement === id ? 3 : 1}
                  className="transition-all duration-300"
                />
                <text 
                  x={node.x} y={node.y + 1} 
                  textAnchor="middle" 
                  fontSize="3.5" 
                  fill={selectedElement === id ? 'black' : 'white'} 
                  fontWeight="900" 
                  className="pointer-events-none uppercase tracking-tighter"
                >
                  {node.label}
                </text>
              </g>
            );
          })}
        </svg>

        {/* Legend Dinamis */}
        <div className="absolute bottom-4 left-4 bg-slate-900/90 border border-slate-800 p-3 rounded-xl text-[8px] font-black uppercase tracking-widest space-y-2">
           {isPathologyActive ? (
             <>
               <div className="text-indigo-400 mb-1 border-b border-slate-800 pb-1">Pathology Focus</div>
               <div className="flex items-center gap-2">
                  <div className="w-4 h-1 bg-red-600 shadow-[0_0_5px_rgba(239,68,68,0.8)]"></div> 
                  Menindas (Cheng)
               </div>
               <div className="flex items-center gap-2">
                  <div className="w-4 h-0.5 border-t border-dotted border-amber-400"></div> 
                  Menghina (Wu)
               </div>
             </>
           ) : (
             <>
               <div className="flex items-center gap-2">
                  <div className="w-4 h-0.5 bg-emerald-500"></div> 
                  Generating (Sheng)
               </div>
               <div className="flex items-center gap-2">
                  <div className="w-4 h-0.5 border-t border-dashed border-rose-500"></div> 
                  Controlling (Ke)
               </div>
             </>
           )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useMemo } from 'react';
import { TcmDiagnosisResult, Syndrome } from '../types';
import { TCM_DB } from '../constants';
import { db } from '../services/db';
import { 
  AlertTriangle, Activity, Stethoscope, GitMerge, MapPin, 
  BrainCircuit, Zap, Target, Layers, Save, FileText, 
  FileDown, Leaf, Map, ChevronRight, Info, Search, AlertCircle, Loader2
} from 'lucide-react';
import DoctorNoteModal from './DoctorNoteModal';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';
import { WuXingInteractiveDiagram } from './WuXingInteractiveDiagram';

interface Props {
  diagnosis: TcmDiagnosisResult;
  isPregnant: boolean;
  onShowVisualizer: (element?: string) => void;
  patientContext?: any;
}

const DiagnosisCard: React.FC<Props> = ({ diagnosis, isPregnant, onShowVisualizer, patientContext }) => {
  const [showNoteModal, setShowNoteModal] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const [isExporting, setIsExporting] = useState(false);
  const [syndromeSearch, setSyndromeSearch] = useState('');
  const cardRef = useRef<HTMLDivElement>(null);

  const allSyndromes = useMemo(() => [
    ...TCM_DB.syndromes.FILLED_FROM_PDF,
    ...TCM_DB.syndromes.TODO_FROM_PDF
  ], []);

  const patternName = diagnosis.patternId; 
  const displayOrgans = diagnosis.affectedOrgans || [];

  const filteredSyndromes = useMemo(() => {
    const query = syndromeSearch.trim().toLowerCase();
    if (!query) {
      return allSyndromes.filter(s => 
        s.wuxing_element.toLowerCase() === (diagnosis.wuxingElement || "").toLowerCase()
      ).slice(0, 5);
    }
    return allSyndromes.filter(s => 
      s.name_id.toLowerCase().includes(query) || 
      s.name_en.toLowerCase().includes(query) ||
      s.id.toLowerCase().includes(query)
    ).slice(0, 5);
  }, [syndromeSearch, allSyndromes, diagnosis]);

  const handleSaveToArchive = () => {
    let patientName = patientContext?.patientName || prompt("Masukkan Nama Pasien:") || "Anonim";
    db.patients.add({
      id: Date.now().toString(),
      patientName: patientName,
      age: patientContext?.age || "?",
      sex: patientContext?.sex || "?",
      address: patientContext?.address || "",
      complaint: patientContext?.complaint || "Chat Diagnosis",
      symptoms: patientContext?.symptoms || "",
      selectedSymptoms: patientContext?.selectedSymptoms || [],
      tongue: patientContext?.tongue || {},
      pulse: patientContext?.pulse || { qualities: [] },
      diagnosis: diagnosis,
      timestamp: Date.now()
    });
    setIsSaved(true);
  };

  const handleExportPDF = async () => {
    if (!cardRef.current || isExporting) return;
    setIsExporting(true);

    try {
      // Pastikan capture menangkap seluruh tinggi elemen
      const canvas = await html2canvas(cardRef.current, { 
        scale: 2, 
        useCORS: true, 
        backgroundColor: '#020617', // Slate-950
        logging: false,
        allowTaint: true,
        height: cardRef.current.scrollHeight, 
        windowHeight: cardRef.current.scrollHeight,
        onclone: (clonedDoc) => {
          const el = clonedDoc.querySelector('[data-pdf-content="true"]') as HTMLElement;
          if (el) {
            el.style.height = 'auto';
            el.style.maxHeight = 'none';
            el.style.overflow = 'visible';
          }
        }
      });

      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');

      const pageWidth = pdf.internal.pageSize.getWidth();
      const pageHeight = pdf.internal.pageSize.getHeight();
      const margin = 10;
      const contentWidth = pageWidth - (margin * 2);

      const imgProps = pdf.getImageProperties(imgData);
      const imgHeight = (imgProps.height * contentWidth) / imgProps.width;

      let heightLeft = imgHeight;
      let position = 0;

      // Halaman Pertama
      pdf.setFillColor(2, 6, 23); 
      pdf.rect(0, 0, pageWidth, pageHeight, 'F');
      pdf.addImage(imgData, 'PNG', margin, margin, contentWidth, imgHeight);
      heightLeft -= (pageHeight - margin * 2);

      // Tambah Halaman jika konten masih ada (Multi-page)
      while (heightLeft > 0) {
        position = heightLeft - imgHeight + margin; 
        pdf.addPage();
        pdf.setFillColor(2, 6, 23);
        pdf.rect(0, 0, pageWidth, pageHeight, 'F');
        pdf.addImage(imgData, 'PNG', margin, position, contentWidth, imgHeight);
        heightLeft -= pageHeight;
      }

      pdf.save(`TCM_Report_${patternName.replace(/\s+/g, '_')}.pdf`);
    } catch (error) {
      console.error("PDF Export Error:", error);
      alert("Gagal mengekspor PDF. Pastikan browser Anda mendukung fitur ini.");
    } finally {
      setIsExporting(false);
    }
  };

  const elementColorClass = (() => {
    const el = (diagnosis.wuxingElement || "").toLowerCase();
    if (el.includes('wood')) return 'border-emerald-500 shadow-emerald-900/20';
    if (el.includes('fire')) return 'border-rose-500 shadow-rose-900/20';
    if (el.includes('earth')) return 'border-amber-500 shadow-amber-900/20';
    if (el.includes('metal')) return 'border-slate-300 shadow-slate-500/20';
    if (el.includes('water')) return 'border-blue-500 shadow-blue-900/20';
    return 'border-slate-800';
  })();

  return (
    <>
      <DoctorNoteModal isOpen={showNoteModal} onClose={() => setShowNoteModal(false)} diagnosis={diagnosis} initialPatientData={{ name: patientContext?.patientName }} />

      <div 
        ref={cardRef} 
        data-pdf-content="true"
        className={`bg-slate-950 border-t-4 ${elementColorClass} rounded-3xl p-6 my-6 shadow-2xl animate-fade-in relative overflow-hidden transition-all h-auto`}
      >
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8 relative z-10">
          <div className="flex items-center gap-5">
            <div className="w-16 h-16 rounded-2xl bg-slate-900 flex items-center justify-center border border-slate-800 shadow-inner">
               <BrainCircuit className="w-10 h-10 text-tcm-primary" />
            </div>
            <div>
              <div className="flex items-center gap-2 mb-1">
                 <h3 className="text-2xl font-black text-white tracking-tighter uppercase">{patternName}</h3>
                 <span className="text-[10px] bg-emerald-500/20 text-emerald-400 px-2 py-0.5 rounded-full font-black border border-emerald-500/30">
                    {Math.round(diagnosis.confidence * 100)}% CONFIDENCE
                 </span>
              </div>
              <div className="text-xs text-slate-500 font-bold uppercase tracking-widest">Maciocia Syndrome Classification</div>
            </div>
          </div>

          <div className="flex flex-wrap items-center gap-2 print:hidden">
              <button onClick={handleSaveToArchive} disabled={isSaved} className={`p-2.5 rounded-xl border transition-all ${isSaved ? 'bg-emerald-950 text-emerald-400 border-emerald-800' : 'bg-slate-900 text-slate-400 border-slate-800 hover:text-white'}`}>
                  <Save className="w-5 h-5" />
              </button>
              <button onClick={() => setShowNoteModal(true)} className="px-4 py-2 bg-tcm-primary hover:bg-emerald-400 text-white rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 shadow-lg">
                  <FileText className="w-4 h-4" /> Rx Note
              </button>
              <button 
                onClick={handleExportPDF} 
                disabled={isExporting}
                title="Export PDF" 
                className="p-2.5 bg-slate-900 text-slate-400 hover:text-white rounded-xl border border-slate-800 disabled:opacity-50"
              >
                {isExporting ? <Loader2 className="w-5 h-5 animate-spin" /> : <FileDown className="w-5 h-5" />}
              </button>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8 relative z-10">
           <div className="bg-slate-900/40 border border-slate-800/50 p-6 rounded-3xl flex flex-col h-[450px]">
              <div className="flex items-center gap-2 mb-4 text-indigo-400 text-[10px] font-black uppercase tracking-[0.3em]">
                 <GitMerge className="w-4 h-4" /> Pathological Visualizer
              </div>
              <div className="flex-1 min-h-0">
                 <WuXingInteractiveDiagram 
                    initialHighlight={diagnosis.wuxingElement} 
                    highlightedRelationships={diagnosis.wuxingRelationships}
                    compact={true}
                    embedded={true}
                 />
              </div>
           </div>

           <div className="flex flex-col gap-6">
              <div className="grid grid-cols-2 gap-4">
                 <div className="bg-slate-900 border border-slate-800 p-5 rounded-3xl">
                    <div className="flex items-center gap-2 text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3">
                       <Target className="w-4 h-4 text-emerald-500" /> Organs
                    </div>
                    <div className="flex flex-wrap gap-1.5">
                       {displayOrgans.map(org => <span key={org} className="bg-slate-950 px-3 py-1 rounded-xl border border-slate-800 text-xs font-bold text-slate-200">{org}</span>)}
                    </div>
                 </div>
                 <div className="bg-slate-900 border border-slate-800 p-5 rounded-3xl">
                    <div className="flex items-center gap-2 text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3">
                       <Layers className="w-4 h-4 text-tcm-primary" /> Element
                    </div>
                    <span className="text-lg font-black text-tcm-primary uppercase tracking-tighter">{diagnosis.wuxingElement || 'General'}</span>
                 </div>
              </div>

              <div className="bg-slate-900/60 border border-slate-800 p-5 rounded-3xl flex-1 print:hidden">
                 <div className="flex items-center gap-2 mb-4 text-[10px] font-black text-slate-500 uppercase tracking-widest">
                    <Search className="w-4 h-4" /> Related Patterns
                 </div>
                 <div className="space-y-2 max-h-[200px] overflow-y-auto scrollbar-hide">
                    {filteredSyndromes.map(s => (
                       <div key={s.id} className="p-3 bg-slate-950 border border-slate-800 rounded-xl flex items-center justify-between group">
                          <div>
                             <span className="text-xs font-bold text-slate-200">{s.name_id}</span>
                             <span className="block text-[9px] text-slate-600 uppercase">{s.wuxing_element}</span>
                          </div>
                       </div>
                    ))}
                 </div>
              </div>
           </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8 relative z-10">
           <div className="bg-slate-900 border border-slate-800 p-6 rounded-3xl shadow-inner">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4 block">Clinical Synthesis</span>
              <p className="text-slate-300 leading-relaxed text-sm italic border-l-2 border-tcm-primary pl-4">"{diagnosis.explanation}"</p>
