import { TcmDiagnosisResult } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  diagnosis: TcmDiagnosisResult;
  initialPatientData?: {
    name?: string;
    age?: string;
    address?: string;
  };
}

const DoctorNoteModal: React.FC<Props> = ({ isOpen, onClose, diagnosis, initialPatientData }) => {
  const [clinicName, setClinicName] = useState('Klinik TCM WuXing Sejahtera');
  const [doctorName, setDoctorName] = useState('Dr. TCM Practitioner');
  const [patientName, setPatientName] = useState(initialPatientData?.name || '');
  const [age, setAge] = useState(initialPatientData?.age || '');
  const [address, setAddress] = useState(initialPatientData?.address || '');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [signature, setSignature] = useState<string | null>(null);

  // Perbaikan mapping titik akupunktur agar tidak muncul [object Object]
  const pointCodes = (diagnosis.recommendedPoints || []).map(p => p.code).join(', ');

  const defaultNotes = `DIAGNOSIS: ${diagnosis.patternId.replace(/_/g, ' ')}

TERAPI AKUPUNKTUR:
${pointCodes || '-'}

RESEP HERBAL:
${diagnosis.herbal_recommendation ? `${diagnosis.herbal_recommendation.formula_name || 'Formula Individual'}
- Utama: ${diagnosis.herbal_recommendation.chief.join(', ')}
- Pendamping: ${(diagnosis.herbal_recommendation.assistants || []).join(', ')}` : '-'}

SARAN LIFESTYLE:
${diagnosis.lifestyleAdvice}`;

  const [notes, setNotes] = useState(defaultNotes);
  const [isGenerating, setIsGenerating] = useState(false);

  const receiptRef = useRef<HTMLDivElement>(null);

  const handleSignatureUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSignature(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const generatePDF = async () => {
    if (!receiptRef.current) return;
    setIsGenerating(true);

    try {
      const canvas = await html2canvas(receiptRef.current, {
        scale: 3,
        useCORS: true,
        backgroundColor: '#ffffff'
      });

      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a5');
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = pdf.internal.pageSize.getHeight();

      pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      pdf.save(`Resep_TCM_${patientName || 'Pasien'}_${date}.pdf`);
    } catch (err) {
      console.error("PDF Gen Error", err);
      alert("Gagal membuat PDF.");
    } finally {
      setIsGenerating(false);
    }
  };

  const generateTextFile = () => {
    const textContent = `
========================================
       ${clinicName.toUpperCase()}
       ${doctorName}
========================================

DATA PASIEN:
- Nama: ${patientName || '-'}
- Umur: ${age} th
- Alamat: ${address || '-'}
- Tanggal: ${date}

----------------------------------------
ISI RESEP & CATATAN:
----------------------------------------
${notes}

----------------------------------------
Generated by TCM WuXing Pro System
========================================
    `.trim();

    const blob = new Blob([textContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Resep_${patientName || 'Pasien'}_${date}.txt`;
    link.click();
    URL.revokeObjectURL(url);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/90 backdrop-blur-sm p-4 animate-fade-in">
      <div className="bg-slate-900 border border-slate-700 w-full max-w-6xl h-[90vh] rounded-3xl shadow-2xl flex flex-col md:flex-row overflow-hidden">

        {/* LEFT: Controls */}
        <div className="w-full md:w-[380px] bg-slate-800 p-6 overflow-y-auto border-r border-slate-700 flex flex-col gap-5">
           <div className="flex items-center justify-between">
              <h2 className="text-xl font-black text-white flex items-center gap-3">
                 <FileSignature className="w-6 h-6 text-tcm-primary" /> Rx Builder
              </h2>
              <button onClick={onClose} className="text-slate-500 hover:text-white transition-colors"><X className="w-6 h-6"/></button>
           </div>

           <div className="space-y-4">
              <div className="space-y-3">
                 <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Klinik & Praktisi</label>
                 <input className="w-full bg-slate-950 border border-slate-700 rounded-xl px-4 py-2.5 text-sm text-white focus:border-tcm-primary outline-none transition-all" 
                        value={clinicName} onChange={e => setClinicName(e.target.value)} placeholder="Nama Klinik" />
                 <input className="w-full bg-slate-950 border border-slate-700 rounded-xl px-4 py-2.5 text-sm text-white focus:border-tcm-primary outline-none transition-all" 
                        value={doctorName} onChange={e => setDoctorName(e.target.value)} placeholder="Nama Dokter" />
              </div>

              <div className="space-y-3">
                 <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Detail Pasien</label>
                 <div className="flex gap-2">
                    <input className="flex-1 bg-slate-950 border border-slate-700 rounded-xl px-4 py-2.5 text-sm text-white focus:border-tcm-primary outline-none" 
                           value={patientName} onChange={e => setPatientName(e.target.value)} placeholder="Nama Pasien" />
                    <input className="w-20 bg-slate-950 border border-slate-700 rounded-xl px-4 py-2.5 text-sm text-white focus:border-tcm-primary outline-none" 
                           value={age} onChange={e => setAge(e.target.value)} placeholder="Age" />
                 </div>
                 <input className="w-full bg-slate-950 border border-slate-700 rounded-xl px-4 py-2.5 text-sm text-white focus:border-tcm-primary outline-none" 
                        value={address} onChange={e => setAddress(e.target.value)} placeholder="Alamat Pasien" />
                 <input type="date" className="w-full bg-slate-950 border border-slate-700 rounded-xl px-4 py-2.5 text-sm text-white focus:border-tcm-primary outline-none" 
                        value={date} onChange={e => setDate(e.target.value)} />
              </div>

              <div className="space-y-3">
                 <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Resep / Instruksi Klinis</label>
                 <textarea 
                    className="w-full h-44 bg-slate-950 border border-slate-700 rounded-xl px-4 py-3 text-xs text-white font-mono leading-relaxed focus:border-tcm-primary outline-none resize-none"
                    value={notes}
                    onChange={e => setNotes(e.target.value)}
                 />
              </div>

              <div className="space-y-3">
                 <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Digital Signature</label>
                 <div className="flex items-center gap-2">
                    <label className="flex-1 cursor-pointer bg-slate-950 hover:bg-slate-900 border border-slate-700 border-dashed rounded-xl p-3 text-center transition-all group">
                        <span className="text-[10px] text-slate-500 group-hover:text-slate-300 flex items-center justify-center gap-2 font-bold uppercase tracking-widest">
                           <Upload className="w-4 h-4" /> Import PNG
                        </span>
                        <input type="file" accept="image/*" className="hidden" onChange={handleSignatureUpload} />
                    </label>
                    {signature && (
                        <button onClick={() => setSignature(null)} className="p-2.5 bg-rose-950/30 text-rose-500 rounded-xl border border-rose-900/50 hover:bg-rose-900 transition-colors">
                           <X className="w-4 h-4" />
                        </button>
                    )}
                 </div>
              </div>

              <div className="grid grid-cols-2 gap-2 mt-4">
                  <button 
                    onClick={generatePDF} 
                    disabled={isGenerating}
                    className="py-3 bg-indigo-600 hover:bg-indigo-500 text-white font-black rounded-xl shadow-lg flex items-center justify-center gap-2 text-xs uppercase tracking-widest transition-all disabled:opacity-50"
                  >
                    {isGenerating ? 'Wait...' : <><FileDown className="w-4 h-4" /> PDF</>}
                  </button>
                  <button 
                    onClick={generateTextFile}
                    className="py-3 bg-slate-700 hover:bg-slate-600 text-white font-black rounded-xl shadow-lg flex items-center justify-center gap-2 text-xs uppercase tracking-widest transition-all"
                  >
                    <Clipboard className="w-4 h-4" /> Text
                  </button>
              </div>
           </div>
        </div>

        {/* RIGHT: Live Preview */}
        <div className="flex-1 bg-slate-950 p-6 md:p-12 flex items-center justify-center overflow-auto scrollbar-hide">
