                     <p><span className="font-bold text-slate-400 uppercase tracking-tighter mr-2">Nama Pasien:</span> <span className="font-black">{patientName || '-'}</span></p>
                     <p><span className="font-bold text-slate-400 uppercase tracking-tighter mr-2">Umur:</span> <span className="font-black">{age} th</span></p>
                     <p><span className="font-bold text-slate-400 uppercase tracking-tighter mr-2">Alamat:</span> <span className="font-black">{address || '-'}</span></p>
                  </div>
                  <div className="text-right space-y-1.5">
                     <p><span className="font-bold text-slate-400 uppercase tracking-tighter mr-2">Tanggal:</span> <span className="font-black">{date}</span></p>
                     <p><span className="font-bold text-slate-400 uppercase tracking-tighter mr-2">No. Reg:</span> <span className="font-black">#TCM-{Date.now().toString().slice(-6)}</span></p>
                  </div>
               </div>

               {/* Body Content */}
               <div className="flex-1 font-mono text-xs whitespace-pre-wrap leading-loose text-slate-800">
                  <div className="flex items-start gap-3 mb-4">
                     <span className="text-4xl font-black font-serif italic text-slate-300 leading-none">R/</span>
                  </div>
                  <div className="pl-2">
                    {notes}
                  </div>
               </div>

               {/* Footer / Signature */}
               <div className="mt-12 flex flex-col items-end">
                  <p className="text-[10px] text-slate-500 mb-8 font-sans uppercase tracking-widest">Klinik {clinicName.split(' ')[1] || 'Pusat'}, {date}</p>
                  <div className="w-40 h-24 flex items-center justify-center relative mb-2">
                     {signature ? (
                        <img src={signature} alt="Signature" className="max-w-full max-h-full object-contain mix-blend-multiply" />
                     ) : (
                        <div className="w-full h-full border border-slate-100 border-dashed rounded flex items-center justify-center text-[9px] text-slate-300 uppercase font-sans tracking-widest">
                           Signature Required
                        </div>
                     )}
                  </div>
                  <p className="text-sm font-black border-t-2 border-slate-900 pt-2 min-w-[180px] text-center uppercase tracking-tighter">
                     {doctorName}
                  </p>
               </div>

               {/* Bottom Brand */}
               <div className="absolute bottom-6 left-0 right-0 text-center opacity-30">
                  <p className="text-[8px] text-slate-400 uppercase tracking-[0.6em] font-sans font-bold">
                     Powered by TCM WuXing Pro CDSS
                  </p>
               </div>
            </div>

        </div>
      </div>
    </div>
  );
};

