const PatientFormModal: React.FC<Props> = ({ isOpen, onClose, onSubmit }) => {
  const [storedPatients, setStoredPatients] = useState<SavedPatient[]>([]);
  const [showLookup, setShowLookup] = useState(false);
  const [lookupSearch, setLookupSearch] = useState('');

  const [formData, setFormData] = useState<PatientData>({
    patientName: '',
    age: '',
    sex: 'male',
    address: '',
    complaint: '',
    symptoms: '',
    selectedSymptoms: [],
    isAcuteMode: false,
    medicalHistory: '',
    biomedicalDiagnosis: '',
    icd10: '',
    medications: '',
    followUpDate: '',
    notes: '',
    tongue: {
      body_color: '',
      coating_color: '',
      coating_quality: '',
      special_features: []
    },
    pulse: {
      qualities: []
    }
  });

  useEffect(() => {
    if (isOpen) {
      setStoredPatients(db.patients.getAll());
    }
  }, [isOpen]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(formData);
    onClose();
  };

  const handleSelectExisting = (p: SavedPatient) => {
    setFormData({
      patientName: p.patientName,
      age: p.age,
      sex: p.sex as any,
      address: p.address || '',
      complaint: p.complaint,
      symptoms: p.symptoms,
      selectedSymptoms: p.selectedSymptoms || [],
      isAcuteMode: false,
      medicalHistory: p.medicalHistory || '',
      biomedicalDiagnosis: p.biomedicalDiagnosis || '',
      icd10: p.icd10 || '',
      medications: p.medications || '',
      followUpDate: p.followUpDate || '',
      notes: p.notes || '',
      tongue: {
        body_color: p.tongue.body_color || '',
        coating_color: p.tongue.coating_color || '',
        coating_quality: p.tongue.coating_quality || '',
        special_features: p.tongue.special_features || []
      },
      pulse: {
        qualities: p.pulse.qualities || []
      }
    });
    setShowLookup(false);
  };

  const toggleSymptom = (symptom: string) => {
    const current = formData.selectedSymptoms;
    const updated = current.includes(symptom)
      ? current.filter(s => s !== symptom)
      : [...current, symptom];
    setFormData({ ...formData, selectedSymptoms: updated });
  };

  const toggleTongueFeature = (feature: string) => {
    const current = formData.tongue.special_features;
    const updated = current.includes(feature)
      ? current.filter(f => f !== feature)
      : [...current, feature];
    setFormData({ ...formData, tongue: { ...formData.tongue, special_features: updated } });
  };

  const togglePulseQuality = (quality: string) => {
    const current = formData.pulse.qualities;
    const updated = current.includes(quality)
      ? current.filter(q => q !== quality)
      : [...current, quality];
    setFormData({ ...formData, pulse: { ...formData.pulse, qualities: updated } });
  };

  const filteredStored = storedPatients.filter(p => 
    p.patientName.toLowerCase().includes(lookupSearch.toLowerCase()) ||
    (p.biomedicalDiagnosis && p.biomedicalDiagnosis.toLowerCase().includes(lookupSearch.toLowerCase()))
  ).slice(0, 5);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-fade-in">
      <div className="bg-slate-800 border border-slate-700 w-full max-w-2xl rounded-2xl shadow-2xl max-h-[90vh] overflow-y-auto scrollbar-hide">
        <div className="flex items-center justify-between p-4 border-b border-slate-700 sticky top-0 bg-slate-800 z-20">
          <div className="flex items-center gap-2">
             <Activity className="w-5 h-5 text-tcm-primary" />
             <h2 className="text-xl font-bold text-tcm-primary">Patient Intake Form</h2>
          </div>
          <div className="flex items-center gap-2">
            <button 
                type="button"
                onClick={() => setShowLookup(!showLookup)}
                className="flex items-center gap-2 px-3 py-1.5 bg-slate-700 hover:bg-slate-600 text-slate-300 rounded-lg text-xs font-bold transition-all border border-slate-600"
            >
                <Search className="w-3.5 h-3.5" /> {showLookup ? 'Tutup Cari' : 'Cari Pasien'}
            </button>
            <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors">
                <X className="w-6 h-6" />
            </button>
          </div>
        </div>

        {showLookup && (
            <div className="p-4 bg-slate-900 border-b border-slate-700 animate-fade-in">
                <div className="relative mb-4">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                    <input 
                        type="text" 
                        placeholder="Ketik nama pasien yang sudah terdaftar..."
                        className="w-full bg-slate-800 border border-slate-700 rounded-xl py-2 pl-10 pr-4 text-sm text-white focus:border-tcm-primary outline-none"
                        value={lookupSearch}
                        onChange={(e) => setLookupSearch(e.target.value)}
                    />
                </div>
                <div className="space-y-2">
                    {filteredStored.map(p => (
                        <button 
                            key={p.id}
                            type="button"
                            onClick={() => handleSelectExisting(p)}
                            className="w-full text-left p-3 rounded-xl bg-slate-800 border border-slate-700 hover:border-tcm-primary flex items-center justify-between group transition-all"
                        >
                            <div className="flex items-center gap-3">
                                <div className="p-2 bg-slate-700 rounded-lg text-slate-400 group-hover:text-tcm-primary">
                                    <UserCheck className="w-4 h-4" />
                                </div>
                                <div>
                                    <span className="block text-sm font-bold text-slate-200">{p.patientName}</span>
                                    <span className="text-[10px] text-slate-500 uppercase">{p.age} th • {p.biomedicalDiagnosis || 'Umum'}</span>
                                </div>
                            </div>
                            <ChevronRight className="w-4 h-4 text-slate-600 group-hover:text-tcm-primary" />
                        </button>
                    ))}
                </div>
            </div>
        )}

        <form onSubmit={handleSubmit} className="p-6 space-y-8">
            {/* Identity Section */}
            <div className="space-y-4">
              <h3 className="text-xs font-bold text-indigo-400 uppercase tracking-widest border-b border-slate-700/50 pb-2">I. Identity</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                      <label className="block text-xs font-semibold text-slate-400 uppercase mb-1">Patient Name</label>
                      <div className="relative">
                        <User className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                        <input 
                            type="text" 
                            className="w-full bg-slate-900 border border-slate-700 rounded-lg pl-10 pr-3 py-2 text-slate-200 focus:border-tcm-primary outline-none transition-all"
                            value={formData.patientName}
                            onChange={e => setFormData({...formData, patientName: e.target.value})}
                            placeholder="Full Name"
                        />
                      </div>
                  </div>
                  <div className="grid grid-cols-2 gap-2">
                    <div>
                        <label className="block text-xs font-semibold text-slate-400 uppercase mb-1">Age</label>
                        <input 
                            type="number" 
                            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-200 focus:border-tcm-primary outline-none"
                            value={formData.age}
                            onChange={e => setFormData({...formData, age: e.target.value})}
                        />
                    </div>
                    <div>
                        <label className="block text-xs font-semibold text-slate-400 uppercase mb-1">Sex</label>
                        <select 
                            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-slate-200 focus:border-tcm-primary outline-none"
                            value={formData.sex}
                            onChange={e => setFormData({...formData, sex: e.target.value})}
                        >
                            <option value="male">Male</option>
                            <option value="female">Female</option>
                        </select>
                    </div>
                  </div>
              </div>
            </div>

            {/* Medical History Section */}
            <div className="space-y-4">
              <h3 className="text-xs font-bold text-amber-500 uppercase tracking-widest border-b border-slate-700/50 pb-2">II. Medical History & Previous Diagnoses</h3>
              <div className="grid grid-cols-1 gap-4">
                  <div>
                      <label className="block text-xs font-semibold text-slate-400 uppercase mb-1 flex items-center gap-2">
                        <History className="w-3 h-3"/> Past Medical History / Riwayat Penyakit Dahulu
                      </label>
                      <textarea 
                          className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2 text-sm text-slate-200 focus:border-tcm-primary outline-none h-20 transition-colors resize-none"
                          value={formData.medicalHistory}
                          onChange={e => setFormData({...formData, medicalHistory: e.target.value})}
                          placeholder="List previous illnesses, surgeries, or chronic conditions..."
                      />
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      <div>
                          <label className="block text-xs font-semibold text-slate-400 uppercase mb-1 flex items-center gap-2">
                            <Stethoscope className="w-3 h-3"/> Previous Diagnoses
                          </label>
                          <input 
                              type="text" 
                              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-sm text-slate-200 focus:border-tcm-primary outline-none"
                              value={formData.biomedicalDiagnosis}
                              onChange={e => setFormData({...formData, biomedicalDiagnosis: e.target.value})}
                              placeholder="Common biomedical diagnosis..."
                          />
                      </div>
                      <div>
                          <label className="block text-xs font-semibold text-slate-400 uppercase mb-1 flex items-center gap-2">
                            <ShieldAlert className="w-3 h-3"/> Allergies & Contraindications
                          </label>
                          <input 
                              type="text" 
                              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-sm text-slate-200 focus:border-tcm-primary outline-none"
                              value={formData.notes}
                              onChange={e => setFormData({...formData, notes: e.target.value})}
                              placeholder="Food, drug, or environment allergies..."
                          />
                      </div>
                  </div>
              </div>
            </div>

            {/* Symptoms Tracking Section */}
            <div className="space-y-4">
              <h3 className="text-xs font-bold text-tcm-primary uppercase tracking-widest border-b border-slate-700/50 pb-2">III. Clinical Manifestations (Symptom Tracking)</h3>

              <div className="space-y-4">
                {SYMPTOM_GROUPS.map((group) => (
                  <div key={group.category}>
                    <label className="block text-[10px] font-black text-slate-500 uppercase mb-2 tracking-widest flex items-center gap-2">
                       <Tag className="w-3 h-3 text-tcm-primary"/> {group.category}
                    </label>
                    <div className="flex flex-wrap gap-2 mb-3">
                       {group.items.map(s => (
                         <button
                          key={s}
                          type="button"
                          onClick={() => toggleSymptom(s)}
                          className={`px-3 py-1.5 rounded-xl text-[10px] font-bold border transition-all ${
                            formData.selectedSymptoms.includes(s)
                            ? 'bg-tcm-primary border-tcm-primary text-white shadow-lg shadow-emerald-900/40'
                            : 'bg-slate-900 border-slate-700 text-slate-500 hover:border-slate-500'
                          }`}
                         >
                           {s}
                         </button>
                       ))}
                    </div>
                  </div>
                ))}
              </div>

              <div className="pt-4">
                  <label className="block text-xs font-semibold text-slate-400 uppercase mb-1 flex items-center gap-2">
                    <Clipboard className="w-3 h-3"/> Detailed Observation / Chief Complaint
                  </label>
                  <textarea 
                      className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-3 text-sm text-slate-200 focus:border-tcm-primary outline-none h-24 transition-colors resize-none font-medium"
                      value={formData.symptoms}
                      onChange={e => setFormData({...formData, symptoms: e.target.value})}
                      placeholder="Add detailed specific symptoms or history here..."
                  />
                  <p className="text-[10px] text-slate-500 mt-2 italic flex items-center gap-1">
                    <Info className="w-3 h-3" /> Detailed symptoms help the AI build a more accurate Wu Xing pathological timeline.
                  </p>
              </div>
            </div>

            {/* Physical Examination Section (Tongue & Pulse) */}
            <div className="space-y-4">
              <h3 className="text-xs font-bold text-amber-400 uppercase tracking-widest border-b border-slate-700/50 pb-2">IV. Physical Examination (Tongue & Pulse)</h3>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {/* Tongue Sub-section */}
                <div className="bg-slate-950/30 p-5 rounded-2xl border border-slate-700/50">
                  <h4 className="text-[10px] font-black text-slate-400 mb-4 uppercase tracking-widest flex items-center gap-2">
                    <div className="w-2 h-2 rounded-full bg-tcm-primary"></div> Tongue Diagnosis
                  </h4>

                  <div className="space-y-4">
                    <div className="grid grid-cols-1 gap-3">
                      <div>
                        <label className="block text-[9px] font-bold text-slate-500 uppercase mb-1">Body Color</label>
                        <select 
                          className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-xs text-slate-200 outline-none focus:border-tcm-primary"
                          value={formData.tongue.body_color} 
                          onChange={e => setFormData({...formData, tongue: {...formData.tongue, body_color: e.target.value}})}
                        >
