import { Send, User, Bot, Menu, X, Baby, ClipboardList, Activity, MessageSquare, Stethoscope, BookOpen, Map, Zap, Compass, LogOut, Users, Shield, GraduationCap, Archive, Loader2 } from 'lucide-react';
