const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [activePanel, setActivePanel] = useState<'chat' | 'diagnosis' | 'theory' | 'stroke' | 'atlas' | 'wuxing' | 'ukom' | 'archive'>('chat');
  const [linkedSyndromeId, setLinkedSyndromeId] = useState<string | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: 'welcome', role: 'model', text: 'Selamat datang di TCM WuXing Pro. Silakan isi form pasien atau ceritakan keluhan Anda.', timestamp: new Date() }
  ]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false); 
  const [selectedLanguage, setSelectedLanguage] = useState<Language>(Language.INDONESIAN);
  const [isPregnant, setIsPregnant] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isVisualizerOpen, setIsVisualizerOpen] = useState(false);
  const [isUserMgmtOpen, setIsUserMgmtOpen] = useState(false);
  const [visualizerHighlight, setVisualizerHighlight] = useState<string | null>(null);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [cdssResults, setCdssResults] = useState<ScoredSyndrome[]>([]);
  const [lastPatientForm, setLastPatientForm] = useState<any>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  };

  useEffect(() => { 
    if (activePanel === 'chat') scrollToBottom(); 
  }, [messages, activePanel, isLoading]);

  const handleSendMessage = async (textOverride?: string, analysis?: ScoredSyndrome[]) => {
    const textToSend = textOverride || inputText;
    const imageToSend = textOverride ? undefined : (selectedImage || undefined);

    if ((!textToSend.trim() && !imageToSend) || isLoading) return;

    // Set loading SEGERA sebelum proses API dimulai
    setIsLoading(true);

    const userMessage: ChatMessage = { 
      id: Date.now().toString(), 
      role: 'user', 
      text: textToSend, 
      image: imageToSend, 
      timestamp: new Date() 
    };

    setMessages(prev => [...prev, userMessage]);
    setInputText('');
    setSelectedImage(null);

    try {
      const response = await sendMessageToGemini(textToSend, imageToSend, messages, selectedLanguage, isPregnant, analysis || cdssResults);
      const botMessage: ChatMessage = { 
        id: (Date.now() + 1).toString(), 
        role: 'model', 
        text: response.conversationalResponse, 
        timestamp: new Date(), 
        tcmResult: response.diagnosis 
      };
      setMessages(prev => [...prev, botMessage]);
    } catch (error) {
      setMessages(prev => [...prev, { 
        id: (Date.now() + 1).toString(), 
        role: 'model', 
        text: "Maaf, terjadi kesalahan koneksi. Silakan coba lagi.", 
        timestamp: new Date(), 
        isError: true 
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const handleFormSubmit = (data: any) => {
    setLastPatientForm(data);
    setIsAnalyzing(true);
    setActivePanel('diagnosis'); 

    setTimeout(() => {
        const results = analyzePatient({ symptoms: data.symptoms, tongue: data.tongue, pulse: data.pulse });
        setCdssResults(results);
        setIsAnalyzing(false);

        if (results.length > 0) {
            const topResult = results[0];
            const diagnosisToSave: TcmDiagnosisResult = {
                patternId: topResult.syndrome.id,
                confidence: topResult.score / 100,
                explanation: topResult.rationale.join('; '),
                recommendedPoints: topResult.points.map(p => ({ code: p.code, description: p.note || p.role })),
                affectedOrgans: topResult.syndrome.primary_organs,
                lifestyleAdvice: "CDSS Analysis Result.",
                herbal_recommendation: topResult.herbal_recommendation,
                wuxingElement: topResult.syndrome.wuxing_element,
                wuxingRelationships: topResult.wuxingRelationships,
                pulse: data.pulse
            };

            db.patients.add({
                id: Date.now().toString(),
                patientName: data.patientName || "Anonymous",
                age: data.age || "",
                sex: data.sex || "",
                address: data.address || "",
                complaint: data.complaint || "",
                symptoms: data.symptoms || "",
                selectedSymptoms: data.selectedSymptoms || [],
                tongue: data.tongue,
                pulse: data.pulse,
                diagnosis: diagnosisToSave,
                medicalHistory: data.medicalHistory || "",
                biomedicalDiagnosis: data.biomedicalDiagnosis || "",
                icd10: data.icd10 || "",
                medications: data.medications || "",
                notes: data.notes || "",
                followUpDate: data.followUpDate || "",
                timestamp: Date.now(),
            });
        }

        const formattedMessage = `
**DATA PASIEN BARU**
Nama: ${data.patientName || 'Anonymous'}
Keluhan: ${data.complaint}
Lidah: ${data.tongue.body_color} | Nadi: ${data.pulse.qualities.join(', ')}
Mohon berikan analisis Wu Xing yang mendalam.
        `.trim();
        handleSendMessage(formattedMessage, results);
    }, 400); // Dipercepat dari 800ms ke 400ms
  };

  if (!currentUser) return <LoginScreen onLoginSuccess={setCurrentUser} />;

  return (
    <div className="flex h-screen bg-slate-950 text-slate-100 overflow-hidden font-sans">
      <PatientFormModal isOpen={isFormOpen} onClose={() => setIsFormOpen(false)} onSubmit={handleFormSubmit} />
      <WuXingVisualizerModal isOpen={isVisualizerOpen} onClose={() => setIsVisualizerOpen(false)} initialHighlight={visualizerHighlight} />

      <div className={`fixed inset-y-0 left-0 z-40 w-64 bg-slate-900 border-r border-slate-800 transform transition-transform md:relative md:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} flex flex-col`}>
        <div className="p-5">
           <h1 className="text-xl font-black bg-gradient-to-r from-tcm-primary to-tcm-accent bg-clip-text text-transparent flex items-center gap-2">
              <Activity className="w-6 h-6 text-tcm-primary" /> TCM WuXing
           </h1>
        </div>
        <div className="flex-1 px-3 space-y-2 overflow-y-auto">
           <button onClick={() => setActivePanel('chat')} className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm ${activePanel === 'chat' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/20' : 'text-slate-400 hover:bg-slate-800'}`}>
              <MessageSquare className="w-4 h-4" /> Chat / Diagnosa
           </button>
           <button onClick={() => setActivePanel('diagnosis')} className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm ${activePanel === 'diagnosis' ? 'bg-tcm-primary text-white shadow-lg shadow-emerald-900/40' : 'text-slate-400 hover:bg-slate-800'}`}>
              <Stethoscope className="w-4 h-4" /> CDSS Auto-Rx
           </button>
           <button onClick={() => setActivePanel('archive')} className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm ${activePanel === 'archive' ? 'bg-emerald-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>
              <Archive className="w-4 h-4" /> Arsip Pasien
           </button>
           <button onClick={() => setActivePanel('wuxing')} className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm ${activePanel === 'wuxing' ? 'bg-pink-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>
              <Compass className="w-4 h-4" /> Wu Xing Master
           </button>
           <button onClick={() => setActivePanel('ukom')} className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm ${activePanel === 'ukom' ? 'bg-sky-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>
              <GraduationCap className="w-4 h-4" /> Latihan UKOM
           </button>
        </div>
        <div className="p-3 pb-8 border-t border-slate-800 space-y-2">
           <button onClick={() => setIsSidebarOpen(false) || setIsFormOpen(true)} className="w-full flex items-center justify-center gap-2 py-3 bg-slate-800 text-tcm-primary rounded-xl font-bold text-sm hover:border-tcm-primary border border-slate-700 transition-all">
              <ClipboardList className="w-4 h-4" /> New Patient
           </button>
        </div>
      </div>

      <div className="flex-1 flex flex-col h-full relative overflow-hidden bg-slate-950">
        {activePanel === 'chat' && (
           <div className="flex-1 flex flex-col min-h-0">
              <div className="flex-1 overflow-y-auto p-4 space-y-4 scrollbar-hide">
                {messages.map((msg) => (
                  <div key={msg.id} className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-fade-in`}>
                    <div className={`flex max-w-[90%] md:max-w-[80%] gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                      <div className="flex flex-col gap-1 w-full min-w-0">
                        <div className={`p-4 rounded-2xl text-sm whitespace-pre-wrap shadow-md ${msg.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-200 border border-slate-700'}`}>
                          {msg.text}
                        </div>
                        {msg.tcmResult && (
                          <DiagnosisCard 
                            diagnosis={msg.tcmResult} 
                            isPregnant={isPregnant} 
                            onShowVisualizer={(el) => { setVisualizerHighlight(el || null); setIsVisualizerOpen(true); }}
                            patientContext={lastPatientForm}
                          />
                        )}
                      </div>
                    </div>
                  </div>
                ))}

                {isLoading && (
                  <div className="flex w-full justify-start animate-fade-in">
                    <div className="bg-slate-800 border border-slate-700 p-4 rounded-2xl text-slate-200 shadow-md flex items-center gap-2 min-w-[80px]">
                      <span className="dot-typing"></span>
                      <span className="dot-typing"></span>
                      <span className="dot-typing"></span>
                    </div>
                  </div>
                )}

                <div ref={messagesEndRef} />
              </div>
              <div className="p-4 bg-slate-900 border-t border-slate-800 shrink-0">
                <div className="max-w-4xl mx-auto flex items-end gap-2">
                  <textarea 
                    value={inputText} 
                    onChange={(e) => setInputText(e.target.value)} 
                    onKeyDown={handleKeyDown}
                    placeholder="Tulis keluhan..." 
                    className="flex-1 bg-slate-950 border border-slate-800 rounded-2xl text-white text-sm p-3 focus:border-tcm-primary outline-none resize-none transition-all duration-300 focus:ring-1 focus:ring-tcm-primary/30" 
                    rows={1} 
                  />
                  <button 
                    onClick={() => handleSendMessage()} 
                    disabled={isLoading}
                    className={`p-3 rounded-full text-white transition-all duration-300 transform active:scale-90 ${isLoading ? 'bg-slate-700 cursor-not-allowed' : 'bg-tcm-primary hover:bg-emerald-400 hover:shadow-lg hover:shadow-emerald-900/40'}`}
                  >
                    {isLoading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Send className="w-5 h-5" />}
                  </button>
                </div>
              </div>
           </div>
        )}

        {activePanel === 'diagnosis' && (
           <div className="flex-1 min-h-0 bg-slate-950">
             <ScoringAndPointsHub analysis={cdssResults} onAnalyzeRequest={() => setIsFormOpen(true)} patientContext={lastPatientForm} />
           </div>
        )}
        {activePanel === 'archive' && <div className="flex-1 min-h-0 bg-slate-950"><PatientArchivePanel onLoadPatient={(p) => { setActivePanel('diagnosis'); }} /></div>}
        {activePanel === 'ukom' && <div className="flex-1 min-h-0 bg-slate-950"><UkomPracticePanel /></div>}
        {activePanel === 'wuxing' && <div className="flex-1 min-h-0 bg-slate-950"><WuXingMasterPanel onSelectSyndrome={(id) => { setActivePanel('diagnosis'); }} /></div>}
      </div>
    </div>
  );
};

