      symptoms: patientContext?.symptoms || "",
      selectedSymptoms: patientContext?.selectedSymptoms || [],
      tongue: patientContext?.tongue || {},
      pulse: patientContext?.pulse || { qualities: [] },
      diagnosis: diagnosis,
      medicalHistory: patientContext?.medicalHistory || "",
      biomedicalDiagnosis: patientContext?.biomedicalDiagnosis || "",
      notes: patientContext?.notes || "",
      timestamp: Date.now()
    });
    setIsSaved(true);
  };

  const handleExportPDF = async () => {
    if (!cardRef.current || isExporting) return;
    setIsExporting(true);

    try {
      const canvas = await html2canvas(cardRef.current, { 
        scale: 2, 
        useCORS: true, 
        backgroundColor: '#020617', // Slate-950
        logging: false,
        allowTaint: true,
        height: cardRef.current.scrollHeight, 
        windowHeight: cardRef.current.scrollHeight,
        onclone: (clonedDoc) => {
          const el = clonedDoc.querySelector('[data-pdf-content="true"]') as HTMLElement;
          if (el) {
            el.style.height = 'auto';
            el.style.maxHeight = 'none';
            el.style.overflow = 'visible';
          }
        }
      });

      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');

      const pageWidth = pdf.internal.pageSize.getWidth();
      const pageHeight = pdf.internal.pageSize.getHeight();
      const margin = 10;
      const contentWidth = pageWidth - (margin * 2);

      const imgProps = pdf.getImageProperties(imgData);
      const imgHeight = (imgProps.height * contentWidth) / imgProps.width;

      let heightLeft = imgHeight;
      let position = 0;

      // First Page
      pdf.setFillColor(2, 6, 23); 
      pdf.rect(0, 0, pageWidth, pageHeight, 'F');
      pdf.addImage(imgData, 'PNG', margin, margin, contentWidth, imgHeight);
      heightLeft -= (pageHeight - margin * 2);

      // Multi-page logic
      while (heightLeft > 0) {
        position = heightLeft - imgHeight + margin; 
        pdf.addPage();
        pdf.setFillColor(2, 6, 23);
        pdf.rect(0, 0, pageWidth, pageHeight, 'F');
        pdf.addImage(imgData, 'PNG', margin, position, contentWidth, imgHeight);
        heightLeft -= pageHeight;
      }

      pdf.save(`TCM_Report_${(patternName || 'Diagnosis').replace(/\s+/g, '_')}.pdf`);
    } catch (error) {
      console.error("PDF Export Error:", error);
      alert("Gagal mengekspor PDF.");
    } finally {
      setIsExporting(false);
    }
  };

  const elementColorClass = (() => {
    const el = (diagnosis.wuxingElement || "").toLowerCase();
    if (el.includes('wood')) return 'border-emerald-500 shadow-emerald-900/20';
    if (el.includes('fire')) return 'border-rose-500 shadow-rose-900/20';
    if (el.includes('earth')) return 'border-amber-500 shadow-amber-900/20';
    if (el.includes('metal')) return 'border-slate-300 shadow-slate-500/20';
    if (el.includes('water')) return 'border-blue-500 shadow-blue-900/20';
    return 'border-slate-800';
  })();

  return (
