              >
                  <Save className="w-4 h-4" /> <span className="text-xs font-bold uppercase">{isSaved ? 'Saved' : 'Save'}</span>
              </button>
              <button onClick={() => setShowNoteModal(true)} className="px-4 py-2 bg-slate-800 hover:bg-slate-700 text-white rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 border border-slate-700">
                  <FileText className="w-4 h-4" /> Rx Note
              </button>
              <button 
                onClick={handleExportPDF} 
                disabled={isExporting}
                className="px-4 py-2 bg-tcm-primary hover:bg-emerald-400 text-white rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 shadow-lg disabled:opacity-50"
              >
                {isExporting ? <Loader2 className="w-4 h-4 animate-spin" /> : <><FileDown className="w-4 h-4" /> Export Report</>}
              </button>
          </div>
        </div>

        {/* Clinical Background Section - New */}
        {(patientContext?.medicalHistory || patientContext?.biomedicalDiagnosis) && (
          <div className="mb-8 relative z-10 grid grid-cols-1 md:grid-cols-2 gap-4">
             {patientContext.biomedicalDiagnosis && (
                <div className="bg-indigo-900/20 border border-indigo-500/30 p-4 rounded-2xl">
                   <div className="flex items-center gap-2 text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-2">
                      <Stethoscope className="w-3 h-3" /> Biomedical Diagnosis
                   </div>
                   <p className="text-sm font-bold text-slate-200">{patientContext.biomedicalDiagnosis}</p>
                </div>
             )}
             {patientContext.medicalHistory && (
                <div className="bg-slate-900 border border-slate-800 p-4 rounded-2xl">
