                   <p className="text-xs text-slate-400 italic line-clamp-2">"{patientContext.medicalHistory}"</p>
                </div>
             )}
          </div>
        )}

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8 relative z-10">
           <div className="bg-slate-900/40 border border-slate-800/50 p-6 rounded-3xl flex flex-col h-[450px]">
              <div className="flex items-center gap-2 mb-4 text-indigo-400 text-[10px] font-black uppercase tracking-[0.3em]">
                 <GitMerge className="w-4 h-4" /> Pathological Visualizer
              </div>
              <div className="flex-1 min-h-0">
                 <WuXingInteractiveDiagram 
                    initialHighlight={diagnosis.wuxingElement} 
                    highlightedRelationships={diagnosis.wuxingRelationships}
                    compact={true}
                    embedded={true}
                 />
              </div>
           </div>

           <div className="flex flex-col gap-6">
              <div className="grid grid-cols-2 gap-4">
                 <div className="bg-slate-900 border border-slate-800 p-5 rounded-3xl">
                    <div className="flex items-center gap-2 text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3">
                       <Target className="w-4 h-4 text-emerald-500" /> Organs
                    </div>
                    <div className="flex flex-wrap gap-1.5">
                       {(displayOrgans || []).map(org => <span key={org} className="bg-slate-950 px-3 py-1 rounded-xl border border-slate-800 text-xs font-bold text-slate-200">{org}</span>)}
                    </div>
                 </div>
                 <div className="bg-slate-900 border border-slate-800 p-5 rounded-3xl">
