                                 <span className="text-tcm-primary font-bold block mb-1 uppercase text-[10px] print:text-black">Assistant (Chen)</span>
                                 <div className="text-slate-300 print:text-black">
                                     {renderHerbList(selectedSyndrome.herbal_recommendation?.assistants)}
                                 </div>
                             </div>
                        </div>
                    </div>
                </div>

            </div>

            {/* Footer / Print Button */}
            <div className="flex-shrink-0 mt-4 text-xs text-slate-500 border-t border-slate-800 pt-4 print:border-t print:border-gray-300 print:pt-4">
                 Generated by TCM WuXing Pro Auto-Rx Engine v{TCM_DB.metadata.version}
            </div>

            {/* Bottom Actions Floating Bar */}
            <div className="absolute bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-slate-950 via-slate-950 to-transparent flex justify-end gap-3 print:hidden">
               <button 
                  onClick={handleSnapshot}
                  className="px-4 py-2 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-lg text-sm font-semibold border border-slate-700 transition-colors flex items-center gap-2"
                  title="Simpan tampilan layar sebagai PDF"
               >
                  <Camera className="w-4 h-4" /> Snapshot PDF
               </button>
               <button 
                  onClick={() => setShowNoteModal(true)}
                  className="px-5 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg text-sm font-bold shadow-lg shadow-indigo-900/20 flex items-center gap-2 transition-colors"
                  title="Buat Nota / Resep Resmi"
               >
                  <FileText className="w-4 h-4" /> Nota / Resep
               </button>
            </div>
          </>
        ) : (
          <div className="flex items-center justify-center h-full text-slate-500 print:hidden">
             <div className="text-center">
               <ArrowRight className="w-8 h-8 mx-auto mb-2 opacity-30" />
               <p>Pilih hasil diagnosis dari panel kiri untuk melihat detail.</p>
               <button onClick={onAnalyzeRequest} className="mt-4 text-tcm-primary hover:underline text-sm font-semibold">
                    Atau mulai analisis baru
               </button>
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

