import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { Language, ScoredSyndrome } from '../types';

const getSystemInstruction = (language: Language, isPregnant: boolean, cdssAnalysis?: ScoredSyndrome[]) => {
  let cdssText = "";
  if (cdssAnalysis && cdssAnalysis.length > 0) {
    const primary = cdssAnalysis[0];
    cdssText = `
**REFERENSI CDSS (Maciocia DB):**
- Pola: ${primary.syndrome.name_id} (${primary.syndrome.name_en})
- Elemen: ${primary.syndrome.wuxing_element}
- Poin Utama: ${primary.syndrome.acupuncture_points?.join(', ')}
    `;
  }

  return `
Anda adalah Pakar Senior TCM yang mengadopsi 100% teori Giovanni Maciocia ("The Foundations of Chinese Medicine").

**KEWAJIBAN KERAS:**
1. **Nama Pinyin:** Gunakan nama Pinyin asli Maciocia untuk field 'patternId'. JANGAN hanya menggunakan bahasa Inggris.
2. **Acu-Points:** Berikan resep titik akupunktur lengkap dengan DESKRIPSI fungsinya sesuai literatur Maciocia.
3. **Analisis Wu Xing:** Jelaskan dinamika elemen secara detail menggunakan siklus Sheng, Ke, Cheng, dan Wu.
4. **Bahasa:** Gunakan ${language}.
5. **Format:** Anda HARUS merespon dalam format JSON yang valid sesuai schema.

${cdssText}
`;
};

const diagnosisSchema = {
  type: Type.OBJECT,
  properties: {
    conversationalResponse: { type: Type.STRING },
    diagnosis: {
      type: Type.OBJECT,
      properties: {
        patternId: { type: Type.STRING },
        confidence: { type: Type.NUMBER },
        explanation: { type: Type.STRING },
        recommendedPoints: { 
          type: Type.ARRAY, 
          items: { 
            type: Type.OBJECT,
            properties: {
              code: { type: Type.STRING },
              description: { type: Type.STRING }
            },
            required: ["code", "description"]
          } 
        },
        affectedOrgans: { type: Type.ARRAY, items: { type: Type.STRING } },
        lifestyleAdvice: { type: Type.STRING },
        wuxingElement: { type: Type.STRING },
        wuxingRelationships: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING },
              targetElement: { type: Type.STRING },
              description: { type: Type.STRING }
            },
            required: ["type", "targetElement", "description"]
          }
        },
        herbal_recommendation: {
          type: Type.OBJECT,
          properties: {
            formula_name: { type: Type.STRING },
            chief: { type: Type.ARRAY, items: { type: Type.STRING } },
            assistants: { type: Type.ARRAY, items: { type: Type.STRING } },
            avoid: { type: Type.ARRAY, items: { type: Type.STRING } }
          }
        }
      },
      required: ["patternId", "explanation", "recommendedPoints", "wuxingRelationships", "wuxingElement"]
    }
  },
  required: ["conversationalResponse", "diagnosis"]
};

export const sendMessageToGeminiStream = async (
  message: string,
  image: string | undefined,
  history: any[],
  language: Language,
  isPregnant: boolean,
  cdssAnalysis?: ScoredSyndrome[],
  onChunk?: (text: string) => void
) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const parts: any[] = [{ text: message }];
    if (image) {
      const [mimeTypePrefix, base64Data] = image.split(';base64,');
      parts.push({ inlineData: { mimeType: mimeTypePrefix.split(':')[1], data: base64Data } });
    }

    const responseStream = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history.slice(-6).map(h => ({ role: h.role === 'user' ? 'user' : 'model', parts: [{ text: h.text }] })),
        { role: 'user', parts }
      ],
      config: {
        systemInstruction: getSystemInstruction(language, isPregnant, cdssAnalysis),
        responseMimeType: "application/json",
        responseSchema: diagnosisSchema,
        thinkingConfig: { thinkingBudget: 0 } // MATIKAN THINKING UNTUK KECEPATAN MAKSIMAL
      }
    });

    let fullText = "";
    for await (const chunk of responseStream) {
      const partText = chunk.text;
      if (partText) {
        fullText += partText;
        // Kita tidak bisa parsing partial JSON dengan mudah, 
        // tapi kita bisa memberikan sinyal progress
        if (onChunk) onChunk(fullText);
      }
    }

    return JSON.parse(fullText || "{}");
  } catch (error) {
    console.error("Gemini Streaming Error:", error);
    throw error;
  }
};

