  AlertTriangle, Activity, Stethoscope, GitMerge, MapPin, 
  BrainCircuit, Zap, Target, Layers, Save, FileText, 
  FileDown, Leaf, Map, ChevronRight, Info, Search, AlertCircle, Loader2, History, ClipboardCheck
} from 'lucide-react';
import DoctorNoteModal from './DoctorNoteModal';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';
import { WuXingInteractiveDiagram } from './WuXingInteractiveDiagram';

interface Props {
  diagnosis?: TcmDiagnosisResult | null;
  isPregnant: boolean;
  onShowVisualizer: (element?: string) => void;
  patientContext?: any;
}

const DiagnosisCard: React.FC<Props> = ({ diagnosis, isPregnant, onShowVisualizer, patientContext }) => {
  const [showNoteModal, setShowNoteModal] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const [isExporting, setIsExporting] = useState(false);
  const [syndromeSearch, setSyndromeSearch] = useState('');
  const cardRef = useRef<HTMLDivElement>(null);

  // Subtle Loading state if diagnosis is null or undefined
  if (!diagnosis) {
    return (
      <div className="bg-slate-900 border border-slate-800 rounded-3xl p-8 my-6 flex flex-col items-center justify-center gap-4 animate-pulse-soft shadow-xl border-dashed">
         <div className="w-12 h-12 rounded-2xl bg-slate-950 flex items-center justify-center border border-slate-800">
            <Loader2 className="w-6 h-6 text-tcm-primary animate-spin" />
         </div>
         <div className="text-center">
            <p className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-1">Building Clinical Profile</p>
            <p className="text-[10px] text-slate-600 font-bold uppercase">Synthesizing Wu Xing Dynamics...</p>
         </div>
      </div>
    );
  }

  const allSyndromes = useMemo(() => [
    ...TCM_DB.syndromes.FILLED_FROM_PDF,
    ...TCM_DB.syndromes.TODO_FROM_PDF
  ], []);

  const patternName = diagnosis.patternId; 
  const displayOrgans = diagnosis.affectedOrgans || [];

  const filteredSyndromes = useMemo(() => {
    const query = syndromeSearch.trim().toLowerCase();
    if (!query) {
      return allSyndromes.filter(s => 
        (s.wuxing_element || "").toLowerCase() === (diagnosis.wuxingElement || "").toLowerCase()
      ).slice(0, 5);
    }
    return allSyndromes.filter(s => 
      (s.name_id || "").toLowerCase().includes(query) || 
      (s.name_en || "").toLowerCase().includes(query) ||
      (s.id || "").toLowerCase().includes(query)
    ).slice(0, 5);
  }, [syndromeSearch, allSyndromes, diagnosis]);

  const handleSaveToArchive = () => {
    let patientName = patientContext?.patientName || prompt("Masukkan Nama Pasien:") || "Anonim";
    db.patients.add({
      id: Date.now().toString(),
      patientName: patientName,
      age: patientContext?.age || "?",
      sex: patientContext?.sex || "?",
      address: patientContext?.address || "",
      complaint: patientContext?.complaint || "Chat Diagnosis",
      symptoms: patientContext?.symptoms || "",
      selectedSymptoms: patientContext?.selectedSymptoms || [],
      tongue: patientContext?.tongue || {},
      pulse: patientContext?.pulse || { qualities: [] },
      diagnosis: diagnosis,
      medicalHistory: patientContext?.medicalHistory || "",
      biomedicalDiagnosis: patientContext?.biomedicalDiagnosis || "",
      notes: patientContext?.notes || "",
      timestamp: Date.now()
    });
    setIsSaved(true);
  };

  const handleExportPDF = async () => {
    if (!cardRef.current || isExporting) return;
    setIsExporting(true);

    try {
      const canvas = await html2canvas(cardRef.current, { 
        scale: 2, 
        useCORS: true, 
        backgroundColor: '#020617', // Slate-950
        logging: false,
        allowTaint: true,
        height: cardRef.current.scrollHeight, 
        windowHeight: cardRef.current.scrollHeight,
        onclone: (clonedDoc) => {
          const el = clonedDoc.querySelector('[data-pdf-content="true"]') as HTMLElement;
          if (el) {
            el.style.height = 'auto';
            el.style.maxHeight = 'none';
            el.style.overflow = 'visible';
          }
        }
      });

      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');

      const pageWidth = pdf.internal.pageSize.getWidth();
      const pageHeight = pdf.internal.pageSize.getHeight();
      const margin = 10;
      const contentWidth = pageWidth - (margin * 2);

      const imgProps = pdf.getImageProperties(imgData);
      const imgHeight = (imgProps.height * contentWidth) / imgProps.width;

      let heightLeft = imgHeight;
      let position = 0;

      // First Page
      pdf.setFillColor(2, 6, 23); 
      pdf.rect(0, 0, pageWidth, pageHeight, 'F');
      pdf.addImage(imgData, 'PNG', margin, margin, contentWidth, imgHeight);
      heightLeft -= (pageHeight - margin * 2);

      // Multi-page logic
      while (heightLeft > 0) {
        position = heightLeft - imgHeight + margin; 
        pdf.addPage();
        pdf.setFillColor(2, 6, 23);
        pdf.rect(0, 0, pageWidth, pageHeight, 'F');
        pdf.addImage(imgData, 'PNG', margin, position, contentWidth, imgHeight);
        heightLeft -= pageHeight;
      }

      pdf.save(`TCM_Report_${(patternName || 'Diagnosis').replace(/\s+/g, '_')}.pdf`);
    } catch (error) {
      console.error("PDF Export Error:", error);
      alert("Gagal mengekspor PDF.");
    } finally {
      setIsExporting(false);
    }
  };

  const elementColorClass = (() => {
    const el = (diagnosis.wuxingElement || "").toLowerCase();
    if (el.includes('wood')) return 'border-emerald-500 shadow-emerald-900/20';
    if (el.includes('fire')) return 'border-rose-500 shadow-rose-900/20';
    if (el.includes('earth')) return 'border-amber-500 shadow-amber-900/20';
    if (el.includes('metal')) return 'border-slate-300 shadow-slate-500/20';
    if (el.includes('water')) return 'border-blue-500 shadow-blue-900/20';
    return 'border-slate-800';
  })();

  return (
    <>
      <DoctorNoteModal isOpen={showNoteModal} onClose={() => setShowNoteModal(false)} diagnosis={diagnosis} initialPatientData={{ name: patientContext?.patientName, age: patientContext?.age, address: patientContext?.address }} />

      <div 
        ref={cardRef} 
        data-pdf-content="true"
        className={`bg-slate-950 border-t-4 ${elementColorClass} rounded-3xl p-6 my-6 shadow-2xl animate-fade-in relative overflow-hidden transition-all h-auto`}
      >
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8 relative z-10">
          <div className="flex items-center gap-5">
            <div className="w-16 h-16 rounded-2xl bg-slate-900 flex items-center justify-center border border-slate-800 shadow-inner">
               <BrainCircuit className="w-10 h-10 text-tcm-primary" />
            </div>
            <div>
              <div className="flex items-center gap-2 mb-1">
                 <h3 className="text-2xl font-black text-white tracking-tighter uppercase">{patternName || 'Unknown Pattern'}</h3>
                 <span className="text-[10px] bg-emerald-500/20 text-emerald-400 px-2 py-0.5 rounded-full font-black border border-emerald-500/30">
                    {Math.round((diagnosis.confidence || 0) * 100)}% CONFIDENCE
                 </span>
              </div>
              <div className="text-xs text-slate-500 font-bold uppercase tracking-widest">Maciocia Syndrome Classification</div>
            </div>
          </div>

          <div className="flex flex-wrap items-center gap-2 print:hidden">
              <button 
                onClick={handleSaveToArchive} 
                disabled={isSaved} 
                className={`flex items-center gap-2 px-4 py-2 rounded-xl border transition-all ${isSaved ? 'bg-emerald-950 text-emerald-400 border-emerald-800' : 'bg-slate-900 text-slate-400 border-slate-800 hover:text-white'}`}
              >
                  <Save className="w-4 h-4" /> <span className="text-xs font-bold uppercase">{isSaved ? 'Saved' : 'Save'}</span>
              </button>
              <button onClick={() => setShowNoteModal(true)} className="px-4 py-2 bg-slate-800 hover:bg-slate-700 text-white rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 border border-slate-700">
                  <FileText className="w-4 h-4" /> Rx Note
              </button>
              <button 
                onClick={handleExportPDF} 
                disabled={isExporting}
                className="px-4 py-2 bg-tcm-primary hover:bg-emerald-400 text-white rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 shadow-lg disabled:opacity-50"
              >
                {isExporting ? <Loader2 className="w-4 h-4 animate-spin" /> : <><FileDown className="w-4 h-4" /> Export Report</>}
              </button>
          </div>
        </div>

        {/* Clinical Background Section - New */}
        {(patientContext?.medicalHistory || patientContext?.biomedicalDiagnosis) && (
          <div className="mb-8 relative z-10 grid grid-cols-1 md:grid-cols-2 gap-4">
             {patientContext.biomedicalDiagnosis && (
                <div className="bg-indigo-900/20 border border-indigo-500/30 p-4 rounded-2xl">
                   <div className="flex items-center gap-2 text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-2">
                      <Stethoscope className="w-3 h-3" /> Biomedical Diagnosis
                   </div>
                   <p className="text-sm font-bold text-slate-200">{patientContext.biomedicalDiagnosis}</p>
                </div>
             )}
             {patientContext.medicalHistory && (
                <div className="bg-slate-900 border border-slate-800 p-4 rounded-2xl">
                   <div className="flex items-center gap-2 text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2">
                      <History className="w-3 h-3" /> Medical History
                   </div>
                   <p className="text-xs text-slate-400 italic line-clamp-2">"{patientContext.medicalHistory}"</p>
                </div>
             )}
          </div>
        )}

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8 relative z-10">
           <div className="bg-slate-900/40 border border-slate-800/50 p-6 rounded-3xl flex flex-col h-[450px]">
              <div className="flex items-center gap-2 mb-4 text-indigo-400 text-[10px] font-black uppercase tracking-[0.3em]">
                 <GitMerge className="w-4 h-4" /> Pathological Visualizer
              </div>
              <div className="flex-1 min-h-0">
                 <WuXingInteractiveDiagram 
                    initialHighlight={diagnosis.wuxingElement} 
                    highlightedRelationships={diagnosis.wuxingRelationships}
                    compact={true}
                    embedded={true}
                 />
              </div>
           </div>

           <div className="flex flex-col gap-6">
              <div className="grid grid-cols-2 gap-4">
                 <div className="bg-slate-900 border border-slate-800 p-5 rounded-3xl">
                    <div className="flex items-center gap-2 text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3">
                       <Target className="w-4 h-4 text-emerald-500" /> Organs
                    </div>
                    <div className="flex flex-wrap gap-1.5">
                       {(displayOrgans || []).map(org => <span key={org} className="bg-slate-950 px-3 py-1 rounded-xl border border-slate-800 text-xs font-bold text-slate-200">{org}</span>)}
                    </div>
                 </div>
                 <div className="bg-slate-900 border border-slate-800 p-5 rounded-3xl">
                    <div className="flex items-center gap-2 text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3">
                       <Layers className="w-4 h-4 text-tcm-primary" /> Element
                    </div>
                    <span className="text-lg font-black text-tcm-primary uppercase tracking-tighter">{diagnosis.wuxingElement || 'General'}</span>
                 </div>
              </div>

              <div className="bg-slate-900/60 border border-slate-800 p-5 rounded-3xl flex-1 print:hidden">
                 <div className="flex items-center gap-2 mb-4 text-[10px] font-black text-slate-500 uppercase tracking-widest">
                    <Search className="w-4 h-4" /> Related Patterns
                 </div>
                 <div className="space-y-2 max-h-[200px] overflow-y-auto scrollbar-hide">
                    {filteredSyndromes.map(s => (
                       <div key={s.id} className="p-3 bg-slate-950 border border-slate-800 rounded-xl flex items-center justify-between group">
                          <div>
                             <span className="text-xs font-bold text-slate-200">{s.name_id}</span>
                             <span className="block text-[9px] text-slate-600 uppercase">{s.wuxing_element}</span>
                          </div>
                       </div>
                    ))}
                 </div>
              </div>
           </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8 relative z-10">
           <div className="bg-slate-900 border border-slate-800 p-6 rounded-3xl shadow-inner">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4 block flex items-center gap-2">
                 <ClipboardCheck className="w-4 h-4" /> Clinical Synthesis
              </span>
              <p className="text-slate-300 leading-relaxed text-sm italic border-l-2 border-tcm-primary pl-4">"{diagnosis.explanation || 'No explanation available.'}"</p>
           </div>

           <div className="bg-slate-900 border border-slate-800 p-6 rounded-3xl">
              <h4 className="text-[10px] font-black text-tcm-primary uppercase tracking-[0.3em] mb-4 flex items-center gap-2">
                  <MapPin className="w-4 h-4"/> Acupuncture Points
              </h4>
              <div className="space-y-3">
                {(diagnosis.recommendedPoints || []).map((point, idx) => (
                    <div key={idx} className="flex items-start gap-3 p-3 bg-slate-950 rounded-2xl border border-slate-800">
                       <div className="px-2 py-1 bg-emerald-500/10 text-emerald-400 rounded-lg border border-emerald-500/20 text-[10px] font-black">
                          {point.code}
                       </div>
                       <p className="text-[11px] text-slate-400 leading-tight">
                          {point.description}
                       </p>
                    </div>
                ))}
              </div>
           </div>
        </div>

        {diagnosis.herbal_recommendation && (
          <div className="bg-emerald-950/20 border border-emerald-500/30 p-8 rounded-[2rem] relative z-10">
             <div className="flex items-center gap-4 mb-8">
                <div className="w-12 h-12 rounded-2xl bg-emerald-500/10 flex items-center justify-center border border-emerald-500/20">
                  <Leaf className="w-6 h-6 text-emerald-400" />
                </div>
                <div>
                  <h4 className="text-[10px] font-black text-emerald-400 uppercase tracking-[0.4em] mb-1">Herbal Strategy</h4>
                  <p className="text-2xl font-black text-white uppercase tracking-tighter">
                    {diagnosis.herbal_recommendation.formula_name || "Custom Prep"}
                  </p>
                </div>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="bg-slate-950/60 p-6 rounded-3xl border border-slate-800">
                   <span className="text-[10px] font-black text-emerald-500 uppercase tracking-[0.2em] mb-4 block">Chief Herbs</span>
                   <div className="flex flex-wrap gap-2">
                      {(diagnosis.herbal_recommendation.chief || []).map((herb, i) => (
                        <span key={i} className="px-3 py-1.5 bg-slate-900 text-xs rounded-xl text-slate-300 border border-slate-800 font-bold">{herb}</span>
                      ))}
                   </div>
                </div>

                {diagnosis.herbal_recommendation.avoid && (
                   <div className="bg-rose-950/20 p-6 rounded-3xl border border-rose-500/30">
                      <span className="text-[10px] font-black text-rose-400 uppercase tracking-[0.2em] mb-4 block flex items-center gap-2">
                         <AlertCircle className="w-3 h-3" /> Contraindications
                      </span>
                      <ul className="text-xs text-rose-100 list-disc list-inside space-y-1">
                         {(diagnosis.herbal_recommendation.avoid || []).map((a, i) => <li key={i}>{a}</li>)}
                      </ul>
                   </div>
                )}
             </div>
          </div>
        )}
      </div>
    </>
  );
};

export default DiagnosisCard;

// Fix: Map points to objects with code and description to satisfy TcmDiagnosisResult type definition.
import React, { useState, useRef, useEffect } from 'react';
import { Send, User, Bot, Menu, X, Baby, ClipboardList, Activity, MessageSquare, Stethoscope, BookOpen, Map, Zap, Compass, LogOut, Users, Shield, GraduationCap, Archive, Loader2 } from 'lucide-react';
import { Language, ChatMessage, ScoredSyndrome, UserAccount, SavedPatient, TcmDiagnosisResult } from './types';
import { sendMessageToGeminiStream } from './services/geminiService';
import { analyzePatient } from './services/tcmLogic';
import { db, DEFAULT_ADMIN } from './services/db';
import DiagnosisCard from './components/DiagnosisCard';
import LanguageSelector from './components/LanguageSelector';
import PatientFormModal from './components/PatientFormModal';
import WuXingVisualizerModal from './components/WuXingVisualizerModal';
import ScoringAndPointsHub from './components/ScoringAndPointsHub';
import { YinYangTheoryWindow } from './components/YinYangTheoryWindow';
import StrokeEducationPanel from './components/StrokeEducationPanel';
import WuXingMasterPanel from './components/WuXingMasterPanel';
import { SyndromeAtlasWindow } from './components/SyndromeAtlasWindow';
import LoginScreen from './components/LoginScreen';
import UserManagementModal from './components/UserManagementModal';
import UkomPracticePanel from './components/UkomPracticePanel';
import PatientArchivePanel from './components/PatientArchivePanel';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(() => {
    const users = db.users.getAll();
    return users.find(u => u.username === 'admin') || DEFAULT_ADMIN;
  });

  const [activePanel, setActivePanel] = useState<'chat' | 'diagnosis' | 'theory' | 'stroke' | 'atlas' | 'wuxing' | 'ukom' | 'archive'>('chat');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: 'welcome', role: 'model', text: 'Selamat datang di TCM WuXing Pro. Silakan isi form pasien atau ceritakan keluhan Anda.', timestamp: new Date() }
  ]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false); 
  const [selectedLanguage, setSelectedLanguage] = useState<Language>(Language.INDONESIAN);
  const [isPregnant, setIsPregnant] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isVisualizerOpen, setIsVisualizerOpen] = useState(false);
  const [isUserMgmtOpen, setIsUserMgmtOpen] = useState(false);
  const [visualizerHighlight, setVisualizerHighlight] = useState<string | null>(null);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [cdssResults, setCdssResults] = useState<ScoredSyndrome[]>([]);
  const [lastPatientForm, setLastPatientForm] = useState<any>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  };

  useEffect(() => { 
    if (activePanel === 'chat') scrollToBottom(); 
  }, [messages, activePanel, isLoading]);

  const handleSendMessage = async (textOverride?: string, analysis?: ScoredSyndrome[]) => {
    const textToSend = textOverride || inputText;
    const imageToSend = textOverride ? undefined : (selectedImage || undefined);

    if ((!textToSend.trim() && !imageToSend) || isLoading) return;

    setIsLoading(true);

    const userMessage: ChatMessage = { 
      id: Date.now().toString(), 
      role: 'user', 
      text: textToSend, 
      image: imageToSend, 
      timestamp: new Date() 
    };

    setMessages(prev => [...prev, userMessage]);
    setInputText('');
    setSelectedImage(null);

    const botMsgId = (Date.now() + 1).toString();
    setMessages(prev => [...prev, { 
      id: botMsgId, 
      role: 'model', 
      text: "Menganalisis data...", 
      timestamp: new Date() 
    }]);

    try {
      const response = await sendMessageToGeminiStream(
        textToSend, 
        imageToSend, 
        messages, 
        selectedLanguage, 
        isPregnant, 
        analysis || cdssResults,
        (partialJson) => {
            try {
                if (partialJson.includes('"conversationalResponse":')) {
                    const match = partialJson.match(/"conversationalResponse":\s*"([^"]*)"/);
                    if (match && match[1]) {
                        setMessages(prev => prev.map(m => m.id === botMsgId ? { ...m, text: match[1] } : m));
                    }
                }
            } catch (e) { /* ignore partial parse errors */ }
        }
      );

      setMessages(prev => prev.map(m => m.id === botMsgId ? { 
        ...m, 
        text: response.conversationalResponse || "Analisis selesai.", 
        tcmResult: response.diagnosis 
      } : m));

    } catch (error) {
      setMessages(prev => prev.map(m => m.id === botMsgId ? { 
        ...m, 
        text: "Maaf, terjadi kesalahan koneksi. Silakan coba lagi.", 
        isError: true 
      } : m));
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const handleFormSubmit = (data: any) => {
    setLastPatientForm(data);
    setIsAnalyzing(true);

    const results = analyzePatient({ symptoms: data.symptoms, tongue: data.tongue, pulse: data.pulse });
    setCdssResults(results);
    setIsAnalyzing(false);

    setActivePanel('diagnosis'); 

    if (results.length > 0) {
        const topResult = results[0];
        const diagnosisToSave: TcmDiagnosisResult = {
            patternId: topResult.syndrome.id,
            confidence: topResult.score / 100,
            explanation: (topResult.rationale || []).join('; '),
            recommendedPoints: (topResult.points || []).map(p => ({ code: p.code, description: p.note || p.role })),
            affectedOrgans: topResult.syndrome.primary_organs || [],
            lifestyleAdvice: "CDSS Analysis Result.",
            herbal_recommendation: topResult.herbal_recommendation,
            wuxingElement: topResult.syndrome.wuxing_element,
            wuxingRelationships: topResult.wuxingRelationships || [],
            pulse: data.pulse
        };

        db.patients.add({
            id: Date.now().toString(),
            patientName: data.patientName || "Anonymous",
            age: data.age || "",
            sex: data.sex || "",
            address: data.address || "",
            complaint: data.complaint || "",
            symptoms: data.symptoms || "",
            selectedSymptoms: data.selectedSymptoms || [],
            tongue: data.tongue || {},
            pulse: data.pulse || { qualities: [] },
            diagnosis: diagnosisToSave,
            medicalHistory: data.medicalHistory || "",
            biomedicalDiagnosis: data.biomedicalDiagnosis || "",
            icd10: data.icd10 || "",
            medications: data.medications || "",
            notes: data.notes || "",
            followUpDate: data.followUpDate || "",
            timestamp: Date.now(),
        });
    }

    const formattedMessage = `**DATA PASIEN BARU**\nNama: ${data.patientName || 'Anonymous'}\nKeluhan: ${data.complaint}\nLidah: ${data.tongue?.body_color || 'N/A'} | Nadi: ${(data.pulse?.qualities || []).join(', ')}\nMohon berikan analisis Wu Xing yang mendalam.`.trim();
    handleSendMessage(formattedMessage, results);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setIsSidebarOpen(false);
  };

  if (!currentUser) return <LoginScreen onLoginSuccess={setCurrentUser} />;

  return (
    <div className="flex h-screen bg-slate-950 text-slate-100 overflow-hidden font-sans">
      <PatientFormModal isOpen={isFormOpen} onClose={() => setIsFormOpen(false)} onSubmit={handleFormSubmit} />
      <WuXingVisualizerModal isOpen={isVisualizerOpen} onClose={() => setIsVisualizerOpen(false)} initialHighlight={visualizerHighlight} />
      {isUserMgmtOpen && <UserManagementModal isOpen={isUserMgmtOpen} onClose={() => setIsUserMgmtOpen(false)} currentUser={currentUser} />}

      <div className={`fixed inset-y-0 left-0 z-40 w-64 bg-slate-900 border-r border-slate-800 transform transition-transform md:relative md:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} flex flex-col`}>
        <div className="p-5 flex justify-between items-center">
           <h1 className="text-xl font-black bg-gradient-to-r from-tcm-primary to-tcm-accent bg-clip-text text-transparent flex items-center gap-2">
              <Activity className="w-6 h-6 text-tcm-primary" /> TCM WuXing
           </h1>
           <button onClick={() => setIsSidebarOpen(false)} className="md:hidden text-slate-500 hover:text-white">
              <X className="w-5 h-5" />
           </button>
        </div>
        <div className="flex-1 px-3 space-y-2 overflow-y-auto">
           <button onClick={() => setActivePanel('chat')} className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm ${activePanel === 'chat' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/20' : 'text-slate-400 hover:bg-slate-800'}`}>
              <MessageSquare className="w-4 h-4" /> Chat / Diagnosa
           </button>
           <button onClick={() => setActivePanel('diagnosis')} className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm ${activePanel === 'diagnosis' ? 'bg-tcm-primary text-white shadow-lg shadow-emerald-900/40' : 'text-slate-400 hover:bg-slate-800'}`}>
              <Stethoscope className="w-4 h-4" /> CDSS Auto-Rx
           </button>
           <button onClick={() => setActivePanel('archive')} className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm ${activePanel === 'archive' ? 'bg-emerald-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>
              <Archive className="w-4 h-4" /> Arsip Pasien
           </button>
           <button onClick={() => setActivePanel('wuxing')} className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm ${activePanel === 'wuxing' ? 'bg-pink-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>
              <Compass className="w-4 h-4" /> Wu Xing Master
           </button>
           <button onClick={() => setActivePanel('ukom')} className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm ${activePanel === 'ukom' ? 'bg-sky-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>
              <GraduationCap className="w-4 h-4" /> Latihan UKOM
           </button>

           <div className="pt-4 border-t border-slate-800">
             {currentUser.role === 'admin' && (
               <button onClick={() => setIsUserMgmtOpen(true)} className="w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm text-slate-400 hover:bg-slate-800">
                  <Shield className="w-4 h-4" /> User Management
               </button>
             )}
             <button onClick={handleLogout} className="w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm text-rose-500 hover:bg-rose-950/20">
                <LogOut className="w-4 h-4" /> Logout
             </button>
           </div>
        </div>
        <div className="p-3 pb-8 border-t border-slate-800 space-y-2">
           <button onClick={() => setIsSidebarOpen(false) || setIsFormOpen(true)} className="w-full flex items-center justify-center gap-2 py-3 bg-slate-800 text-tcm-primary rounded-xl font-bold text-sm hover:border-tcm-primary border border-slate-700 transition-all">
              <ClipboardList className="w-4 h-4" /> New Patient
           </button>
        </div>
      </div>

      <div className="flex-1 flex flex-col h-full relative overflow-hidden bg-slate-950">
        <header className="md:hidden flex items-center justify-between p-4 bg-slate-900 border-b border-slate-800">
           <button onClick={() => setIsSidebarOpen(true)} className="p-2 bg-slate-800 rounded-lg text-slate-400">
              <Menu className="w-6 h-6" />
           </button>
           <h1 className="text-lg font-black bg-gradient-to-r from-tcm-primary to-tcm-accent bg-clip-text text-transparent">TCM WuXing</h1>
           <div className="w-10"></div>
        </header>

        {activePanel === 'chat' && (
           <div className="flex-1 flex flex-col min-h-0">
              <div className="flex-1 overflow-y-auto p-4 space-y-4 scrollbar-hide">
                {messages.map((msg) => (
                  <div key={msg.id} className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-fade-in`}>
                    <div className={`flex max-w-[90%] md:max-w-[80%] gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                      <div className="flex flex-col gap-1 w-full min-w-0">
                        <div className={`p-4 rounded-2xl text-sm whitespace-pre-wrap shadow-md ${msg.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-200 border border-slate-700'}`}>
                          {msg.text}
                        </div>
                        {(msg.tcmResult || (isLoading && msg.role === 'model' && msg.id === messages[messages.length - 1].id)) && (
                          <DiagnosisCard 
                            diagnosis={msg.tcmResult} 
                            isPregnant={isPregnant} 
                            onShowVisualizer={(el) => { setVisualizerHighlight(el || null); setIsVisualizerOpen(true); }}
                            patientContext={lastPatientForm}
                          />
                        )}
                      </div>
                    </div>
                  </div>
                ))}

                {isLoading && (
                  <div className="flex w-full justify-start animate-fade-in">
                    <div className="bg-slate-800 border border-slate-700 p-4 rounded-2xl text-slate-200 shadow-md flex items-center gap-2 min-w-[80px]">
                      <span className="dot-typing"></span>
                      <span className="dot-typing"></span>
                      <span className="dot-typing"></span>
                    </div>
                  </div>
                )}

                <div ref={messagesEndRef} />
              </div>
              <div className="p-4 bg-slate-900 border-t border-slate-800 shrink-0">
                <div className="max-w-4xl mx-auto flex items-end gap-2">
                  <textarea 
                    value={inputText} 
                    onChange={(e) => setInputText(e.target.value)} 
                    onKeyDown={handleKeyDown}
                    placeholder="Tulis keluhan..." 
                    className="flex-1 bg-slate-950 border border-slate-800 rounded-2xl text-white text-sm p-3 focus:border-tcm-primary outline-none resize-none transition-all duration-300 focus:ring-1 focus:ring-tcm-primary/30" 
                    rows={1} 
                  />
                  <button 
                    onClick={() => handleSendMessage()} 
                    disabled={isLoading}
                    className={`p-3 rounded-full text-white transition-all duration-300 transform active:scale-90 ${isLoading ? 'bg-slate-700 cursor-not-allowed' : 'bg-tcm-primary hover:bg-emerald-400 hover:shadow-lg hover:shadow-emerald-900/40'}`}
                  >
                    {isLoading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Send className="w-5 h-5" />}
                  </button>
                </div>
              </div>
           </div>
        )}

        {activePanel === 'diagnosis' && (
           <div className="flex-1 min-h-0 bg-slate-950">
             <ScoringAndPointsHub analysis={cdssResults} onAnalyzeRequest={() => setIsFormOpen(true)} patientContext={lastPatientForm} />
           </div>
        )}
        {activePanel === 'archive' && <div className="flex-1 min-h-0 bg-slate-950"><PatientArchivePanel onLoadPatient={(p) => { setActivePanel('diagnosis'); }} /></div>}
        {activePanel === 'ukom' && <div className="flex-1 min-h-0 bg-slate-950"><UkomPracticePanel /></div>}
        {activePanel === 'wuxing' && <div className="flex-1 min-h-0 bg-slate-950"><WuXingMasterPanel onSelectSyndrome={(id) => { setActivePanel('diagnosis'); }} /></div>}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo } from 'react';
import { TcmDiagnosisResult, Syndrome } from '../types';
import { TCM_DB } from '../constants';
import { db } from '../services/db';
import { 
  AlertTriangle, Activity, Stethoscope, GitMerge, MapPin, 
  BrainCircuit, Zap, Target, Layers, Save, FileText, 
  FileDown, Leaf, Map, ChevronRight, Info, Search, AlertCircle, 
  Loader2, History, ClipboardCheck, Heart, ShieldCheck, Sparkles
} from 'lucide-react';
import DoctorNoteModal from './DoctorNoteModal';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';
import { WuXingInteractiveDiagram } from './WuXingInteractiveDiagram';

interface Props {
  diagnosis?: TcmDiagnosisResult | null;
  isPregnant: boolean;
  onShowVisualizer: (element?: string) => void;
  patientContext?: any;
}

const DiagnosisCard: React.FC<Props> = ({ diagnosis, isPregnant, onShowVisualizer, patientContext }) => {
  const [showNoteModal, setShowNoteModal] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const [isExporting, setIsExporting] = useState(false);
  const [syndromeSearch, setSyndromeSearch] = useState('');
  const cardRef = useRef<HTMLDivElement>(null);

  // Subtle Loading state if diagnosis is null or undefined
  if (!diagnosis) {
    return (
      <div className="bg-slate-900 border border-slate-800 rounded-3xl p-8 my-6 flex flex-col items-center justify-center gap-4 animate-pulse-soft shadow-xl border-dashed">
         <div className="w-12 h-12 rounded-2xl bg-slate-950 flex items-center justify-center border border-slate-800">
            <Loader2 className="w-6 h-6 text-tcm-primary animate-spin" />
         </div>
         <div className="text-center">
            <p className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-1">Building Clinical Profile</p>
            <p className="text-[10px] text-slate-600 font-bold uppercase">Synthesizing Wu Xing Dynamics...</p>
         </div>
      </div>
    );
  }

  const allSyndromes = useMemo(() => [
    ...TCM_DB.syndromes.FILLED_FROM_PDF,
    ...TCM_DB.syndromes.TODO_FROM_PDF
  ], []);

  const patternName = diagnosis.patternId; 
  const displayOrgans = diagnosis.affectedOrgans || [];

  const filteredSyndromes = useMemo(() => {
    const query = syndromeSearch.trim().toLowerCase();
    if (!query) {
      return allSyndromes.filter(s => 
        (s.wuxing_element || "").toLowerCase() === (diagnosis.wuxingElement || "").toLowerCase()
      ).slice(0, 5);
    }
    return allSyndromes.filter(s => 
      (s.name_id || "").toLowerCase().includes(query) || 
      (s.name_en || "").toLowerCase().includes(query) ||
      (s.id || "").toLowerCase().includes(query)
    ).slice(0, 5);
  }, [syndromeSearch, allSyndromes, diagnosis]);

  const handleSaveToArchive = () => {
    let patientName = patientContext?.patientName || prompt("Masukkan Nama Pasien:") || "Anonim";
    db.patients.add({
      id: Date.now().toString(),
      patientName: patientName,
      age: patientContext?.age || "?",
      sex: patientContext?.sex || "?",
      address: patientContext?.address || "",
      complaint: patientContext?.complaint || "Chat Diagnosis",
      symptoms: patientContext?.symptoms || "",
      selectedSymptoms: patientContext?.selectedSymptoms || [],
      tongue: patientContext?.tongue || {},
      pulse: patientContext?.pulse || { qualities: [] },
      diagnosis: diagnosis,
      medicalHistory: patientContext?.medicalHistory || "",
      biomedicalDiagnosis: patientContext?.biomedicalDiagnosis || "",
      notes: patientContext?.notes || "",
      timestamp: Date.now()
    });
    setIsSaved(true);
  };

  const handleExportPDF = async () => {
    if (!cardRef.current || isExporting) return;
    setIsExporting(true);

    try {
      const canvas = await html2canvas(cardRef.current, { 
        scale: 2, 
        useCORS: true, 
        backgroundColor: '#020617', // Slate-950
        logging: false,
        allowTaint: true,
        height: cardRef.current.scrollHeight, 
        windowHeight: cardRef.current.scrollHeight,
        onclone: (clonedDoc) => {
          const el = clonedDoc.querySelector('[data-pdf-content="true"]') as HTMLElement;
          if (el) {
            el.style.height = 'auto';
            el.style.maxHeight = 'none';
            el.style.overflow = 'visible';
          }
        }
      });

      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');

      const pageWidth = pdf.internal.pageSize.getWidth();
      const pageHeight = pdf.internal.pageSize.getHeight();
      const margin = 10;
      const contentWidth = pageWidth - (margin * 2);

      const imgProps = pdf.getImageProperties(imgData);
      const imgHeight = (imgProps.height * contentWidth) / imgProps.width;

      let heightLeft = imgHeight;
      let position = 0;

      // First Page
      pdf.setFillColor(2, 6, 23); 
      pdf.rect(0, 0, pageWidth, pageHeight, 'F');
      pdf.addImage(imgData, 'PNG', margin, margin, contentWidth, imgHeight);
      heightLeft -= (pageHeight - margin * 2);

      // Multi-page logic
      while (heightLeft > 0) {
        position = heightLeft - imgHeight + margin; 
        pdf.addPage();
        pdf.setFillColor(2, 6, 23);
        pdf.rect(0, 0, pageWidth, pageHeight, 'F');
        pdf.addImage(imgData, 'PNG', margin, position, contentWidth, imgHeight);
        heightLeft -= pageHeight;
      }

      pdf.save(`TCM_Report_${(patternName || 'Diagnosis').replace(/\s+/g, '_')}.pdf`);
    } catch (error) {
      console.error("PDF Export Error:", error);
      alert("Gagal mengekspor PDF.");
    } finally {
      setIsExporting(false);
    }
  };

  const elementColorClass = (() => {
    const el = (diagnosis.wuxingElement || "").toLowerCase();
    if (el.includes('wood')) return 'border-emerald-500 shadow-emerald-900/20';
    if (el.includes('fire')) return 'border-rose-500 shadow-rose-900/20';
    if (el.includes('earth')) return 'border-amber-500 shadow-amber-900/20';
    if (el.includes('metal')) return 'border-slate-300 shadow-slate-500/20';
    if (el.includes('water')) return 'border-blue-500 shadow-blue-900/20';
    return 'border-slate-800';
  })();

  return (
    <>
      <DoctorNoteModal isOpen={showNoteModal} onClose={() => setShowNoteModal(false)} diagnosis={diagnosis} initialPatientData={{ name: patientContext?.patientName, age: patientContext?.age, address: patientContext?.address }} />

      <div 
        ref={cardRef} 
        data-pdf-content="true"
        className={`bg-slate-950 border-t-4 ${elementColorClass} rounded-3xl p-6 my-6 shadow-2xl animate-fade-in relative overflow-hidden transition-all h-auto`}
      >
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8 relative z-10">
          <div className="flex items-center gap-5">
            <div className="w-16 h-16 rounded-2xl bg-slate-900 flex items-center justify-center border border-slate-800 shadow-inner">
               <BrainCircuit className="w-10 h-10 text-tcm-primary" />
            </div>
            <div>
              <div className="flex items-center gap-2 mb-1">
                 <h3 className="text-2xl font-black text-white tracking-tighter uppercase">{patternName || 'Unknown Pattern'}</h3>
                 <span className="text-[10px] bg-emerald-500/20 text-emerald-400 px-2 py-0.5 rounded-full font-black border border-emerald-500/30">
                    {Math.round((diagnosis.confidence || 0) * 100)}% CONFIDENCE
                 </span>
              </div>
              <div className="text-xs text-slate-500 font-bold uppercase tracking-widest">Maciocia Syndrome Classification</div>
            </div>
          </div>

          <div className="flex flex-wrap items-center gap-2 print:hidden">
              <button 
                onClick={handleSaveToArchive} 
                disabled={isSaved} 
                className={`flex items-center gap-2 px-4 py-2 rounded-xl border transition-all ${isSaved ? 'bg-emerald-950 text-emerald-400 border-emerald-800' : 'bg-slate-900 text-slate-400 border-slate-800 hover:text-white'}`}
              >
                  <Save className="w-4 h-4" /> <span className="text-xs font-bold uppercase">{isSaved ? 'Saved' : 'Save'}</span>
              </button>
              <button onClick={() => setShowNoteModal(true)} className="px-4 py-2 bg-slate-800 hover:bg-slate-700 text-white rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 border border-slate-700">
                  <FileText className="w-4 h-4" /> Rx Note
              </button>
              <button 
                onClick={handleExportPDF} 
                disabled={isExporting}
                className="px-4 py-2 bg-tcm-primary hover:bg-emerald-400 text-white rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 shadow-lg disabled:opacity-50"
              >
                {isExporting ? <Loader2 className="w-4 h-4 animate-spin" /> : <><FileDown className="w-4 h-4" /> Export Report</>}
              </button>
          </div>
        </div>

        {/* Clinical Background Section */}
        {(patientContext?.medicalHistory || patientContext?.biomedicalDiagnosis) && (
          <div className="mb-8 relative z-10 grid grid-cols-1 md:grid-cols-2 gap-4">
             {patientContext.biomedicalDiagnosis && (
                <div className="bg-indigo-900/20 border border-indigo-500/30 p-4 rounded-2xl">
                   <div className="flex items-center gap-2 text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-2">
                      <Stethoscope className="w-3 h-3" /> Biomedical Diagnosis
                   </div>
                   <p className="text-sm font-bold text-slate-200">{patientContext.biomedicalDiagnosis}</p>
                </div>
             )}
             {patientContext.medicalHistory && (
                <div className="bg-slate-900 border border-slate-800 p-4 rounded-2xl">
                   <div className="flex items-center gap-2 text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2">
                      <History className="w-3 h-3" /> Medical History
                   </div>
                   <p className="text-xs text-slate-400 italic line-clamp-2">"{patientContext.medicalHistory}"</p>
                </div>
             )}
          </div>
        )}

        {/* Pathology Visualizer & Elemental Info */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8 relative z-10">
           <div className="bg-slate-900/40 border border-slate-800/50 p-6 rounded-3xl flex flex-col h-[450px]">
              <div className="flex items-center gap-2 mb-4 text-indigo-400 text-[10px] font-black uppercase tracking-[0.3em]">
                 <GitMerge className="w-4 h-4" /> Pathological Visualizer
              </div>
              <div className="flex-1 min-h-0">
                 <WuXingInteractiveDiagram 
                    initialHighlight={diagnosis.wuxingElement} 
                    highlightedRelationships={diagnosis.wuxingRelationships}
                    compact={true}
                    embedded={true}
                 />
              </div>
           </div>

           <div className="flex flex-col gap-6">
              <div className="grid grid-cols-2 gap-4">
                 <div className="bg-slate-900 border border-slate-800 p-5 rounded-3xl">
                    <div className="flex items-center gap-2 text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3">
                       <Target className="w-4 h-4 text-emerald-500" /> Organs
                    </div>
                    <div className="flex flex-wrap gap-1.5">
                       {(displayOrgans || []).map(org => <span key={org} className="bg-slate-950 px-3 py-1 rounded-xl border border-slate-800 text-xs font-bold text-slate-200">{org}</span>)}
                    </div>
                 </div>
                 <div className="bg-slate-900 border border-slate-800 p-5 rounded-3xl">
                    <div className="flex items-center gap-2 text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3">
                       <Layers className="w-4 h-4 text-tcm-primary" /> Element
                    </div>
                    <span className="text-lg font-black text-tcm-primary uppercase tracking-tighter">{diagnosis.wuxingElement || 'General'}</span>
                 </div>
              </div>

              <div className="bg-slate-900/60 border border-slate-800 p-5 rounded-3xl flex-1 print:hidden">
                 <div className="flex items-center gap-2 mb-4 text-[10px] font-black text-slate-500 uppercase tracking-widest">
                    <Search className="w-4 h-4" /> Related Patterns
                 </div>
                 <div className="space-y-2 max-h-[200px] overflow-y-auto scrollbar-hide">
                    {filteredSyndromes.map(s => (
                       <div key={s.id} className="p-3 bg-slate-950 border border-slate-800 rounded-xl flex items-center justify-between group">
                          <div>
                             <span className="text-xs font-bold text-slate-200">{s.name_id}</span>
                             <span className="block text-[9px] text-slate-600 uppercase">{s.wuxing_element}</span>
                          </div>
                       </div>
                    ))}
                 </div>
              </div>
           </div>
        </div>

        {/* Clinical Synthesis & Acupuncture */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8 relative z-10">
           <div className="bg-slate-900 border border-slate-800 p-6 rounded-3xl shadow-inner flex flex-col">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4 block flex items-center gap-2">
                 <ClipboardCheck className="w-4 h-4" /> Clinical Synthesis
              </span>
              <p className="text-slate-300 leading-relaxed text-sm italic border-l-2 border-tcm-primary pl-4 flex-1">"{diagnosis.explanation || 'No explanation available.'}"</p>
           </div>

           <div className="bg-slate-900 border border-slate-800 p-6 rounded-3xl">
              <h4 className="text-[10px] font-black text-tcm-primary uppercase tracking-[0.3em] mb-4 flex items-center gap-2">
                  <MapPin className="w-4 h-4"/> Acupuncture Points
              </h4>
              <div className="space-y-3">
                {(diagnosis.recommendedPoints || []).map((point, idx) => (
                    <div key={idx} className="flex items-start gap-3 p-3 bg-slate-950 rounded-2xl border border-slate-800">
                       <div className="px-2 py-1 bg-emerald-500/10 text-emerald-400 rounded-lg border border-emerald-500/20 text-[10px] font-black">
                          {point.code}
                       </div>
                       <p className="text-[11px] text-slate-400 leading-tight">
                          {point.description}
                       </p>
                    </div>
                ))}
              </div>
           </div>
        </div>

        {/* Saran Kesehatan (Lifestyle Advice) - New Highlighted Section */}
        {diagnosis.lifestyleAdvice && (
          <div className="bg-indigo-950/20 border border-indigo-500/30 p-6 rounded-3xl mb-8 relative z-10 group transition-all hover:bg-indigo-900/30">
             <div className="flex items-center gap-3 mb-4">
                <div className="p-2.5 bg-indigo-500/10 rounded-xl border border-indigo-500/20">
                   <Heart className="w-5 h-5 text-indigo-400 group-hover:scale-110 transition-transform" />
                </div>
                <div>
                  <h4 className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.4em]">Saran Kesehatan</h4>
                  <p className="text-xs text-slate-400 font-bold">Wellness & Recovery Protocol</p>
                </div>
             </div>
             <p className="text-sm text-slate-200 leading-relaxed pl-2 border-l-2 border-indigo-500/50">
                {diagnosis.lifestyleAdvice}
             </p>
          </div>
        )}

        {/* Herbal Strategy & Contraindications */}
        {diagnosis.herbal_recommendation && (
          <div className="bg-emerald-950/20 border border-emerald-500/30 p-8 rounded-[2rem] relative z-10">
             <div className="flex items-center gap-4 mb-8">
                <div className="w-12 h-12 rounded-2xl bg-emerald-500/10 flex items-center justify-center border border-emerald-500/20">
                  <Leaf className="w-6 h-6 text-emerald-400" />
                </div>
                <div>
                  <h4 className="text-[10px] font-black text-emerald-400 uppercase tracking-[0.4em] mb-1">Herbal Strategy</h4>
                  <p className="text-2xl font-black text-white uppercase tracking-tighter">
                    {diagnosis.herbal_recommendation.formula_name || "Custom Prep"}
                  </p>
                </div>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="bg-slate-950/60 p-6 rounded-3xl border border-slate-800">
                   <span className="text-[10px] font-black text-emerald-500 uppercase tracking-[0.2em] mb-4 block flex items-center gap-2">
                     <Sparkles className="w-3 h-3" /> Chief Herbs (Jun)
                   </span>
                   <div className="flex flex-wrap gap-2">
                      {(diagnosis.herbal_recommendation.chief || []).map((herb, i) => (
                        <span key={i} className="px-3 py-1.5 bg-slate-900 text-xs rounded-xl text-slate-300 border border-slate-800 font-bold">{herb}</span>
                      ))}
                   </div>
                </div>

                {diagnosis.herbal_recommendation.avoid && diagnosis.herbal_recommendation.avoid.length > 0 && (
                   <div className="bg-rose-950/40 p-6 rounded-3xl border border-rose-500/40 shadow-lg shadow-rose-900/20 animate-vibrate">
                      <span className="text-[10px] font-black text-rose-400 uppercase tracking-[0.2em] mb-4 block flex items-center gap-2">
                         <ShieldCheck className="w-4 h-4 text-rose-500" /> KONTRAINDIKASI (WARNING)
                      </span>
                      <ul className="space-y-2">
                         {(diagnosis.herbal_recommendation.avoid || []).map((a, i) => (
                           <li key={i} className="text-xs text-rose-100 flex items-start gap-2 bg-rose-900/20 p-2 rounded-lg border border-rose-800/30">
