                                   <div className="px-4 py-1.5 bg-rose-950/30 border border-rose-500/30 rounded-full text-[10px] font-black text-rose-400 uppercase tracking-widest animate-pulse-soft">
                                      {rel.type}
                                   </div>
                                   <div className="h-[2px] w-8 bg-slate-700"></div>
                                </div>
                                <span className="text-[8px] text-slate-600 font-bold uppercase mt-2 italic text-center max-w-[150px]">
                                   {rel.description?.slice(0, 50)}...
                                </span>
                             </div>

                             {/* TARGET ELEMENT */}
                             <div className="flex flex-col items-center">
                                <span className="text-[9px] font-black text-slate-500 uppercase mb-2 tracking-widest">Dampak (Impact)</span>
                                <div className={`px-6 py-3 rounded-2xl border ${targetColors.bg} ${targetColors.border} flex flex-col items-center min-w-[120px]`}>
                                   <Target className={`w-5 h-5 ${targetColors.text} mb-1`} />
                                   <span className={`text-sm font-black uppercase ${targetColors.text}`}>{rel.targetElement}</span>
                                </div>
                             </div>
                          </React.Fragment>
                        );
                      })
                   ) : (
                      <div className="px-8 py-4 bg-slate-950 border border-slate-800 rounded-xl text-[10px] text-slate-600 font-bold uppercase tracking-widest italic">
                         Isolated Internal Imbalance • No External Overflow
                      </div>
                   )}
                </div>

                {/* Simplified Pathological Text Summary */}
                <div className="pt-4 border-t border-slate-800/50">
                   <p className="text-xs text-slate-400 leading-relaxed text-center">
                     Dinamika patologis saat ini menunjukkan unsur <span className={`${activeElementColors.text} font-bold`}>{diagnosis.wuxingElement}</span> 
                     {diagnosis.wuxingRelationships && diagnosis.wuxingRelationships.length > 0 ? (
                        <> sebagai akar masalah yang sedang <span className="text-rose-400 font-bold">{diagnosis.wuxingRelationships[0].type.toLowerCase()}</span> terhadap unsur <span className={`${getElementColors(diagnosis.wuxingRelationships[0].targetElement).text} font-bold`}>{diagnosis.wuxingRelationships[0].targetElement}</span>.</>
                     ) : (
                        <> mengalami ketidakseimbangan internal tanpa mempengaruhi unsur lain dalam siklus Wu Xing.</>
                     )}
                   </p>
                </div>
             </div>
          </div>
        </div>

        {/* Clinical Synthesis & Acupuncture */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8 relative z-10">
           <div className="bg-slate-900 border border-slate-800 p-5 rounded-2xl shadow-inner flex flex-col">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4 block flex items-center gap-2">
                 <ClipboardCheck className="w-3.5 h-3.5" /> Analisis Klinis
              </span>
              <p className="text-slate-300 leading-relaxed text-xs italic border-l-2 border-tcm-primary pl-4 flex-1">
                {diagnosis.explanation || 'Deskripsi tidak tersedia.'}
              </p>
           </div>

           <div className="bg-slate-900 border border-slate-800 p-5 rounded-2xl">
              <h4 className="text-[10px] font-black text-tcm-primary uppercase tracking-[0.3em] mb-4 flex items-center gap-2">
                  <MapPin className="w-3.5 h-3.5"/> Resep Akupunktur
              </h4>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                {(diagnosis.recommendedPoints || []).map((point, idx) => (
                    <div key={idx} className="flex items-center gap-2.5 p-2 bg-slate-950 rounded-xl border border-slate-800 transition-hover hover:border-emerald-500/30">
                       <div className="px-1.5 py-0.5 bg-emerald-500/10 text-emerald-400 rounded-md border border-emerald-500/20 text-[9px] font-black">
                          {point.code}
                       </div>
                       <p className="text-[10px] text-slate-400 leading-tight truncate">
                          {point.description}
                       </p>
                    </div>
                ))}
              </div>
           </div>
        </div>

        {/* Saran Kesehatan (Health Advice) */}
        {diagnosis.lifestyleAdvice && (
          <div className="bg-indigo-950/20 border border-indigo-500/30 p-5 rounded-2xl mb-8 relative z-10 group transition-all">
             <div className="flex items-center gap-3 mb-3">
                <div className="p-2 bg-indigo-500/10 rounded-lg border border-indigo-500/20">
                   <Heart className="w-4 h-4 text-indigo-400" />
                </div>
                <h4 className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.3em]">Saran Kesehatan & Gaya Hidup</h4>
             </div>
             <p className="text-xs text-slate-200 leading-relaxed pl-3 border-l-2 border-indigo-500/50">
                {diagnosis.lifestyleAdvice}
             </p>
          </div>
        )}

        {/* Herbal Section - Refined Header Size */}
        {diagnosis.herbal_recommendation && (
          <div className="bg-emerald-950/10 border border-emerald-500/20 p-6 rounded-3xl relative z-10">
             <div className="flex items-center gap-3 mb-6">
                <div className="w-10 h-10 rounded-xl bg-emerald-500/10 flex items-center justify-center border border-emerald-500/20">
                  <Leaf className="w-5 h-5 text-emerald-400" />
                </div>
                <div>
                  <h4 className="text-[10px] font-black text-emerald-400 uppercase tracking-[0.3em] mb-0.5">Rekomendasi Herbal</h4>
                  <p className="text-lg font-black text-white uppercase tracking-tighter">
                    {diagnosis.herbal_recommendation.formula_name || "Formula Kustom"}
                  </p>
                </div>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                <div className="bg-slate-950/40 p-4 rounded-xl border border-slate-800">
                   <span className="text-[9px] font-black text-emerald-500 uppercase tracking-widest mb-3 block flex items-center gap-2">
                     <Sparkles className="w-3 h-3" /> Komposisi Utama
                   </span>
                   <div className="flex flex-wrap gap-1.5">
                      {(diagnosis.herbal_recommendation.chief || []).map((herb, i) => (
                        <span key={i} className="px-2.5 py-1 bg-slate-900 text-[10px] rounded-lg text-slate-300 border border-slate-800 font-bold">{herb}</span>
                      ))}
                   </div>
                </div>

                {diagnosis.herbal_recommendation.avoid && diagnosis.herbal_recommendation.avoid.length > 0 && (
                   <div className="bg-rose-950/30 p-4 rounded-xl border border-rose-500/30 shadow-lg shadow-rose-900/10">
                      <span className="text-[9px] font-black text-rose-400 uppercase tracking-widest mb-3 block flex items-center gap-2">
                         <ShieldAlert className="w-3.5 h-3.5 text-rose-500" /> KONTRAINDIKASI & PERINGATAN
                      </span>
                      <ul className="space-y-1.5">
                         {(diagnosis.herbal_recommendation.avoid || []).map((a, i) => (
                           <li key={i} className="text-[10px] text-rose-100 flex items-start gap-2 bg-rose-900/10 p-2 rounded-lg border border-rose-800/20">
                              <AlertTriangle className="w-3 h-3 mt-0.5 text-rose-500 shrink-0" />
                              <span className="font-semibold">{a}</span>
                           </li>
                         ))}
                      </ul>
                   </div>
                )}
             </div>
          </div>
        )}
      </div>
    </>
  );
};

