Anda adalah Pakar Senior TCM yang mengadopsi 100% teori Giovanni Maciocia ("Foundations of Chinese Medicine").

**KRITERIA OUTPUT:**
1. **Terminologi Maciocia:** Field 'patternId' harus berisi Nama Pinyin dan Nama Inggris standar Maciocia (Contoh: "Gan Qi Yu Jie - Liver Qi Stagnation").
2. **Deskripsi Titik RX:** Untuk setiap titik di 'recommendedPoints', berikan deskripsi fungsi klinis spesifik Maciocia. Contoh: "ST36: Mengharmoniskan Lambung dan menguatkan Qi Limpa".
3. **Analisis Wu Xing:** Berikan narasi patologis yang menjelaskan Unsur Akar (Root) dan Unsur Cabang (Impact) yang terganggu.
4. **Saran Kesehatan:** Berikan saran gaya hidup (diet, emosi, istirahat) yang spesifik untuk sindrom tersebut.
5. **Bahasa:** Gunakan ${language}.
6. **Format:** Output HARUS JSON valid.

${cdssText}
`;
};

const diagnosisSchema = {
  type: Type.OBJECT,
  properties: {
    conversationalResponse: { type: Type.STRING },
    diagnosis: {
      type: Type.OBJECT,
      properties: {
        patternId: { type: Type.STRING },
        confidence: { type: Type.NUMBER },
        explanation: { type: Type.STRING },
        recommendedPoints: { 
          type: Type.ARRAY, 
          items: { 
            type: Type.OBJECT,
            properties: {
              code: { type: Type.STRING },
              description: { type: Type.STRING }
            },
            required: ["code", "description"]
          } 
        },
        affectedOrgans: { type: Type.ARRAY, items: { type: Type.STRING } },
        lifestyleAdvice: { type: Type.STRING },
        wuxingElement: { type: Type.STRING },
        wuxingRelationships: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING },
              targetElement: { type: Type.STRING },
              description: { type: Type.STRING }
            },
            required: ["type", "targetElement", "description"]
          }
        },
        herbal_recommendation: {
          type: Type.OBJECT,
          properties: {
            formula_name: { type: Type.STRING },
            chief: { type: Type.ARRAY, items: { type: Type.STRING } },
            assistants: { type: Type.ARRAY, items: { type: Type.STRING } },
            avoid: { type: Type.ARRAY, items: { type: Type.STRING } }
          }
        }
      },
      required: ["patternId", "explanation", "recommendedPoints", "wuxingRelationships", "wuxingElement"]
    }
  },
  required: ["conversationalResponse", "diagnosis"]
};

export const sendMessageToGeminiStream = async (
  message: string,
  image: string | undefined,
  history: any[],
  language: Language,
  isPregnant: boolean,
  cdssAnalysis?: ScoredSyndrome[],
  onChunk?: (text: string) => void
) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const parts: any[] = [{ text: message }];
    if (image) {
      const [mimeTypePrefix, base64Data] = image.split(';base64,');
      parts.push({ inlineData: { mimeType: mimeTypePrefix.split(':')[1], data: base64Data } });
    }

    const responseStream = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history.slice(-6).map(h => ({ role: h.role === 'user' ? 'user' : 'model', parts: [{ text: h.text }] })),
        { role: 'user', parts }
      ],
      config: {
        systemInstruction: getSystemInstruction(language, isPregnant, cdssAnalysis),
        responseMimeType: "application/json",
        responseSchema: diagnosisSchema,
        thinkingConfig: { thinkingBudget: 0 }
      }
    });

    let fullText = "";
    for await (const chunk of responseStream) {
      const partText = chunk.text;
      if (partText) {
        fullText += partText;
        if (onChunk) onChunk(fullText);
      }
    }

    return JSON.parse(fullText || "{}");
  } catch (error) {
    console.error("Gemini Streaming Error:", error);
    throw error;
  }
};

