import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { Language, ScoredSyndrome } from '../types';

const getSystemInstruction = (language: Language, isPregnant: boolean, cdssAnalysis?: ScoredSyndrome[]) => {
  let cdssText = "";
  if (cdssAnalysis && cdssAnalysis.length > 0) {
    const primary = cdssAnalysis[0];
    cdssText = `
REFERENSI BASIS DATA:
- Pola Primer: ${primary.syndrome.name_id} (${primary.syndrome.name_en})
- Unsur: ${primary.syndrome.wuxing_element}
- Titik Dasar: ${primary.syndrome.acupuncture_points?.join(', ')}
    `;
  }

  return `
Anda adalah Pakar Senior Diagnosis TCM (Teori Giovanni Maciocia).
TUGAS: Analisis kasus kompleks dengan akurasi tinggi.

KRITERIA OUTPUT:
1. 'patternId': Gunakan terminologi Maciocia (Contoh: "Lung/Kidney Yin Deficiency with Liver Fire").
2. 'explanation': Berikan analisis mendalam mencakup etiologi (akar) dan manifestasi (cabang).
3. 'recommendedPoints': Berikan 8-12 titik. Format: "Kode: Fungsi spesifik (Maciocia)". Contoh: "LR3: Mengatur Qi Hati dan memadamkan Api".
4. 'wuxingRelationships': Analisis hubungan antar unsur (Sheng/Ke/Cheng/Wu).
5. 'lifestyleAdvice': Berikan saran diet (hindari/anjurkan), emosi, dan istirahat.
6. Bahasa: ${language}.

${cdssText}
`;
};

const diagnosisSchema = {
  type: Type.OBJECT,
  properties: {
    conversationalResponse: { type: Type.STRING },
    diagnosis: {
      type: Type.OBJECT,
      properties: {
        patternId: { type: Type.STRING },
        confidence: { type: Type.NUMBER },
        explanation: { type: Type.STRING },
        recommendedPoints: { 
          type: Type.ARRAY, 
          items: { 
            type: Type.OBJECT,
            properties: {
              code: { type: Type.STRING },
              description: { type: Type.STRING }
            },
            required: ["code", "description"]
          } 
        },
        affectedOrgans: { type: Type.ARRAY, items: { type: Type.STRING } },
        lifestyleAdvice: { type: Type.STRING },
        wuxingElement: { type: Type.STRING },
        wuxingRelationships: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING },
              targetElement: { type: Type.STRING },
              description: { type: Type.STRING }
            },
            required: ["type", "targetElement", "description"]
          }
        },
        herbal_recommendation: {
          type: Type.OBJECT,
          properties: {
            formula_name: { type: Type.STRING },
            chief: { type: Type.ARRAY, items: { type: Type.STRING } },
            avoid: { type: Type.ARRAY, items: { type: Type.STRING } }
          }
        }
      },
      required: ["patternId", "explanation", "recommendedPoints", "wuxingRelationships", "wuxingElement"]
    }
  },
  required: ["conversationalResponse", "diagnosis"]
};

export const sendMessageToGeminiStream = async (
  message: string,
  image: string | undefined,
  history: any[],
  language: Language,
  isPregnant: boolean,
  cdssAnalysis?: ScoredSyndrome[],
  onChunk?: (text: string) => void
) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const parts: any[] = [{ text: message }];
    if (image) {
      const [mimeTypePrefix, base64Data] = image.split(';base64,');
      parts.push({ inlineData: { mimeType: mimeTypePrefix.split(':')[1], data: base64Data } });
    }

    const responseStream = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history.slice(-4).map(h => ({ role: h.role === 'user' ? 'user' : 'model', parts: [{ text: h.text }] })),
        { role: 'user', parts }
      ],
      config: {
        systemInstruction: getSystemInstruction(language, isPregnant, cdssAnalysis),
        responseMimeType: "application/json",
        responseSchema: diagnosisSchema,
        thinkingConfig: { thinkingBudget: 0 },
        temperature: 0.3
      }
    });

    let fullText = "";
    for await (const chunk of responseStream) {
      if (chunk.text) {
        fullText += chunk.text;
        if (onChunk) onChunk(fullText);
      }
    }

    return JSON.parse(fullText || "{}");
  } catch (error) {
    console.error("Gemini Error:", error);
    throw error;
  }
};

