import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { Language, ScoredSyndrome } from '../types';

const getSystemInstruction = (language: Language, cdssAnalysis?: ScoredSyndrome[]) => {
  const cdssRaw = cdssAnalysis?.[0] ? `REF CDSS: ${cdssAnalysis[0].syndrome.name_en}, Element: ${cdssAnalysis[0].syndrome.wuxing_element}` : "";

  return `
Anda adalah Pakar TCM (Giovanni Maciocia). Jawab cepat & klinis.
${cdssRaw}
Format: JSON.
Field WAJIB:
- conversationalResponse: Jawaban singkat (max 2 kalimat).
- diagnosis: {
    patternId: "Pinyin - English Name",
    explanation: "Analisis singkat (akar & cabang)",
    recommendedPoints: [{code: "Kode", description: "Fungsi singkat"}],
    wuxingElement: "Wood/Fire/Earth/Metal/Water",
    wuxingRelationships: [{type: "Sheng/Ke/Cheng/Wu", targetElement: "Target", description: "Alasan"}],
    lifestyleAdvice: "2-3 tips praktis",
    herbal_recommendation: {formula_name: "Nama", chief: ["Herba1", "Herba2"]}
  }
Bahasa: ${language}. Prioritas: Kecepatan & Akurasi Maciocia.
`;
};

const diagnosisSchema = {
  type: Type.OBJECT,
  properties: {
    conversationalResponse: { type: Type.STRING },
    diagnosis: {
      type: Type.OBJECT,
      properties: {
        patternId: { type: Type.STRING },
        confidence: { type: Type.NUMBER },
        explanation: { type: Type.STRING },
        recommendedPoints: { 
          type: Type.ARRAY, 
          items: { 
            type: Type.OBJECT,
            properties: { code: { type: Type.STRING }, description: { type: Type.STRING } },
            required: ["code", "description"]
          } 
        },
        lifestyleAdvice: { type: Type.STRING },
        wuxingElement: { type: Type.STRING },
        wuxingRelationships: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: { type: { type: Type.STRING }, targetElement: { type: Type.STRING }, description: { type: Type.STRING } },
            required: ["type", "targetElement", "description"]
          }
        },
        herbal_recommendation: {
          type: Type.OBJECT,
          properties: {
            formula_name: { type: Type.STRING },
            chief: { type: Type.ARRAY, items: { type: Type.STRING } }
          }
        }
      },
      required: ["patternId", "explanation", "recommendedPoints", "wuxingRelationships", "wuxingElement"]
    }
  },
  required: ["conversationalResponse", "diagnosis"]
};

export const sendMessageToGeminiStream = async (
  message: string,
  image: string | undefined,
  history: any[],
  language: Language,
  isPregnant: boolean,
  cdssAnalysis?: ScoredSyndrome[],
  onChunk?: (text: string) => void
) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const parts: any[] = [{ text: message }];
    if (image) {
      const [mimeTypePrefix, base64Data] = image.split(';base64,');
      parts.push({ inlineData: { mimeType: mimeTypePrefix.split(':')[1] || 'image/jpeg', data: base64Data } });
    }

    const responseStream = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history.slice(-2).map(h => ({ role: h.role === 'user' ? 'user' : 'model', parts: [{ text: h.text }] })),
        { role: 'user', parts }
      ],
      config: {
        systemInstruction: getSystemInstruction(language, cdssAnalysis),
        responseMimeType: "application/json",
        responseSchema: diagnosisSchema,
        temperature: 0.1, // Rendah untuk kecepatan & konsistensi
        thinkingConfig: { thinkingBudget: 0 }
      }
    });

    let fullText = "";
    for await (const chunk of responseStream) {
      if (chunk.text) {
        fullText += chunk.text;
        if (onChunk) onChunk(fullText);
      }
    }
    return JSON.parse(fullText || "{}");
  } catch (error) {
    console.error("Gemini Quick Response Error:", error);
    throw error;
  }
};

