  const [activePanel, setActivePanel] = useState<'chat' | 'diagnosis' | 'wuxing' | 'ukom' | 'archive'>('chat');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: 'welcome', role: 'model', text: 'Sistem Siap. Masukkan keluhan pasien untuk analisis cepat.', timestamp: new Date() }
  ]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isVisualizerOpen, setIsVisualizerOpen] = useState(false);
  const [cdssResults, setCdssResults] = useState<ScoredSyndrome[]>([]);
  const [lastPatientForm, setLastPatientForm] = useState<any>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (messagesEndRef.current) messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading]);

  const handleSendMessage = async (textOverride?: string, analysis?: ScoredSyndrome[]) => {
    const textToSend = textOverride || inputText;
    if (!textToSend.trim() || isLoading) return;

    setIsLoading(true);
    const userMsg: ChatMessage = { id: Date.now().toString(), role: 'user', text: textToSend, timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setInputText('');

    const botMsgId = (Date.now() + 1).toString();
    setMessages(prev => [...prev, { id: botMsgId, role: 'model', text: "Menganalisis pola...", timestamp: new Date() }]);

    try {
      const response = await sendMessageToGeminiStream(textToSend, undefined, messages, Language.INDONESIAN, false, analysis || cdssResults);
      setMessages(prev => prev.map(m => m.id === botMsgId ? { 
        ...m, 
        text: response.conversationalResponse || "Analisis Berhasil.", 
        tcmResult: response.diagnosis 
      } : m));
    } catch (error) {
      setMessages(prev => prev.map(m => m.id === botMsgId ? { ...m, text: "Gagal. Periksa koneksi.", isError: true } : m));
    } finally {
      setIsLoading(false);
    }
  };

  const handleFormSubmit = (data: any) => {
    setLastPatientForm(data);
    const results = analyzePatient({ symptoms: data.symptoms, tongue: data.tongue, pulse: data.pulse });
    setCdssResults(results);
    setActivePanel('chat');
    const msg = `PASIEN: ${data.patientName}, USIA: ${data.age}. KELUHAN: ${data.complaint}. LIDAH: ${data.tongue.body_color}. NADI: ${data.pulse.qualities.join(', ')}`;
    handleSendMessage(msg, results);
  };

  if (!currentUser) return <LoginScreen onLoginSuccess={setCurrentUser} />;

  return (
    <div className="flex h-screen bg-slate-950 text-slate-100 overflow-hidden font-sans">
      <PatientFormModal isOpen={isFormOpen} onClose={() => setIsFormOpen(false)} onSubmit={handleFormSubmit} />
      <WuXingVisualizerModal isOpen={isVisualizerOpen} onClose={() => setIsVisualizerOpen(false)} />

      {/* Sidebar */}
      <div className={`fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 border-r border-slate-800 transform transition-transform duration-300 md:relative md:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} flex flex-col`}>
        <div className="p-6 flex justify-between items-center border-b border-slate-800">
           <h1 className="text-xl font-black text-tcm-primary flex items-center gap-2"><Activity /> TCM PRO</h1>
           <button onClick={() => setIsSidebarOpen(false)} className="md:hidden"><X /></button>
        </div>
        <nav className="flex-1 p-4 space-y-2">
           <button onClick={() => {setActivePanel('chat'); setIsSidebarOpen(false);}} className={`w-full flex items-center gap-3 p-3 rounded-xl text-sm font-bold ${activePanel === 'chat' ? 'bg-indigo-600' : 'hover:bg-slate-800 text-slate-400'}`}><MessageSquare /> Chat Diagnosa</button>
           <button onClick={() => {setActivePanel('diagnosis'); setIsSidebarOpen(false);}} className={`w-full flex items-center gap-3 p-3 rounded-xl text-sm font-bold ${activePanel === 'diagnosis' ? 'bg-emerald-600' : 'hover:bg-slate-800 text-slate-400'}`}><Stethoscope /> CDSS Auto-Rx</button>
           <button onClick={() => {setActivePanel('wuxing'); setIsSidebarOpen(false);}} className={`w-full flex items-center gap-3 p-3 rounded-xl text-sm font-bold ${activePanel === 'wuxing' ? 'bg-pink-600' : 'hover:bg-slate-800 text-slate-400'}`}><Compass /> Wu Xing Master</button>
           <button onClick={() => {setActivePanel('archive'); setIsSidebarOpen(false);}} className={`w-full flex items-center gap-3 p-3 rounded-xl text-sm font-bold ${activePanel === 'archive' ? 'bg-slate-700' : 'hover:bg-slate-800 text-slate-400'}`}><Archive /> Arsip</button>
        </nav>
        <div className="p-4 border-t border-slate-800">
           <button onClick={() => setIsFormOpen(true)} className="w-full py-3 bg-tcm-primary text-white rounded-xl font-black text-xs uppercase tracking-widest hover:brightness-110">Input Pasien Baru</button>
        </div>
      </div>

      <div className="flex-1 flex flex-col h-full bg-slate-950 overflow-hidden">
        <header className="md:hidden p-4 bg-slate-900 border-b border-slate-800 flex justify-between">
           <button onClick={() => setIsSidebarOpen(true)}><Menu /></button>
           <h1 className="font-black text-tcm-primary">TCM PRO</h1>
        </header>

        <main className="flex-1 overflow-y-auto p-4 scrollbar-hide">
          {activePanel === 'chat' && (
            <div className="max-w-4xl mx-auto space-y-6">
              {messages.map(msg => (
                <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className="max-w-[90%] md:max-w-[80%]">
                    <div className={`p-4 rounded-2xl text-sm ${msg.role === 'user' ? 'bg-indigo-600' : 'bg-slate-900 border border-slate-800'}`}>
                      {msg.text}
                    </div>
                    {msg.tcmResult && <DiagnosisCard diagnosis={msg.tcmResult} isPregnant={false} onShowVisualizer={() => setIsVisualizerOpen(true)} patientContext={lastPatientForm} />}
                  </div>
                </div>
              ))}
              {isLoading && <div className="text-slate-500 text-xs font-bold animate-pulse">Sedang Berpikir...</div>}
              <div ref={messagesEndRef} />
            </div>
          )}
          {activePanel === 'diagnosis' && <ScoringAndPointsHub analysis={cdssResults} onAnalyzeRequest={() => setIsFormOpen(true)} patientContext={lastPatientForm} />}
          {activePanel === 'wuxing' && <WuXingMasterPanel />}
          {activePanel === 'archive' && <PatientArchivePanel onLoadPatient={(p) => { setCdssResults([{syndrome: p.diagnosis as any, score: 100, points: [], warnings: [], rationale: []}]); setActivePanel('chat'); }} />}
        </main>

        {activePanel === 'chat' && (
          <div className="p-4 bg-slate-900/50 border-t border-slate-800">
            <div className="max-w-4xl mx-auto flex gap-3">
              <input value={inputText} onChange={e => setInputText(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleSendMessage()} placeholder="Tulis gejala..." className="flex-1 bg-slate-950 border border-slate-800 rounded-xl px-5 py-3 outline-none" />
              <button onClick={() => handleSendMessage()} className="p-3 bg-tcm-primary rounded-xl"><Send /></button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

