import React, { useState, useRef } from 'react';
import { TcmDiagnosisResult } from '../types';
import { db } from '../services/db';
import { 
  BrainCircuit, FileText, FileDown, ShieldCheck, MapPin, 
  Heart, Leaf, Save, Check, Loader2, Download
} from 'lucide-react';
import DoctorNoteModal from './DoctorNoteModal';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface Props {
  diagnosis?: TcmDiagnosisResult | null;
  isPregnant: boolean;
  onShowVisualizer: (element?: string) => void;
  patientContext?: any;
}

const DiagnosisCard: React.FC<Props> = ({ diagnosis, isPregnant, onShowVisualizer, patientContext }) => {
  const [showNoteModal, setShowNoteModal] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const [isExporting, setIsExporting] = useState(false);
  const cardRef = useRef<HTMLDivElement>(null);

  if (!diagnosis) return null;

  const handleSave = () => {
    db.patients.add({
      id: Date.now().toString(),
      patientName: patientContext?.patientName || "Anonim",
      age: patientContext?.age || "-",
      sex: patientContext?.sex || "-",
      address: patientContext?.address || "",
      complaint: patientContext?.complaint || "Chat Diagnosis",
      symptoms: patientContext?.symptoms || "",
      selectedSymptoms: patientContext?.selectedSymptoms || [],
      tongue: patientContext?.tongue || {},
      pulse: patientContext?.pulse || { qualities: [] },
      diagnosis: diagnosis,
      timestamp: Date.now()
    });
    setIsSaved(true);
  };

  const handleExportPDF = async () => {
    if (!cardRef.current || isExporting) return;
    setIsExporting(true);
    try {
      const canvas = await html2canvas(cardRef.current, { scale: 2, useCORS: true, backgroundColor: '#020617' });
      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');
      pdf.addImage(imgData, 'PNG', 10, 10, 190, 0);
      pdf.save(`TCM_Resep_${diagnosis.patternId}.pdf`);
    } catch (e) { alert("Ekspor Gagal."); } finally { setIsExporting(false); }
  };

  return (
    <div className="mt-6 space-y-4 animate-fade-in">
      <DoctorNoteModal 
        isOpen={showNoteModal} 
        onClose={() => setShowNoteModal(false)} 
        diagnosis={diagnosis}
        initialPatientData={{ name: patientContext?.patientName, age: patientContext?.age }}
      />

      <div ref={cardRef} className="bg-slate-900 border border-slate-800 rounded-3xl p-6 shadow-2xl relative overflow-hidden">
        <div className="flex justify-between items-start mb-6">
           <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-tcm-primary/10 border border-tcm-primary/30 rounded-2xl flex items-center justify-center">
                 <BrainCircuit className="text-tcm-primary w-7 h-7" />
              </div>
              <div>
                 <h3 className="text-xl font-black text-white uppercase tracking-tight">{diagnosis.patternId}</h3>
                 <p className="text-[10px] text-emerald-400 font-bold uppercase tracking-widest">Protocol Giovanni Maciocia</p>
              </div>
           </div>
           <div className="flex gap-2">
              <button onClick={handleSave} className={`p-2 rounded-xl border ${isSaved ? 'text-emerald-400 border-emerald-800' : 'text-slate-500 border-slate-800 hover:text-white'}`}>
                {isSaved ? <Check /> : <Save />}
              </button>
              <button onClick={() => setShowNoteModal(true)} className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase flex items-center gap-2">
                <FileText className="w-4 h-4" /> Rx CDSS
              </button>
              <button onClick={handleExportPDF} className="px-4 py-2 bg-slate-800 text-white rounded-xl text-[10px] font-black uppercase flex items-center gap-2">
                <FileDown className="w-4 h-4" /> PDF
              </button>
           </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
           <div className="bg-slate-950 p-5 rounded-2xl border border-slate-800">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-3 flex items-center gap-2"><ShieldCheck className="w-4 h-4 text-indigo-400"/> Analisis Klinis</span>
              <p className="text-xs text-slate-300 leading-relaxed italic">{diagnosis.explanation}</p>
           </div>
           <div className="bg-slate-950 p-5 rounded-2xl border border-slate-800">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-3 flex items-center gap-2"><MapPin className="w-4 h-4 text-tcm-primary"/> Resep Titik ({diagnosis.recommendedPoints?.length})</span>
              <div className="grid grid-cols-2 gap-2">
                 {diagnosis.recommendedPoints?.map((pt, i) => (
                    <div key={i} className="text-[10px] border border-slate-800 p-2 rounded-lg hover:border-emerald-500/30 transition-all">
                       <span className="font-black text-emerald-400 block">{pt.code}</span>
                       <span className="text-slate-500 text-[9px] leading-tight line-clamp-1">{pt.description}</span>
                    </div>
                 ))}
              </div>
           </div>
        </div>

        {diagnosis.herbal_recommendation && (
           <div className="mt-4 p-4 bg-emerald-950/20 border border-emerald-500/20 rounded-2xl flex items-center justify-between">
              <div className="flex items-center gap-3">
                 <Leaf className="text-emerald-400 w-5 h-5" />
                 <div>
                    <span className="text-[9px] font-black text-emerald-500 uppercase tracking-widest">Herbal Recommendation</span>
                    <p className="text-sm font-bold text-white">{diagnosis.herbal_recommendation.formula_name}</p>
                 </div>
              </div>
              <div className="flex gap-1">
                 {diagnosis.herbal_recommendation.chief.map(h => <span key={h} className="text-[9px] px-2 py-1 bg-slate-950 rounded-lg text-slate-300">{h}</span>)}
              </div>
           </div>
        )}
      </div>
    </div>
  );
};

export default DiagnosisCard;

