const PULSE_QUALITIES = [
  'Floating', 'Deep', 'Slow', 'Rapid', 'Empty/Deficient', 'Full/Excess', 
  'Slippery', 'Wiry', 'Tight', 'Thready/Fine', 'Knotted', 'Intermittent', 'Choppy', 'Hasty'
