                          <label className="block text-[9px] font-bold text-slate-500 uppercase mb-1">Coat Quality</label>
                          <select 
                            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-xs text-slate-200 outline-none focus:border-tcm-primary"
                            value={formData.tongue.coating_quality} 
                            onChange={e => setFormData({...formData, tongue: {...formData.tongue, coating_quality: e.target.value}})}
                          >
                            <option value="">Quality...</option>
                            {TONGUE_COAT_QUALITIES.map(c => <option key={c} value={c}>{c}</option>)}
                          </select>
                        </div>
                      </div>
                    </div>

                    <div>
                      <label className="block text-[9px] font-bold text-slate-500 uppercase mb-2">Special Features</label>
                      <div className="flex flex-wrap gap-1.5">
                        {TONGUE_FEATURES.map(f => (
                          <button
                            key={f}
                            type="button"
                            onClick={() => toggleTongueFeature(f)}
                            className={`px-2 py-1 rounded-lg text-[9px] font-bold border transition-all ${
                              formData.tongue.special_features.includes(f)
                              ? 'bg-indigo-600 border-indigo-400 text-white'
                              : 'bg-slate-800 border-slate-700 text-slate-500'
                            }`}
                          >
                            {f}
                          </button>
                        ))}
                      </div>
                    </div>
                  </div>
                </div>

                {/* Pulse Sub-section */}
                <div className="bg-slate-950/30 p-5 rounded-2xl border border-slate-700/50">
                  <h4 className="text-[10px] font-black text-slate-400 mb-4 uppercase tracking-widest flex items-center gap-2">
                    <div className="w-2 h-2 rounded-full bg-amber-400"></div> Pulse Diagnosis
                  </h4>

                  <label className="block text-[9px] font-bold text-slate-500 uppercase mb-2">Qualities (Multi-select)</label>
                  <div className="grid grid-cols-2 sm:grid-cols-3 gap-1.5 overflow-y-auto max-h-[160px] p-1 scrollbar-hide">
                    {PULSE_QUALITIES.map(q => (
                       <button 
                        key={q} 
                        type="button" 
                        onClick={() => togglePulseQuality(q)} 
                        className={`px-2 py-2 rounded-lg text-[9px] font-bold border text-center transition-all ${
                          formData.pulse.qualities.includes(q) 
                          ? 'bg-emerald-600 border-emerald-400 text-white shadow-lg' 
                          : 'bg-slate-800 border-slate-700 text-slate-500 hover:border-slate-600'
                        }`}
                       >
                         {q}
                       </button>
                    ))}
                  </div>
                  <p className="mt-3 text-[8px] text-slate-500 italic font-medium">* Selection based on palpation results.</p>
                </div>
              </div>
