            {/* Form Actions */}
            <div className="pt-6 flex justify-end gap-3 sticky bottom-0 bg-slate-800 py-4 border-t border-slate-700 z-10">
                <button type="button" onClick={onClose} className="px-5 py-2 rounded-xl text-slate-400 hover:text-white text-sm font-bold uppercase tracking-widest transition-all">Cancel</button>
                <button type="submit" className="flex items-center gap-2 bg-tcm-primary hover:bg-tcm-secondary text-white px-8 py-3 rounded-xl font-black shadow-xl shadow-emerald-900/30 text-sm uppercase tracking-widest transition-all active:scale-95">
                    <Save className="w-5 h-5" /> Start Analysis
