                            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-xs text-slate-200 outline-none focus:border-tcm-primary"
                            value={formData.tongue.coating_color} 
                            onChange={e => setFormData({...formData, tongue: {...formData.tongue, coating_color: e.target.value}})}
                          >
                            <option value="">Color...</option>
                            {TONGUE_COAT_COLORS.map(c => <option key={c} value={c}>{c}</option>)}
                          </select>
                        </div>
                        <div>
                          <label className="block text-[9px] font-bold text-slate-500 uppercase mb-1">Coat Quality</label>
