                      </div>
                    </div>
                  </div>
                </div>

                {/* Pulse Sub-section */}
                <div className="bg-slate-950/30 p-5 rounded-2xl border border-slate-700/50">
                  <h4 className="text-[10px] font-black text-slate-400 mb-4 uppercase tracking-widest flex items-center gap-2">
                    <div className="w-2 h-2 rounded-full bg-amber-400"></div> Pulse Diagnosis
                  </h4>

                  <label className="block text-[9px] font-bold text-slate-500 uppercase mb-2">Qualities (Multi-select)</label>
