                    {PULSE_QUALITIES.map(q => (
                       <button 
                        key={q} 
                        type="button" 
                        onClick={() => togglePulseQuality(q)} 
                        className={`px-2 py-2 rounded-lg text-[9px] font-bold border text-center transition-all ${
