interface Props {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (data: PatientData) => void;
}

const PatientFormModal: React.FC<Props> = ({ isOpen, onClose, onSubmit }) => {
  const [storedPatients, setStoredPatients] = useState<SavedPatient[]>([]);
  const [showLookup, setShowLookup] = useState(false);
  const [lookupSearch, setLookupSearch] = useState('');

  const [formData, setFormData] = useState<PatientData>({
    patientName: '',
    age: '',
    sex: 'male',
    address: '',
    complaint: '',
    symptoms: '',
    selectedSymptoms: [],
    isAcuteMode: false,
    medicalHistory: '',
    biomedicalDiagnosis: '',
    icd10: '',
    medications: '',
    followUpDate: '',
    notes: '',
    tongue: {
      body_color: 'Normal (Pink)',
      coating_color: 'White',
      coating_quality: 'Thin',
      special_features: []
    },
    pulse: {
      qualities: []
    }
  });

  useEffect(() => {
    if (isOpen) {
      setStoredPatients(db.patients.getAll());
    }
  }, [isOpen]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(formData);
    onClose();
  };

  const handleSelectExisting = (p: SavedPatient) => {
    setFormData({
      patientName: p.patientName,
      age: p.age,
      sex: p.sex as any,
      address: p.address || '',
      complaint: p.complaint,
      symptoms: p.symptoms,
      selectedSymptoms: p.selectedSymptoms || [],
      isAcuteMode: false,
      medicalHistory: p.medicalHistory || '',
      biomedicalDiagnosis: p.biomedicalDiagnosis || '',
      icd10: p.icd10 || '',
      medications: p.medications || '',
      followUpDate: p.followUpDate || '',
      notes: p.notes || '',
      tongue: {
        body_color: p.tongue?.body_color || 'Normal (Pink)',
        coating_color: p.tongue?.coating_color || 'White',
        coating_quality: p.tongue?.coating_quality || 'Thin',
        special_features: p.tongue?.special_features || []
      },
      pulse: {
        qualities: p.pulse?.qualities || []
      }
    });
    setShowLookup(false);
  };

  const toggleSymptom = (symptom: string) => {
    const current = formData.selectedSymptoms;
    const updated = current.includes(symptom)
      ? current.filter(s => s !== symptom)
      : [...current, symptom];
    setFormData({ ...formData, selectedSymptoms: updated });
  };

  const toggleTongueFeature = (feature: string) => {
    const current = formData.tongue.special_features;
    const updated = current.includes(feature)
      ? current.filter(f => f !== feature)
      : [...current, feature];
    setFormData({ ...formData, tongue: { ...formData.tongue, special_features: updated } });
  };

  const togglePulseQuality = (quality: string) => {
    const current = formData.pulse.qualities;
    const updated = current.includes(quality)
      ? current.filter(q => q !== quality)
      : [...current, quality];
    setFormData({ ...formData, pulse: { ...formData.pulse, qualities: updated } });
  };

  const filteredStored = storedPatients.filter(p => 
    p.patientName.toLowerCase().includes(lookupSearch.toLowerCase()) ||
    (p.biomedicalDiagnosis && p.biomedicalDiagnosis.toLowerCase().includes(lookupSearch.toLowerCase()))
  ).slice(0, 5);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-md p-4 animate-fade-in">
      <div className="bg-slate-800 border border-slate-700 w-full max-w-2xl rounded-3xl shadow-2xl max-h-[90vh] overflow-y-auto scrollbar-hide">
        <div className="flex items-center justify-between p-6 border-b border-slate-700 sticky top-0 bg-slate-800 z-20">
          <div className="flex items-center gap-2">
             <Activity className="w-5 h-5 text-tcm-primary" />
             <h2 className="text-xl font-black text-white uppercase tracking-tighter">Clinical Intake</h2>
          </div>
          <div className="flex items-center gap-3">
            <button 
                type="button"
                onClick={() => setShowLookup(!showLookup)}
                className="flex items-center gap-2 px-4 py-2 bg-slate-700 hover:bg-slate-600 text-slate-200 rounded-xl text-xs font-black transition-all border border-slate-600 shadow-lg"
            >
                <Search className="w-3.5 h-3.5" /> {showLookup ? 'CLOSE' : 'LOOKUP'}
            </button>
            <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors">
                <X className="w-6 h-6" />
            </button>
          </div>
        </div>

        {showLookup && (
            <div className="p-4 bg-slate-900 border-b border-slate-700 animate-fade-in">
                <div className="relative mb-4">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                    <input 
                        type="text" 
                        placeholder="Search existing patients..."
                        className="w-full bg-slate-800 border border-slate-700 rounded-xl py-3 pl-10 pr-4 text-sm text-white focus:border-tcm-primary outline-none"
                        value={lookupSearch}
                        onChange={(e) => setLookupSearch(e.target.value)}
                    />
                </div>
                <div className="space-y-2">
                    {filteredStored.map(p => (
                        <button 
                            key={p.id}
                            type="button"
                            onClick={() => handleSelectExisting(p)}
                            className="w-full text-left p-4 rounded-xl bg-slate-800 border border-slate-700 hover:border-tcm-primary flex items-center justify-between group transition-all"
                        >
                            <div className="flex items-center gap-3">
                                <div className="p-2 bg-slate-700 rounded-lg text-slate-400 group-hover:text-tcm-primary">
                                    <UserCheck className="w-4 h-4" />
                                </div>
                                <div>
                                    <span className="block text-sm font-bold text-slate-200">{p.patientName}</span>
                                    <span className="text-[10px] text-slate-500 uppercase font-black">{p.age} th • {p.biomedicalDiagnosis || 'General'}</span>
                                </div>
                            </div>
                            <ChevronRight className="w-4 h-4 text-slate-600 group-hover:text-tcm-primary" />
                        </button>
                    ))}
                </div>
            </div>
        )}

        <form onSubmit={handleSubmit} className="p-8 space-y-10">
            {/* Identity Section */}
            <div className="space-y-4">
              <h3 className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.3em] border-b border-slate-700/50 pb-2">I. Identity</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                      <label className="block text-[10px] font-black text-slate-500 uppercase mb-1 ml-1 tracking-widest">Full Name</label>
                      <div className="relative">
                        <User className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                        <input 
                            type="text" 
                            className="w-full bg-slate-900 border border-slate-700 rounded-xl pl-10 pr-3 py-3 text-white focus:border-tcm-primary outline-none transition-all shadow-inner"
                            value={formData.patientName}
                            onChange={e => setFormData({...formData, patientName: e.target.value})}
                            placeholder="Patient name"
                            required
                        />
                      </div>
                  </div>
                  <div className="grid grid-cols-2 gap-2">
                    <div>
                        <label className="block text-[10px] font-black text-slate-500 uppercase mb-1 ml-1 tracking-widest">Age</label>
                        <input 
                            type="number" 
                            className="w-full bg-slate-900 border border-slate-700 rounded-xl px-3 py-3 text-white focus:border-tcm-primary outline-none shadow-inner"
                            value={formData.age}
                            onChange={e => setFormData({...formData, age: e.target.value})}
                        />
                    </div>
                    <div>
                        <label className="block text-[10px] font-black text-slate-500 uppercase mb-1 ml-1 tracking-widest">Sex</label>
                        <select 
                            className="w-full bg-slate-900 border border-slate-700 rounded-xl px-3 py-3 text-white focus:border-tcm-primary outline-none shadow-inner"
                            value={formData.sex}
                            onChange={e => setFormData({...formData, sex: e.target.value})}
                        >
                            <option value="male">Male</option>
                            <option value="female">Female</option>
                        </select>
                    </div>
                  </div>
              </div>
            </div>

            {/* Tongue Diagnosis - Detailed */}
            <div className="space-y-4">
              <h3 className="text-[10px] font-black text-tcm-primary uppercase tracking-[0.3em] border-b border-slate-700/50 pb-2">II. Tongue Diagnosis Details</h3>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                 <div>
                    <label className="block text-[10px] font-black text-slate-500 uppercase mb-2 ml-1 tracking-widest">Body Color</label>
                    <div className="space-y-2">
                       {TONGUE_BODY_COLORS.map(color => (
                         <button 
                            key={color} type="button" 
                            onClick={() => setFormData({...formData, tongue: {...formData.tongue, body_color: color}})}
                            className={`w-full text-left px-3 py-2 rounded-xl text-[10px] font-bold border transition-all ${
                               formData.tongue.body_color === color 
                               ? 'bg-tcm-primary/20 border-tcm-primary text-tcm-primary' 
                               : 'bg-slate-900 border-slate-700 text-slate-500'
                            }`}
                         >
                            {color}
                         </button>
                       ))}
                    </div>
                 </div>

                 <div>
                    <label className="block text-[10px] font-black text-slate-500 uppercase mb-2 ml-1 tracking-widest">Coat Properties</label>
