                       </div>
                       <div>
                          <span className="block text-[8px] font-black text-slate-600 uppercase mb-2">Quality</span>
                          <select 
                             className="w-full bg-slate-900 border border-slate-700 rounded-xl px-3 py-2 text-xs text-white outline-none"
                             value={formData.tongue.coating_quality}
                             onChange={e => setFormData({...formData, tongue: {...formData.tongue, coating_quality: e.target.value}})}
                          >
                             {TONGUE_COAT_QUALITIES.map(q => <option key={q} value={q}>{q}</option>)}
