                 </div>

                 <div>
                    <label className="block text-[10px] font-black text-slate-500 uppercase mb-2 ml-1 tracking-widest">Special Features</label>
                    <div className="flex flex-wrap gap-2 overflow-y-auto max-h-[180px] pr-2 scrollbar-hide">
                       {TONGUE_FEATURES.map(feat => (
                         <button 
