                            onClick={() => toggleTongueFeature(feat)}
                            className={`px-3 py-1.5 rounded-xl text-[9px] font-bold border transition-all ${
                               formData.tongue.special_features.includes(feat) 
                               ? 'bg-amber-500/20 border-amber-500 text-amber-500' 
                               : 'bg-slate-900 border-slate-700 text-slate-600'
                            }`}
                         >
                            {feat}
                         </button>
                       ))}
                    </div>
                 </div>
              </div>
            </div>

            {/* Pulse Diagnosis */}
            <div className="space-y-4">
              <h3 className="text-[10px] font-black text-amber-500 uppercase tracking-[0.3em] border-b border-slate-700/50 pb-2">III. Pulse Diagnosis</h3>
              <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-2">
                 {PULSE_QUALITIES.map(q => (
                    <button 
                      key={q} type="button" 
                      onClick={() => togglePulseQuality(q)}
                      className={`px-3 py-2 rounded-xl text-[10px] font-black border transition-all ${
                        formData.pulse.qualities.includes(q) 
                        ? 'bg-emerald-600 border-emerald-400 text-white' 
                        : 'bg-slate-900 border-slate-700 text-slate-500'
                      }`}
                    >
                      {q}
                    </button>
                 ))}
              </div>
            </div>

            {/* Complaints & Detailed History */}
            <div className="space-y-4">
              <h3 className="text-[10px] font-black text-rose-500 uppercase tracking-[0.3em] border-b border-slate-700/50 pb-2">IV. Clinical Complaints</h3>
              <div className="space-y-4">
                 <div>
                    <label className="block text-[10px] font-black text-slate-500 uppercase mb-2 ml-1 tracking-widest">Chief Complaint</label>
                    <textarea 
                       className="w-full bg-slate-950 border border-slate-700 rounded-2xl px-5 py-4 text-sm text-white focus:border-tcm-primary outline-none h-24 resize-none shadow-inner"
                       value={formData.complaint}
                       onChange={e => setFormData({...formData, complaint: e.target.value})}
                       placeholder="What is the patient's main concern?"
                    />
                 </div>

                 <div>
                    <label className="block text-[10px] font-black text-slate-500 uppercase mb-2 ml-1 tracking-widest">Symptom Checklist (Shortcut)</label>
                    <div className="flex flex-wrap gap-2">
                       {SYMPTOM_GROUPS.flatMap(g => g.items).slice(0, 15).map(s => (
                         <button 
                            key={s} type="button" 
                            onClick={() => toggleSymptom(s)}
                            className={`px-3 py-1.5 rounded-xl text-[9px] font-bold border transition-all ${
                               formData.selectedSymptoms.includes(s) 
                               ? 'bg-indigo-600 border-indigo-500 text-white' 
                               : 'bg-slate-900 border-slate-700 text-slate-500'
                            }`}
                         >
                            {s}
                         </button>
                       ))}
                    </div>
                 </div>
              </div>
            </div>

            {/* Footer Actions */}
            <div className="pt-6 flex justify-end gap-4 border-t border-slate-700 sticky bottom-0 bg-slate-800 py-6 z-10">
                <button type="button" onClick={onClose} className="px-6 py-3 rounded-2xl text-slate-400 hover:text-white text-xs font-black uppercase tracking-widest transition-all">Cancel</button>
                <button type="submit" className="flex items-center gap-2 bg-gradient-to-r from-emerald-500 to-tcm-primary text-white px-10 py-4 rounded-2xl font-black shadow-xl shadow-emerald-900/40 text-xs uppercase tracking-widest transition-all active:scale-95">
                    <Save className="w-5 h-5" /> Start AI Analysis
                </button>
            </div>
        </form>
      </div>
    </div>
  );
};

